function normalizeAudioSystemConfMap(confMap: AudioSystemConfigurationMap = {}): AudioSystemConfigurationMap {
	const systemDefaults: AudioSystemConfigurationMap = {
		music: {
			loop: true,
			hint: { streaming: true }
		},
		sound: {
			loop: false,
			hint: { streaming: false }
		}
	};

	for (const key in systemDefaults) {
		if (!(key in confMap)) {
			confMap[key] = systemDefaults[key];
		}
	}

	return confMap;
}

function normalizeCommonArea(area: CommonArea | CommonAreaShortened): CommonArea {
	return Array.isArray(area) ? { x: area[0], y: area[1], width: area[2], height: area[3] } : area;
}

/**
 * パスパターンを関数に変換する。
 *
 * パスパターンは、パス文字列、または0個以上の `**`, `*`, `?` を含むパス文字列である。
 * (実装の単純化のため、いわゆる glob のうちよく使われそうなものだけをサポートしている。)
 * 詳細は `AssetAccessor#getAllImages()` の仕様を参照のこと。
 *
 * 戻り値は、文字列一つを受け取り、パターンにマッチするか否かを返す関数。
 *
 * @param pattern パターン文字列
 */
function patternToFilter(pattern: string): (path: string) => boolean {
	const parserRe = /([^\*\\\?]*)(\\\*|\\\?|\?|\*(?!\*)|\*\*\/|$)/g;
	//                [----A-----][--------------B---------------]
	// A: パターンの特殊文字でない文字の塊。そのままマッチさせる(ためにエスケープして正規表現にする)
	// B: パターンの特殊文字一つ(*, ** など)かそのエスケープ。patternSpecialsTable で対応する正規表現に変換
	const patternSpecialsTable: { [pat: string]: string } = {
		"": "", // 入力末尾で parserRe の B 部分が $ にマッチして空文字列になることに対応
		"\\*": "\\*",
		"\\?": "\\?",
		"*": "[^/]*",
		"?": "[^/]",
		"**/": "(?:^/)?(?:[^/]+/)*"
		//      [--C--][----D----]
		// C: 行頭の `/` (行頭でなければないので ? つき)
		// D: ディレクトリ一つ分(e.g. "foo/")が0回以上
	};

	const regExpSpecialsRe = /[\\^$.*+?()[\]{}|]/g;
	function escapeRegExp(s: string): string {
		return s.replace(regExpSpecialsRe, "\\$&");
	}

	let code = "";
	for (let match = parserRe.exec(pattern); match && match[0] !== ""; match = parserRe.exec(pattern)) {
		code += escapeRegExp(match[1]) + patternSpecialsTable[match[2]];
	}
	const re = new RegExp("^" + code + "$");
	return path => re.test(path);
}

/**
 * `Asset` を管理するクラス。
 *
 * このクラスのインスタンスは `Game` に一つデフォルトで存在する(デフォルトアセットマネージャ)。
 * デフォルトアセットマネージャは、game.json に記述された通常のアセットを読み込むために利用される。
 *
 * ゲーム開発者は、game.json に記述のないリソースを取得するために、このクラスのインスタンスを独自に生成してよい。
 */
export class AssetManager implements AssetLoadHandler {
	static MAX_ERROR_COUNT: number = 3;

	/**
	 * コンストラクタに渡されたアセットの設定。(assets.json が入っていることが期待される)
	 */
	configuration: AssetConfigurationMap;

	/**
	 * require解決用の仮想パスからアセットIDを引くためのテーブル。
	 * @private
	 */
	_virtualPathToIdTable: { [key: string]: string };

	/**
	 * 読み込み済みのアセット。
	 * requestAssets() で読み込みをリクエストしたゲーム開発者はコールバックでアセットを受け取るので、この変数を参照する必要は通常ない
	 * @private
	 */
	_assets: { [key: string]: OneOfAsset };

	/**
	 * 読み込み済みのrequire解決用の仮想パスからアセットを引くためのテーブル。
	 * アセットIDと異なり、ファイルパスは重複しうる (同じ画像を複数の名前で参照することはできる) ので、要素数は `_assets` 以下である。
	 * この情報は逆引き用の補助的な値にすぎない。このクラスの読み込み済みアセットの管理はすべて `_assets` 経由で行う。
	 * @private
	 */
	_liveAssetVirtualPathTable: { [key: string]: OneOfAsset };

	/**
	 * 読み込み済みのアセットの絶対パスからrequire解決用の仮想パスを引くためのテーブル。
	 * @private
	 */
	_liveAssetPathTable: { [path: string]: string };

	/**
	 * requireの第一引数から対応する仮想パスを引くためのテーブル。
	 * @private
	 */
	_moduleMainScripts: ModuleMainScriptsMap;

	/**
	 * package.json のパスをキーに、その main フィールドの内容を値に持つテーブル
	 * @private
	 */
	_moduleMainPaths: ModuleMainPathsMap | null;

	/**
	 * 各アセットに対する参照の数。
	 * 参照は requestAssets() で増え、unrefAssets() で減る。
	 * なおロード中であっても参照に数える。つまり (this._refCounts[id] > 1) であるなら !!(this._assets[id] || this._loadings[id])
	 * @private
	 */
	_refCounts: { [key: string]: number };

	/**
	 * 各種リソースのファクトリ。
	 */
	private _resourceFactory: ResourceFactory;

	/**
	 * オーディオシステム群
	 */
	private _audioSystemManager: AudioSystemManager;

	/**
	 * デフォルトで利用されるオーディオシステムのID。
	 */
	private _defaultAudioSystemId: "music" | "sound";

	/**
	 * 読み込み中のアセットの情報。
	 * @ignore
	 */
	private _loadings: { [key: string]: AssetLoadingInfo };

	/**
	 * オーディオシステムの宣言。
	 */
	private _audioSystemConfMap: AudioSystemConfigurationMap;

	/**
	 * 動的生成アセットを生成した回数。
	 */
	private _generatedAssetCount: number;

	/**
	 * アセットバンドル。
	 */
	private _assetBundle: AssetBundleConfiguration | null;

	/**
	 * `AssetManager` のインスタンスを生成する。
	 *
	 * @param gameParams このインスタンスが属するゲーム。
	 * @param conf このアセットマネージャに与えるアセット定義。game.json の `"assets"` に相当。
	 * @param audioSystemConfMap このアセットマネージャに与えるオーディオシステムの宣言。
	 * @param moduleMainScripts このアセットマネージャに与える require() 解決用のエントリポイント。
	 */
	constructor(
		gameParams: AssetManagerParameterGameLike,
		conf?: AssetConfigurationMap,
		audioSystemConfMap?: AudioSystemConfigurationMap,
		moduleMainScripts?: ModuleMainScriptsMap,
		moduleMainPaths?: ModuleMainPathsMap
	) {
		this._resourceFactory = gameParams.resourceFactory;
		this._audioSystemManager = gameParams.audio;
		this._defaultAudioSystemId = gameParams.defaultAudioSystemId;
		this._audioSystemConfMap = normalizeAudioSystemConfMap(audioSystemConfMap);
		this.configuration = this._normalize(conf || {});
		this._assets = {};
		this._virtualPathToIdTable = {};
		this._liveAssetVirtualPathTable = {};
		this._liveAssetPathTable = {};
		this._moduleMainScripts = moduleMainScripts ? moduleMainScripts : {};
		this._moduleMainPaths = moduleMainPaths ?? null;
		this._refCounts = {};
		this._loadings = {};
		this._generatedAssetCount = 0;
		this._assetBundle = null;

		const assetIds = Object.keys(this.configuration);
		for (let i = 0; i < assetIds.length; ++i) {
			const assetId = assetIds[i];
			const conf = this.configuration[assetId];
			this._virtualPathToIdTable[conf.virtualPath!] = assetId; // virtualPath の存在は _normalize() で確認済みのため 非 null アサーションとする
		}
	}

	/**
	 * このインスタンスを破棄する。
	 */
	destroy(): void {
		const assetIds = Object.keys(this._refCounts);
		for (let i = 0; i < assetIds.length; ++i) {
			this._releaseAsset(assetIds[i]);
		}
		this.configuration = undefined!;
		this._assets = undefined!;
		this._liveAssetVirtualPathTable = undefined!;
		this._liveAssetPathTable = undefined!;
		this._refCounts = undefined!;
		this._loadings = undefined!;
		this._assetBundle = undefined!;
	}

	/**
	 * このインスタンスが破棄済みであるかどうかを返す。
	 */
	destroyed(): boolean {
		return this._assets === undefined;
	}

	/**
	 * `Asset` の読み込みを再試行する。
	 *
	 * 引数 `asset` は読み込みの失敗が (`Scene#assetLoadFail` で) 通知されたアセットでなければならない。
	 * @param asset 読み込みを再試行するアセット
	 */
	retryLoad(asset: Asset): void {
		if (!this._loadings.hasOwnProperty(asset.id))
			throw ExceptionFactory.createAssertionError("AssetManager#retryLoad: invalid argument.");

		const loadingInfo = this._loadings[asset.id];
		if (loadingInfo.errorCount > AssetManager.MAX_ERROR_COUNT) {
			// DynamicAsset はエラーが規定回数超えた場合は例外にせず諦める。
			if (!this.configuration[asset.id]) return;
			throw ExceptionFactory.createAssertionError("AssetManager#retryLoad: too many retrying.");
		}

		if (!loadingInfo.loading) {
			loadingInfo.loading = true;
			asset._load(this);
		}
	}

	/**
	 * グローバルアセットのIDを全て返す。
	 */
	globalAssetIds(): string[] {
		const ret: string[] = [];
		const conf = this.configuration;
		for (const p in conf) {
			if (!conf.hasOwnProperty(p)) continue;
			if (conf[p].global) ret.push(p);
		}
		return ret;
	}

	/**
	 * プリロードすべきスクリプトアセットの path を全て返す。
	 */
	preloadScriptAssetPaths(): string[] {
		let assetPaths: string[] = [];

		if (this._assetBundle) {
			assetPaths.push(
				...Object.values(this._assetBundle.assets)
					.filter(conf => conf.type === "script" && conf.preload)
					.map(conf => conf.path)
			);
		}

		assetPaths.push(
			...Object.values(this.configuration)
				.filter(conf => conf.type === "script" && conf.global && conf.preload)
				.map(conf => conf.virtualPath!) // この箇所ではすでに virtualPath が補完されていることが前提
		);

		assetPaths = assetPaths.map(path => (path.startsWith("./") ? path : `./${path}`));

		return assetPaths;
	}

	/**
	 * パターンまたはフィルタに合致するパスを持つアセットIDを全て返す。
	 *
	 * 戻り値は読み込み済みでないアセットのIDを含むことに注意。
	 * 読み込み済みのアセットにアクセスする場合は、 `peekAllLiveAssetsByPattern()` を利用すること。
	 *
	 * @param patternOrFilters パターンまたはフィルタ。仕様は `AssetAccessor#getAllImages()` を参照
	 */
	resolvePatternsToAssetIds(patternOrFilters: (string | ((accessorPath: string) => boolean))[]): string[] {
		if (patternOrFilters.length === 0) return [];
		const vpaths = Object.keys(this._virtualPathToIdTable);
		const ret: string[] = [];
		for (let i = 0; i < patternOrFilters.length; ++i) {
			const patternOrFilter = patternOrFilters[i];
			const filter =
				typeof patternOrFilter === "string" ? patternToFilter(this._replaceModulePathToAbsolute(patternOrFilter)) : patternOrFilter;
			for (let j = 0; j < vpaths.length; ++j) {
				const vpath = vpaths[j];
				const accessorPath = "/" + vpath; // virtualPath に "/" を足すと accessorPath という仕様
				if (filter(accessorPath)) ret.push(this._virtualPathToIdTable[vpath]);
			}
		}
		return ret;
	}

	/**
	 * アセットの取得を要求する。
	 *
	 * 要求したアセットが読み込み済みでない場合、読み込みが行われる。
	 * 取得した結果は `handler` を通して通知される。
	 * ゲーム開発者はこのメソッドを呼び出してアセットを取得した場合、
	 * 同じアセットID(または取得したアセット)で `unrefAsset()` を呼び出さなければならない。
	 *
	 * @param assetIdOrConf 要求するアセットのIDまたは設定
	 * @param handler 要求結果を受け取るハンドラ
	 */
	requestAsset(assetIdOrConf: AssetIdOrConf, handler: AssetManagerLoadHandler): boolean {
		let assetId: string;
		if (typeof assetIdOrConf === "string") {
			assetId = assetIdOrConf;
		} else if ("uri" in assetIdOrConf) {
			assetId = assetIdOrConf.id;
			assetIdOrConf = this._normalizeAssetBaseDeclaration(assetId, Object.create(assetIdOrConf));
		} else {
			// TODO: ノーマライズ処理を _normalizeAssetBaseDeclaration() に統合すべき
			assetId = assetIdOrConf.id;
		}
		let waiting = false;
		let loadingInfo: AssetLoadingInfo;
		if (this._assets.hasOwnProperty(assetId)) {
			++this._refCounts[assetId];
			handler._onAssetLoad(this._assets[assetId]);
		} else if (this._loadings.hasOwnProperty(assetId)) {
			loadingInfo = this._loadings[assetId];
			loadingInfo.handlers.push(handler);
			++this._refCounts[assetId];
			waiting = true;
		} else {
			const system = this._getAudioSystem(assetIdOrConf);
			const audioAsset = system?.getDestroyRequestedAsset(assetId);
			if (system && audioAsset) {
				system.cancelRequestDestroy(audioAsset);
				this._addAssetToTables(audioAsset);
				this._refCounts[assetId] = 1;
				handler._onAssetLoad(audioAsset);
			} else {
				const a = this._createAssetFor(assetIdOrConf);
				loadingInfo = new AssetLoadingInfo(a, handler);
				this._loadings[assetId] = loadingInfo;
				this._refCounts[assetId] = 1;
				waiting = true;
				loadingInfo.loading = true;
				a._load(this);
			}
		}
		return waiting;
	}

	/**
	 * アセットの参照カウントを減らす。
	 * 引数の各要素で `unrefAsset()` を呼び出す。
	 *
	 * @param assetOrId 参照カウントを減らすアセットまたはアセットID
	 */
	unrefAsset(assetOrId: string | Asset): void {
		const assetId = typeof assetOrId === "string" ? assetOrId : assetOrId.id;
		if (--this._refCounts[assetId] > 0) return;
		this._releaseAsset(assetId);
	}

	/**
	 * 複数のアセットの取得を要求する。
	 * 引数の各要素で `requestAsset()` を呼び出す。
	 *
	 * @param assetIdOrConfs 取得するアセットのIDまたはアセット定義
	 * @param handler 取得の結果を受け取るハンドラ
	 */
	requestAssets(assetIdOrConfs: AssetIdOrConf[], handler: AssetManagerLoadHandler): number {
		let waitingCount = 0;
		for (let i = 0, len = assetIdOrConfs.length; i < len; ++i) {
			if (this.requestAsset(assetIdOrConfs[i], handler)) {
				++waitingCount;
			}
		}
		return waitingCount;
	}

	/**
	 * 複数のアセットを解放する。
	 * 引数の各要素で `unrefAsset()` を呼び出す。
	 *
	 * @param assetOrIds 参照カウントを減らすアセットまたはアセットID
	 * @private
	 */
	unrefAssets(assetOrIds: (string | Asset)[]): void {
		for (let i = 0, len = assetOrIds.length; i < len; ++i) {
			this.unrefAsset(assetOrIds[i]);
		}
	}

	/**
	 * アクセッサパスで指定された読み込み済みのアセットを返す。
	 *
	 * ここでアクセッサパスとは、 `AssetAccessor` が使うパス
	 * (game.jsonのディレクトリをルート (`/`) とする、 `/` 区切りの絶対パス形式の仮想パス)である。
	 * これは `/` を除けばアセットの仮想パス (virtualPath) と同一である。
	 *
	 * @param accessorPath 取得するアセットのアクセッサパス
	 * @param type 取得するアセットのタイプ。対象のアセットと合致しない場合、エラー
	 */
	peekLiveAssetByAccessorPath<T extends OneOfAsset>(accessorPath: string, type: T["type"]): T {
		accessorPath = this._replaceModulePathToAbsolute(accessorPath);
		if (accessorPath[0] !== "/")
			throw ExceptionFactory.createAssertionError("AssetManager#peekLiveAssetByAccessorPath(): accessorPath must start with '/'");
		const vpath = accessorPath.slice(1); // accessorPath から "/" を削ると virtualPath という仕様
		const asset = this._liveAssetVirtualPathTable[vpath];
		if (!asset || type !== asset.type)
			throw ExceptionFactory.createAssertionError(`AssetManager#peekLiveAssetByAccessorPath(): No ${type} asset for ${accessorPath}`);
		return asset as T; // asset.typeを直前で確認しているので確実にTになるが、型推論できないのでキャストする
	}

	/**
	 * アセットIDで指定された読み込み済みのアセットを返す。
	 *
	 * @param assetId 取得するアセットのID
	 * @param type 取得するアセットのタイプ。対象のアセットと合致しない場合、エラー
	 */
	peekLiveAssetById<T extends OneOfAsset>(assetId: string, type: T["type"]): T {
		const asset = this._assets[assetId];
		if (!asset || type !== asset.type)
			throw ExceptionFactory.createAssertionError(`AssetManager#peekLiveAssetById(): No ${type} asset for id ${assetId}`);
		return asset as T; // asset.typeを直前で確認しているので確実にTになるが、型推論できないのでキャストする
	}

	/**
	 * パターンまたはフィルタにマッチするパスを持つ、指定されたタイプの全読み込み済みアセットを返す。
	 *
	 * 戻り値の要素の順序は保証されない。
	 * パターンとフィルタについては `AssetAccessor#getAllImages()` の仕様を参照のこと。
	 *
	 * @param patternOrFilter 取得するアセットのパスパターンまたはフィルタ
	 * @param type 取得するアセットのタイプ。 null の場合、全てのタイプとして扱われる。
	 */
	peekAllLiveAssetsByPattern<T extends OneOfAsset>(
		patternOrFilter: string | ((accessorPath: string) => boolean),
		type: T["type"] | null
	): T[] {
		const vpaths = Object.keys(this._liveAssetVirtualPathTable);
		const filter =
			typeof patternOrFilter === "string" ? patternToFilter(this._replaceModulePathToAbsolute(patternOrFilter)) : patternOrFilter;
		const ret: T[] = [];
		for (let i = 0; i < vpaths.length; ++i) {
			const vpath = vpaths[i];
			const asset = this._liveAssetVirtualPathTable[vpath];
			if (type && asset.type !== type) continue;
			const accessorPath = "/" + vpath; // virtualPath に "/" を足すと accessorPath という仕様
			// typeがT["type"]であればasset.typeを直前で確認しているので確実にTになるが、typeがnullの時にassetがTではない可能性がある
			if (filter(accessorPath)) ret.push(asset as T);
		}
		return ret;
	}

	/**
	 * アセットIDから読み込み済みのアクセッサパス返す。
	 * 当該のアセットが読み込まれていない場合、 null を返す。
	 *
	 * @param assetId 取得するアセットのID
	 */
	resolveAccessorPath(assetId: string): string | null {
		const asset = this._assets[assetId];
		if (!asset) return null;
		const virtualPath = this._liveAssetPathTable[asset.path];
		if (!virtualPath) return null;
		return "/" + virtualPath;
	}

	/**
	 * アセットバンドルを設定する。
	 *
	 * @param assetBundle アセットバンドル
	 */
	setAssetBundle(assetBundle: AssetBundleConfiguration | null): void {
		this._assetBundle = assetBundle;
	}

	/**
	 * @ignore
	 */
	_normalize(configuration: AssetConfigurationMap): AssetConfigurationMap {
		const ret: AssetConfigurationMap = {};
		if (!(configuration instanceof Object)) throw ExceptionFactory.createAssertionError("AssetManager#_normalize: invalid arguments.");
		for (const p in configuration) {
			if (!configuration.hasOwnProperty(p)) continue;
			const conf = this._normalizeAssetBaseDeclaration<AssetConfiguration>(p, Object.create(configuration[p]));
			if (!conf.path) {
				throw ExceptionFactory.createAssertionError("AssetManager#_normalize: No path given for: " + p);
			}
			if (!conf.virtualPath) {
				throw ExceptionFactory.createAssertionError("AssetManager#_normalize: No virtualPath given for: " + p);
			}
			if (!conf.global) conf.global = false;
			ret[p] = conf;
		}
		return ret;
	}

	/**
	 * @private
	 * @ignore
	 */
	_normalizeAssetBaseDeclaration<T extends AssetConfigurationCore>(assetId: string, conf: T): T {
		if (!conf.type) {
			throw ExceptionFactory.createAssertionError("AssetManager#_normalize: No type given for: " + assetId);
		}
		if (conf.type === "image") {
			if (typeof conf.width !== "number")
				throw ExceptionFactory.createAssertionError("AssetManager#_normalize: wrong width given for the image asset: " + assetId);
			if (typeof conf.height !== "number")
				throw ExceptionFactory.createAssertionError("AssetManager#_normalize: wrong height given for the image asset: " + assetId);
			conf.slice = conf.slice ? normalizeCommonArea(conf.slice) : undefined;
		}
		if (conf.type === "audio") {
			// durationというメンバは後から追加したため、古いgame.jsonではundefinedになる場合がある
			if (conf.duration === undefined) conf.duration = 0;
			const audioSystemConf = this._audioSystemConfMap[conf.systemId];
			if (conf.loop === undefined) {
				conf.loop = !!audioSystemConf && !!audioSystemConf.loop;
			}
			if (conf.hint === undefined) {
				conf.hint = audioSystemConf ? audioSystemConf.hint : {};
			}
			if (conf.systemId !== "music" && conf.systemId !== "sound") {
				throw ExceptionFactory.createAssertionError(
					"AssetManager#_normalize: wrong systemId given for the audio asset: " + assetId
				);
			}
		}
		if (conf.type === "video") {
			if (!conf.useRealSize) {
				if (typeof conf.width !== "number")
					throw ExceptionFactory.createAssertionError(
						"AssetManager#_normalize: wrong width given for the video asset: " + assetId
					);
				if (typeof conf.height !== "number")
					throw ExceptionFactory.createAssertionError(
						"AssetManager#_normalize: wrong height given for the video asset: " + assetId
					);
				conf.useRealSize = false;
			}
		}
		if (conf.type === "vector-image") {
			if (typeof conf.width !== "number")
				throw ExceptionFactory.createAssertionError(
					"AssetManager#_normalize: wrong width given for the vector-image asset: " + assetId
				);
			if (typeof conf.height !== "number")
				throw ExceptionFactory.createAssertionError(
					"AssetManager#_normalize: wrong height given for the vector-image asset: " + assetId
				);
		}
		return conf;
	}

	/**
	 * @private
	 */
	_createAssetFor(idOrConf: AssetIdOrConf): OneOfAsset {
		let id: string;
		let uri: string;
		let conf: AssetConfiguration | DynamicAssetConfiguration;
		if (this._assetBundle && typeof idOrConf === "string") {
			const id = idOrConf;
			const conf = this._assetBundle.assets[id] as BundledAssetConfiguration;
			const type = conf?.type;
			switch (type) {
				case "script":
					return new BundledScriptAsset({
						id,
						...conf
					});
				case "text":
					return new BundledTextAsset({
						id,
						...conf
					});
			}
		}
		if (typeof idOrConf === "string") {
			id = idOrConf;
			conf = this.configuration[id];
			uri = this.configuration[id].path;
		} else if ("uri" in idOrConf) {
			id = idOrConf.id;
			conf = idOrConf;
			uri = idOrConf.uri;
		} else {
			return this._createGeneratedAssetFor(idOrConf);
		}
		const resourceFactory = this._resourceFactory;
		if (!conf) throw ExceptionFactory.createAssertionError("AssetManager#_createAssetFor: unknown asset ID: " + id);
		const type = conf.type;
		switch (type) {
			case "image":
				// _normalize() で conf.slice を CommonArea | undefined にしているので本来は不要な分岐だが、型の担保のためにチェックを行う
				if (Array.isArray(conf.slice)) {
					throw new Error("AssetManager#_createAssetFor: array type of configuration.slice is not yet supported");
				}
				const asset = conf.slice
					? new PartialImageAsset(resourceFactory, id, uri, conf.width, conf.height, conf.slice)
					: resourceFactory.createImageAsset(id, uri, conf.width, conf.height);
				asset.initialize(conf.hint);
				return asset;
			case "audio":
				const system = conf.systemId
					? this._audioSystemManager[conf.systemId]
					: this._audioSystemManager[this._defaultAudioSystemId];
				return resourceFactory.createAudioAsset(id, uri, conf.duration, system, !!conf.loop, conf.hint ?? {}, conf.offset);
			case "text":
				return resourceFactory.createTextAsset(id, uri);
			case "script":
				return resourceFactory.createScriptAsset(id, uri, conf.exports);
			case "video":
				// VideoSystemはまだ中身が定義されていなが、将来のためにVideoAssetにVideoSystemを渡すという体裁だけが整えられている。
				// 以上を踏まえ、ここでは簡単のために都度新たなVideoSystemインスタンスを生成している。
				const videoSystem = new VideoSystem();
				return resourceFactory.createVideoAsset(id, uri, conf.width, conf.height, videoSystem, !!conf.loop, !!conf.useRealSize);
			case "vector-image":
				if (!resourceFactory.createVectorImageAsset) {
					return new EmptyVectorImageAsset(id, uri, conf.width, conf.height, conf.hint);
				}
				return resourceFactory.createVectorImageAsset(id, uri, conf.width, conf.height, conf.hint);
			case "binary":
				if (!resourceFactory.createBinaryAsset) {
					return new EmptyBinaryAsset(id, uri);
				}
				return resourceFactory.createBinaryAsset(id, uri);
			default:
				throw ExceptionFactory.createAssertionError(
					"AssertionError#_createAssetFor: unknown asset type " + type + " for asset ID: " + id
				);
		}
	}

	/**
	 * @private
	 */
	_createGeneratedAssetFor(conf: AssetGenerationConfiguration): OneOfAsset {
		const resourceFactory = this._resourceFactory;
		const path = `%akashic%/generated-asset-${this._generatedAssetCount++}`;
		switch (conf.type) {
			case "vector-image":
				if (!resourceFactory.createVectorImageAssetFromString) {
					return new EmptyGeneratedVectorImageAsset(conf.id, path, conf.data);
				}
				return resourceFactory.createVectorImageAssetFromString(conf.id, path, conf.data);
			default:
				throw ExceptionFactory.createAssertionError(
					`AssertionError#_createFromAssetGenerationFor: unsupported asset type ${conf.type} for asset ID: ${conf.id}`
				);
		}
	}

	/**
	 * @ignore
	 */
	_releaseAsset(assetId: string): void {
		const asset = this._assets[assetId] || (this._loadings[assetId] && this._loadings[assetId].asset);
		let path: string | null = null;
		if (asset) {
			path = asset.path;
			if (asset.inUse()) {
				if (asset.type === "audio") {
					asset._system.requestDestroy(asset);
				} else if (asset.type === "video") {
					// NOTE: 一旦再生完了を待たずに破棄することにする
					// TODO: 再生中の動画を破棄するタイミングをどのように扱うか検討し実装
					asset.destroy();
				} else {
					throw ExceptionFactory.createAssertionError("AssetManager#unrefAssets: Unsupported in-use " + asset.id);
				}
			} else {
				asset.destroy();
			}
		}
		delete this._refCounts[assetId];
		delete this._loadings[assetId];
		delete this._assets[assetId];
		if (this.configuration[assetId]) {
			const virtualPath = this.configuration[assetId].virtualPath;
			if (virtualPath && this._liveAssetVirtualPathTable.hasOwnProperty(virtualPath))
				delete this._liveAssetVirtualPathTable[virtualPath];
			if (path && this._liveAssetPathTable.hasOwnProperty(path)) delete this._liveAssetPathTable[path];
		}
	}

	/**
	 * 現在ロード中のアセットの数。(デバッグ用; 直接の用途はない)
	 * @private
	 */
	_countLoadingAsset(): number {
		return Object.keys(this._loadings).length;
	}

	/**
	 * @private
	 */
	_onAssetError(asset: OneOfAsset, error: AssetLoadError): void {
		// ロード中に Scene が破棄されていた場合などで、asset が破棄済みになることがある
		if (this.destroyed() || asset.destroyed()) return;

		const loadingInfo = this._loadings[asset.id];
		const hs = loadingInfo.handlers;
		loadingInfo.loading = false;
		++loadingInfo.errorCount;

		if (loadingInfo.errorCount > AssetManager.MAX_ERROR_COUNT && error.retriable) {
			error = ExceptionFactory.createAssetLoadError("Retry limit exceeded", false, null, error);
		}
		if (!error.retriable) delete this._loadings[asset.id];
		for (let i = 0; i < hs.length; ++i) hs[i]._onAssetError(asset, error, this.retryLoad.bind(this));
	}

	/**
	 * @private
	 */
	_onAssetLoad(asset: OneOfAsset): void {
		// ロード中に Scene が破棄されていた場合などで、asset が破棄済みになることがある
		if (this.destroyed() || asset.destroyed()) return;

		const loadingInfo = this._loadings[asset.id];
		loadingInfo.loading = false;

		delete this._loadings[asset.id];
		this._addAssetToTables(asset);

		const hs = loadingInfo.handlers;
		for (let i = 0; i < hs.length; ++i) hs[i]._onAssetLoad(asset);
	}

	/**
	 * @private
	 */
	_replaceModulePathToAbsolute(accessorPath: string): string {
		if (
			accessorPath[0] === "/" ||
			accessorPath[0] === "*" // パスに `**/*` が指定された場合
		) {
			return accessorPath;
		}

		for (const moduleName in this._moduleMainScripts) {
			if (!this._moduleMainScripts.hasOwnProperty(moduleName)) continue;
			if (accessorPath.lastIndexOf(moduleName, 0) === 0) {
				return "/node_modules/" + accessorPath;
			}
		}
		return accessorPath;
	}

	/**
	 * @private
	 */
	_getAudioSystem(assetIdOrConf: AssetIdOrConf): AudioSystem | null {
		let conf: AssetConfiguration | DynamicAssetConfiguration | null = null;
		if (typeof assetIdOrConf === "string") {
			conf = this.configuration[assetIdOrConf];
		} else if ("uri" in assetIdOrConf) {
			const dynConf = assetIdOrConf;
			conf = dynConf;
		} else {
			// NOTE: AssetGeneration では一旦非サポート。
		}

		if (!conf) {
			return null;
		}
		if (conf.type !== "audio") {
			return null;
		}

		return conf.systemId ? this._audioSystemManager[conf.systemId] : this._audioSystemManager[this._defaultAudioSystemId];
	}

	/**
	 * @private
	 */
	_addAssetToTables(asset: OneOfAsset): void {
		this._assets[asset.id] = asset;
		let path: string | undefined;

		// DynamicAsset の場合は configuration に書かれていないので以下の判定が偽になる
		if (this.configuration[asset.id]) {
			path = this.configuration[asset.id].virtualPath!; // virtualPath の存在は _normalize() で確認済みのため 非 null アサーションとする
		} else if (this._assetBundle && this._assetBundle.assets[asset.id]) {
			path = this._assetBundle.assets[asset.id].path;
		}

		if (!path) return;

		if (!this._liveAssetVirtualPathTable.hasOwnProperty(path)) {
			this._liveAssetVirtualPathTable[path] = asset;
		} else {
			if (this._liveAssetVirtualPathTable[path].path !== asset.path)
				throw ExceptionFactory.createAssertionError("AssetManager#_onAssetLoad(): duplicated asset path");
		}
		if (!this._liveAssetPathTable.hasOwnProperty(asset.path)) this._liveAssetPathTable[asset.path] = path;
	}
}

import type { Asset, AssetLoadError } from "@akashic/pdi-types";

/**
 * `AssetManager` から `Asset` の読み込みまたは読み込み失敗を受け取るハンドラのインターフェース定義。
 * `AssetLoadHandler` とは異なる。こちらは `AssetManager` を経由してのアセットの読み込み処理を行う場合のハンドラである。
 */
export interface AssetManagerLoadHandler {
	/**
	 * 読み込失敗の通知を受ける関数。
	 * @ignore
	 * @param asset 読み込みに失敗したアセット
	 * @param error 失敗の内容を表すエラー
	 * @param retryCallback 読み込みの再試行を行うコールバック関数。`AssetManager#retryLoad()` が設定される。
	 */
	_onAssetError(asset: Asset, error: AssetLoadError, retryCallback: (asset: Asset) => void): void;

	/**
	 * 読み込み完了の通知を受ける関数。
	 * @ignore
	 * @param asset 読み込みが完了したアセット
	 */
	_onAssetLoad(asset: Asset): void;
}

import type { AudioAsset, AudioPlayer, AudioSystem, ResourceFactory } from "@akashic/pdi-types";
import { Trigger } from "@akashic/trigger";

export interface AudioPlayContextPlayEvent {}
export interface AudioPlayContextStopEvent {}

export interface AudioPlayContextParameterObject {
	id: string;
	resourceFactory: ResourceFactory;
	system: AudioSystem; // TODO: AudioSystem への依存を削除
	systemId: string;
	asset: AudioAsset;
	volume?: number;
}

export class AudioPlayContext {
	/**
	 * この AudioPlayContext に紐づく音声アセット。
	 */
	readonly asset: AudioAsset;

	/**
	 * `play()` が呼び出された時に通知される `Trigger` 。
	 */
	readonly onPlay: Trigger<AudioPlayContextPlayEvent> = new Trigger();

	/**
	 * `stop()` が呼び出された時に通知される `Trigger` 。
	 */
	readonly onStop: Trigger<AudioPlayContextStopEvent> = new Trigger();

	/**
	 * @private
	 */
	_system: AudioSystem;

	/**
	 * @private
	 */
	_resourceFactory: ResourceFactory;

	/**
	 * @private
	 */
	_player: AudioPlayer;

	/**
	 * @private
	 */
	_volume: number;

	/**
	 * @private
	 */
	_id: string;

	/**
	 * @private
	 */
	_systemId: string;

	get volume(): number {
		return this._volume;
	}

	constructor(param: AudioPlayContextParameterObject) {
		this.asset = param.asset;
		this._system = param.system;
		this._resourceFactory = param.resourceFactory;
		this._volume = param.volume ?? 1.0;
		this._id = param.id;
		this._systemId = param.systemId;
		this._player = this._createAudioPlayer();

		this.asset.onDestroyed.addOnce(this.stop, this);
	}

	play(): void {
		this._player.play(this.asset);
	}

	stop(): void {
		this._player.stop();
	}

	changeVolume(vol: number): void {
		this._volume = vol;
		this._player.changeVolume(vol);
	}

	/**
	 * @private
	 */
	_startSuppress(): void {
		if (this._systemId === "music") {
			this._player.changeVolume(0);
			return;
		}

		this.stop();
	}

	/**
	 * @private
	 */
	_endSuppress(): void {
		if (this._systemId === "music") {
			this._player.changeVolume(this._volume);
			return;
		}
	}

	private _createAudioPlayer(): AudioPlayer {
		const audioPlayer = this._resourceFactory.createAudioPlayer(this._system);
		audioPlayer.changeVolume(this._volume);
		audioPlayer.onPlay.add(this.onPlay.fire, this.onPlay);
		audioPlayer.onStop.add(this.onStop.fire, this.onStop);
		return audioPlayer;
	}
}

import type { AudioAsset, AudioPlayer, AudioPlayerEvent, ResourceFactory, AudioSystem as PdiAudioSystem } from "@akashic/pdi-types";
import { AudioPlayContext } from "./AudioPlayContext";
import { ExceptionFactory } from "./ExceptionFactory";
import { WeakRefKVS } from "./WeakRefKVS";

export interface AudioSystemParameterObject {
	/**
	 * オーディオシステムのID
	 */
	id: string;

	/**
	 * オーディオのボリューム
	 */
	volume?: number;

	/**
	 * ミュート中か否か。
	 */
	muted?: boolean;

	/**
	 * 各種リソースのファクトリ
	 */
	resourceFactory: ResourceFactory;
}

export abstract class AudioSystem implements PdiAudioSystem {
	id: string;

	/**
	 * @private
	 */
	_volume: number;

	/**
	 * @private
	 */
	_muted: boolean;

	/**
	 * @private
	 */
	_destroyRequestedAssets: { [key: string]: AudioAsset };

	/**
	 * 再生速度が等倍以外に指定された等の要因により、音声再生が抑制されているかどうか。
	 * @private
	 */
	_suppressed: boolean;

	/**
	 * @private
	 */
	_resourceFactory: ResourceFactory;

	/**
	 * 明示的に設定された、ミュート中か否か。
	 * @private
	 */
	_explicitMuted: boolean;

	/**
	 * @private
	 */
	_contextMap: WeakRefKVS<AudioPlayContext>;

	/**
	 * @private
	 */
	_contextCount: number;

	/**
	 * `this._contextMap` から不要な参照を削除する頻度。
	 * 10 を指定した場合 `AudioPlayContext` を 10 回生成する度に参照の削除が行われる。
	 * @private
	 */
	abstract _contentMapCleaningFrequency: number;

	// volumeの変更時には通知が必要なのでアクセサを使う。
	// 呼び出し頻度が少ないため許容。
	get volume(): number {
		return this._volume;
	}

	set volume(value: number) {
		if (value < 0 || value > 1 || isNaN(value) || typeof value !== "number")
			throw ExceptionFactory.createAssertionError("AudioSystem#volume: expected: 0.0-1.0, actual: " + value);

		this._volume = value;
		this._onVolumeChanged();
	}

	constructor(param: AudioSystemParameterObject) {
		this.id = param.id;
		this._volume = param.volume || 1;
		this._destroyRequestedAssets = {};
		this._explicitMuted = param.muted || false;
		this._suppressed = false;
		this._muted = false;
		this._contextMap = new WeakRefKVS();
		this._contextCount = 0;
		this._resourceFactory = param.resourceFactory;
		this._updateMuted();
	}

	play(asset: AudioAsset): AudioPlayContext {
		const context = this.create(asset);
		context.play();
		return context;
	}

	create(asset: AudioAsset): AudioPlayContext {
		// TODO: 依存関係の見直し
		const context = new AudioPlayContext({
			id: this._generateAudioPlayContextId(),
			resourceFactory: this._resourceFactory,
			asset,
			system: this,
			systemId: this.id,
			volume: 1.0
		});
		if (this._contextCount % this._contentMapCleaningFrequency === 0) {
			this._contextMap.clean();
		}
		this._contextMap.set(context._id, context);
		return context;
	}

	stopAll(): void {
		for (const key of this._contextMap.keys()) {
			const ctx = this._contextMap.get(key);
			ctx?.stop();
		}
		this._contextMap.clean();
	}

	abstract findPlayers(asset: AudioAsset): AudioPlayer[];

	abstract createPlayer(): AudioPlayer;

	requestDestroy(asset: AudioAsset): void {
		this._destroyRequestedAssets[asset.id] = asset;
	}

	/**
	 * `this.requestDestroy()` により破棄要求されているアセットの破棄を取り消す。
	 * @param asset アセット。
	 */
	// NOTE: akashic-engine の独自仕様
	cancelRequestDestroy(asset: AudioAsset): void {
		delete this._destroyRequestedAssets[asset.id];
	}

	/**
	 * `this.requestDestroy()` により破棄要求されていて、まだ実際には破棄されていないアセット。
	 * 対象のアセットが破棄要求されていなければ `null` を返す。
	 * @param assetId アセットID。
	 */
	// NOTE: akashic-engine の独自仕様
	getDestroyRequestedAsset(assetId: string): AudioAsset | null {
		if (this._destroyRequestedAssets.hasOwnProperty(assetId)) {
			return this._destroyRequestedAssets[assetId];
		}

		return null;
	}

	/**
	 * @private
	 */
	_reset(): void {
		this.stopAll();
		this._volume = 1;
		this._destroyRequestedAssets = {};
		this._muted = false;
		this._suppressed = false;
		this._explicitMuted = false;
	}

	/**
	 * @private
	 */
	_setMuted(value: boolean): void {
		const before = this._explicitMuted;
		this._explicitMuted = !!value;
		if (this._explicitMuted !== before) {
			this._updateMuted();
			this._onMutedChanged();
		}
	}

	/**
	 * @private
	 */
	_setPlaybackRate(value: number): void {
		if (value < 0 || isNaN(value) || typeof value !== "number")
			throw ExceptionFactory.createAssertionError("AudioSystem#playbackRate: expected: greater or equal to 0.0, actual: " + value);

		this._suppressed = value !== 1.0;
		this._updateMuted();
		this._onPlaybackRateChanged();
	}

	/**
	 * @private
	 */
	_updateMuted(): void {
		this._muted = this._explicitMuted || this._suppressed;
	}

	/**
	 * @private
	 */
	_generateAudioPlayContextId(): string {
		return `${this.id}-${this._contextCount++}`;
	}

	/**
	 * @private
	 */
	_startSuppress(): void {
		// NOTE: 既存の AudioSystem は playbackRate に 1.0 以外を指定するとミュートとなる
		this._setPlaybackRate(100);

		for (const key of this._contextMap.keys()) {
			const ctx = this._contextMap.get(key);
			ctx?._startSuppress();
		}
	}

	/**
	 * @private
	 */
	_endSuppress(): void {
		// NOTE: 既存の AudioSystem は playbackRate に 1.0 を指定するとミュートが解除される
		this._setPlaybackRate(1.0);

		for (const key of this._contextMap.keys()) {
			const ctx = this._contextMap.get(key);
			ctx?._endSuppress();
		}
	}

	/**
	 * @private
	 */
	_onVolumeChanged(): void {
		for (const key of this._contextMap.keys()) {
			const ctx = this._contextMap.get(key);
			ctx?.changeVolume(this.volume);
		}
	}

	/**
	 * @private
	 */
	abstract _onMutedChanged(): void;

	/**
	 * @private
	 */
	abstract _onPlaybackRateChanged(): void;
}

export class MusicAudioSystem extends AudioSystem {
	/**
	 * @private
	 */
	_player: AudioPlayer | undefined;

	/**
	 * @private
	 */
	_contentMapCleaningFrequency: number = 5;

	// Note: 音楽のないゲームの場合に無駄なインスタンスを作るのを避けるため、アクセサを使う
	get player(): AudioPlayer {
		if (!this._player) {
			this._player = this._resourceFactory.createAudioPlayer(this);
			this._player.onPlay.add(this._handlePlay, this);
			this._player.onStop.add(this._handleStop, this);
		}
		return this._player;
	}
	set player(v: AudioPlayer) {
		this._player = v;
	}

	constructor(param: AudioSystemParameterObject) {
		super(param);
		this._player = undefined;
	}

	findPlayers(asset: AudioAsset): AudioPlayer[] {
		if (this.player.currentAudio && this.player.currentAudio.id === asset.id) return [this.player];
		return [];
	}

	createPlayer(): AudioPlayer {
		return this.player;
	}

	override stopAll(): void {
		super.stopAll();
		if (!this._player) return;
		this._player.stop();
	}

	/**
	 * @private
	 */
	override _reset(): void {
		super._reset();
		if (this._player) {
			this._player.onPlay.remove(this._handlePlay, this);
			this._player.onStop.remove(this._handleStop, this);
		}
		this._player = undefined;
	}

	/**
	 * @private
	 */
	override _onVolumeChanged(): void {
		super._onVolumeChanged();
		this.player._notifyVolumeChanged();
	}

	/**
	 * @private
	 */
	_onMutedChanged(): void {
		this.player._changeMuted(this._muted);
	}

	/**
	 * @private
	 */
	_onPlaybackRateChanged(): void {
		this.player._changeMuted(this._muted);
	}

	/**
	 * @private
	 */
	_handlePlay(e: AudioPlayerEvent): void {
		if (e.player !== this._player)
			throw ExceptionFactory.createAssertionError("MusicAudioSystem#_onPlayerPlayed: unexpected audio player");
	}

	/**
	 * @private
	 */
	_handleStop(e: AudioPlayerEvent): void {
		if (this._destroyRequestedAssets[e.audio.id]) {
			delete this._destroyRequestedAssets[e.audio.id];
			e.audio.destroy();
		}
	}
}

export class SoundAudioSystem extends AudioSystem {
	players: AudioPlayer[];

	/**
	 * @private
	 */
	_contentMapCleaningFrequency: number = 50;

	constructor(param: AudioSystemParameterObject) {
		super(param);
		this.players = [];
	}

	createPlayer(): AudioPlayer {
		const player = this._resourceFactory.createAudioPlayer(this);
		if (player.canHandleStopped()) this.players.push(player);

		player.onPlay.add(this._handlePlay, this);
		player.onStop.add(this._handleStop, this);

		return player;
	}

	findPlayers(asset: AudioAsset): AudioPlayer[] {
		const ret: AudioPlayer[] = [];
		for (let i = 0; i < this.players.length; ++i) {
			const currentAudio = this.players[i].currentAudio;
			if (currentAudio && currentAudio.id === asset.id) ret.push(this.players[i]);
		}
		return ret;
	}

	override stopAll(): void {
		super.stopAll();
		const players = this.players.concat();
		for (let i = 0; i < players.length; ++i) {
			players[i].stop(); // auto remove
		}
	}

	/**
	 * @private
	 */
	override _reset(): void {
		super._reset();
		for (let i = 0; i < this.players.length; ++i) {
			const player = this.players[i];
			player.onPlay.remove(this._handlePlay, this);
			player.onStop.remove(this._handleStop, this);
		}
		this.players = [];
	}

	/**
	 * @private
	 */
	_onMutedChanged(): void {
		const players = this.players;
		for (let i = 0; i < players.length; ++i) {
			players[i]._changeMuted(this._muted);
		}
	}

	/**
	 * @private
	 */
	_onPlaybackRateChanged(): void {
		const players = this.players;
		if (this._suppressed) {
			for (let i = 0; i < players.length; ++i) {
				players[i]._changeMuted(true);
			}
		}
	}

	/**
	 * @private
	 */
	_handlePlay(_e: AudioPlayerEvent): void {
		// do nothing
	}

	/**
	 * @private
	 */
	_handleStop(e: AudioPlayerEvent): void {
		const index = this.players.indexOf(e.player);
		if (index < 0) return;

		e.player.onStop.remove(this._handleStop, this);
		this.players.splice(index, 1);
		if (this._destroyRequestedAssets[e.audio.id]) {
			delete this._destroyRequestedAssets[e.audio.id];
			e.audio.destroy();
		}
	}

	/**
	 * @private
	 */
	override _onVolumeChanged(): void {
		super._onVolumeChanged();
		for (let i = 0; i < this.players.length; ++i) {
			this.players[i]._notifyVolumeChanged();
		}
	}
}

import type { AudioAsset, ResourceFactory } from "@akashic/pdi-types";
import type { AudioPlayContext } from "./AudioPlayContext";
import type { AudioSystem } from "./AudioSystem";
import { MusicAudioSystem, SoundAudioSystem } from "./AudioSystem";
import { ExceptionFactory } from "./ExceptionFactory";

/**
 * `AudioSystem` の管理クラス。
 *
 * 複数の `AudioSystem` に一括で必要な状態設定を行う。
 * 本クラスのインスタンスをゲーム開発者が直接生成することはなく、ゲーム開発者が利用する必要もない。
 */
export class AudioSystemManager {
	/**
	 * ループ再生可能な AudioSystem
	 */
	music: AudioSystem;

	/**
	 * 効果音を扱う AudioSystem
	 */
	sound: AudioSystem;

	/**
	 * @private
	 */
	_muted: boolean = false;

	/**
	 * @private
	 */
	_resourceFactory: ResourceFactory;

	constructor(resourceFactory: ResourceFactory) {
		this._resourceFactory = resourceFactory;
		this.music = new MusicAudioSystem({
			id: "music",
			muted: this._muted,
			resourceFactory
		});
		this.sound = new SoundAudioSystem({
			id: "sound",
			muted: this._muted,
			resourceFactory
		});
	}

	/**
	 * 対象の音声アセットの AudioPlayContext を生成する。
	 *
	 * @param asset 音声アセット
	 */
	create(asset: AudioAsset): AudioPlayContext {
		if (asset._system.id === "music") {
			return this.music.create(asset);
		} else if (asset._system.id === "sound") {
			return this.sound.create(asset);
		} else {
			throw ExceptionFactory.createAssertionError(
				`AudioSystemManager#create(): unknown systemId "${asset._system.id}" for asset ID "${asset.id}"`
			);
		}
	}

	/**
	 * 対象の音声アセットの AudioPlayContext を生成し、再生する。
	 *
	 * @param asset 音声アセット
	 */
	play(asset: AudioAsset): AudioPlayContext {
		if (asset._system.id === "music") {
			return this.music.play(asset);
		} else if (asset._system.id === "sound") {
			return this.sound.play(asset);
		} else {
			throw ExceptionFactory.createAssertionError(
				`AudioSystemManager#play(): unknown systemId "${asset._system.id}" for asset ID "${asset.id}"`
			);
		}
	}

	/**
	 * @private
	 */
	_reset(): void {
		this._muted = false;
		this.music._reset();
		this.sound._reset();
	}

	/**
	 * @private
	 */
	_setMuted(muted: boolean): void {
		if (this._muted === muted) return;

		this._muted = muted;
		this.music._setMuted(muted);
		this.sound._setMuted(muted);
	}

	/**
	 * @private
	 */
	_setPlaybackRate(rate: number): void {
		this.music._setPlaybackRate(rate);
		this.sound._setPlaybackRate(rate);
	}

	_startSuppress(): void {
		this.music._startSuppress();
		this.sound._startSuppress();
	}

	_endSuppress(): void {
		this.music._endSuppress();
		this.sound._endSuppress();
	}

	stopAll(): void {
		this.music.stopAll();
		this.sound.stopAll();
	}
}

import type { AudioPlayContext } from "./AudioPlayContext";
import type { Game } from "./Game";
import { Util } from "./Util";

/**
 * イージング関数。
 *
 * @param t 経過時間
 * @param b 開始位置
 * @param c 差分
 * @param d 所要時間
 */
export type EasingFunction = (t: number, b: number, c: number, d: number) => number;

export type AudioTransitionContext = {
	/**
	 * 遷移を即座に完了する。
	 * 音量は遷移完了後の値となる。
	 */
	complete: () => void;
	/**
	 * 遷移を取り消す。音量はこの関数を実行した時点での値となる。
	 * @param revert 音量を遷移実行前まで戻すかどうか。省略時は `false` 。
	 */
	cancel: (revert?: boolean) => void;
};

/**
 * linear のイージング関数。
 */
const linear: EasingFunction = (t: number, b: number, c: number, d: number) => (c * t) / d + b;

/**
 * Audio に関連するユーティリティ。
 */
export module AudioUtil {
	/**
	 * 音声をフェードインさせる。
	 *
	 * @param game 対象の `Game`。
	 * @param context 対象の `AudioPlayContext` 。
	 * @param duration フェードインの長さ (ms)。
	 * @param to フェードイン後の音量。0 未満または 1 より大きい値を指定した場合の挙動は不定である。省略時は `1` 。
	 * @param easing イージング関数。省略時は linear 。
	 */
	export function fadeIn(
		game: Game,
		context: AudioPlayContext,
		duration: number,
		to: number = 1,
		easing: EasingFunction = linear
	): AudioTransitionContext {
		context.changeVolume(0);
		context.play();
		const { complete, cancel } = transitionVolume(game, context, duration, to, easing);

		return {
			complete: () => {
				complete();
			},
			cancel: (revert: boolean = false) => {
				cancel(revert);
				if (revert) {
					context.stop();
				}
			}
		};
	}

	/**
	 * 音声をフェードアウトさせる。
	 *
	 * @param game 対象の `Game`。
	 * @param context 対象の `AudioPlayContext` 。
	 * @param duration フェードアウトの長さ (ms)。
	 * @param easing イージング関数。省略時は linear が指定される。
	 */
	export function fadeOut(
		game: Game,
		context: AudioPlayContext,
		duration: number,
		easing: EasingFunction = linear
	): AudioTransitionContext {
		const { complete, cancel } = transitionVolume(game, context, duration, 0, easing);

		return {
			complete: () => {
				complete();
				context.stop();
			},
			cancel: (revert: boolean = false) => {
				cancel(revert);
			}
		};
	}

	/**
	 * 二つの音声をクロスフェードさせる。
	 *
	 * @param game 対象の `Game`。
	 * @param fadeInContext フェードイン対象の `AudioPlayContext` 。
	 * @param fadeOutContext フェードアウト対象の `AudioPlayContext` 。
	 * @param duration クロスフェードの長さ (ms)。
	 * @param to クロスフェード後の音量。0 未満または 1 より大きい値を指定した場合の挙動は不定。省略時は `1` 。
	 * @param easing イージング関数。フェードインとフェードアウトで共通であることに注意。省略時は linear が指定される。
	 */
	export function crossFade(
		game: Game,
		fadeInContext: AudioPlayContext,
		fadeOutContext: AudioPlayContext,
		duration: number,
		to: number = 1,
		easing: EasingFunction = linear
	): AudioTransitionContext {
		const fadeInFuncs = fadeIn(game, fadeInContext, duration, to, easing);
		const fadeOutFuncs = fadeOut(game, fadeOutContext, duration, easing);

		return {
			complete: () => {
				fadeInFuncs.complete();
				fadeOutFuncs.complete();
			},
			cancel: (revert: boolean = false) => {
				fadeInFuncs.cancel(revert);
				fadeOutFuncs.cancel(revert);
			}
		};
	}

	/**
	 * 音量を指定のイージングで遷移させる。
	 *
	 * @param game 対象の `Game`。
	 * @param context 対象の `AudioPlayContext` 。
	 * @param duration 遷移の長さ (ms)。
	 * @param to 遷移後の音量。0 未満または 1 より大きい値を指定した場合の挙動は不定。
	 * @param easing イージング関数。省略時は linear が指定される。
	 */
	export function transitionVolume(
		game: Game,
		context: AudioPlayContext,
		duration: number,
		to: number,
		easing: EasingFunction = linear
	): AudioTransitionContext {
		const frame = 1000 / game.fps;
		const from = context.volume;
		let elapsed = 0;
		context.changeVolume(Util.clamp(from, 0, 1));

		const handler = (): boolean => {
			elapsed += frame;
			if (elapsed <= duration) {
				const progress = easing(elapsed, from, to - from, duration);
				context.changeVolume(Util.clamp(progress, 0, 1));
				return false;
			} else {
				context.changeVolume(to);
				return true;
			}
		};
		const remove = (): void => {
			if (game.onUpdate.contains(handler)) {
				game.onUpdate.remove(handler);
			}
		};
		game.onUpdate.add(handler);

		return {
			complete: () => {
				remove();
				context.changeVolume(to);
			},
			cancel: revert => {
				remove();
				if (revert) {
					context.changeVolume(from);
				}
			}
		};
	}
}

import type { GlyphArea, Glyph, ImageAsset, Surface } from "@akashic/pdi-types";
import { Font } from "./Font";
import { SurfaceUtil } from "./SurfaceUtil";

/**
 * BitmapFont の初期化に必要なパラメータのセット
 */
export interface BitmapFontGlyphInfo {
	map: { [key: string]: GlyphArea };
	width: number;
	height: number;
	missingGlyph: GlyphArea;
}

/**
 * `BitmapFont` のコンストラクタに渡すことができるパラメータ。
 * 各メンバの詳細は `BitmapFont` の同名メンバの説明を参照すること。
 */
export interface BitmapFontParameterObject {
	/**
	 * 文字データとして利用する画像を表す `Surface` または `ImageAsset`。文字を敷き詰めたもの。
	 */
	src: Surface | ImageAsset;

	/**
	 * BitmapFont の生成に必要なデータセット。
	 * glyphInfo が与えられる場合、 BitmapFontParameterObject の map, defaultGlyphWidth, defaultGlyphHeight, missingGlyph は参照されない。
	 */
	glyphInfo?: BitmapFontGlyphInfo;

	/**
	 * 各文字から画像上の位置・サイズなどを特定する情報。コードポイントから `GlyphArea` への写像。
	 */
	map?: { [key: string]: GlyphArea };

	/**
	 * `map` で指定を省略した文字に使われる、デフォルトの文字の幅。
	 * この値を省略した場合、 map の持つ全ての GlyphArea は width を持たなければならない。そうでない場合の動作は不定である。
	 */
	defaultGlyphWidth?: number;

	/**
	 * `map` で指定を省略した文字に使われる、デフォルトの文字の高さ
	 * この値を省略した場合、 map の持つ全ての GlyphArea は height を持たなければならない。そうでない場合の動作は不定である。
	 */
	defaultGlyphHeight?: number;

	/**
	 * `map` に存在しないコードポイントの代わりに表示するべき文字の `GlyphArea` 。
	 * @default undefined
	 */
	missingGlyph?: GlyphArea;
}

/**
 * ラスタ画像によるフォント。
 */
export class BitmapFont extends Font {
	surface: Surface;
	defaultGlyphWidth: number;
	defaultGlyphHeight: number;
	map: { [key: string]: GlyphArea };
	missingGlyph: GlyphArea | undefined;

	/**
	 * 各種パラメータを指定して `BitmapFont` のインスタンスを生成する。
	 * @param param `BitmapFont` に設定するパラメータ
	 */
	constructor(param: BitmapFontParameterObject) {
		super();
		// @ts-ignore
		this.surface = SurfaceUtil.asSurface(param.src);

		if (param.glyphInfo) {
			this.map = param.glyphInfo.map;
			this.defaultGlyphWidth = param.glyphInfo.width;
			this.defaultGlyphHeight = param.glyphInfo.height;
			this.missingGlyph = param.glyphInfo.missingGlyph;
			this.size = param.glyphInfo.height;
		} else {
			this.map = param.map || {};
			this.defaultGlyphWidth = param.defaultGlyphWidth || 0;
			this.defaultGlyphHeight = param.defaultGlyphHeight || 0;
			this.missingGlyph = param.missingGlyph;
			this.size = param.defaultGlyphHeight || 0;
		}
	}

	/**
	 * コードポイントに対応するグリフを返す。
	 * @param code コードポイント
	 */
	glyphForCharacter(code: number): Glyph | null {
		const g = this.map[code] || this.missingGlyph;

		if (!g) {
			return null;
		}

		const w = g.width === undefined ? this.defaultGlyphWidth : g.width;
		const h = g.height === undefined ? this.defaultGlyphHeight : g.height;
		const offsetX = g.offsetX || 0;
		const offsetY = g.offsetY || 0;
		const advanceWidth = g.advanceWidth === undefined ? w : g.advanceWidth;
		const surface = w === 0 || h === 0 ? undefined : this.surface;

		return {
			code,
			x: g.x,
			y: g.y,
			width: w,
			height: h,
			surface,
			offsetX,
			offsetY,
			advanceWidth,
			isSurfaceValid: true,
			_atlas: null
		};
	}

	/**
	 * 利用している `Surface` を破棄した上で、このフォントを破棄する。
	 */
	destroy(): void {
		if (this.surface && !this.surface.destroyed()) {
			this.surface.destroy();
		}
		this.map = undefined!;
	}

	/**
	 * 破棄されたオブジェクトかどうかを判定する。
	 */
	destroyed(): boolean {
		// mapをfalsy値で作成された場合最初から破棄扱いになるが、仕様とする
		return !this.map;
	}
}

import type { Renderer } from "@akashic/pdi-types";

/**
 * カメラを表すインターフェース。
 */
export interface Camera {
	/**
	 * このカメラがローカルであるか否か。
	 */
	local: boolean;

	/**
	 * @private
	 */
	_applyTransformToRenderer: (renderer: Renderer) => void;

	serialize(): any;
}

import type { Renderer } from "@akashic/pdi-types";
import type { Camera } from "./Camera";
import type { Object2DParameterObject } from "./Object2D";
import { Object2D } from "./Object2D";

export interface Camera2DSerialization {
	param: Camera2DParameterObject;
}

/**
 * `Camera2D` のコンストラクタに渡すことができるパラメータ。
 * 各メンバの詳細は `Camera2D` の同名メンバの説明を参照すること。
 */
export interface Camera2DParameterObject extends Object2DParameterObject {
	/**
	 * このカメラがローカルであるか否か。
	 * @default false
	 */
	local?: boolean;

	/**
	 * このカメラの名前。
	 * @default undefined
	 */
	name?: string;
}

/**
 * 2D世界におけるカメラ。
 */
export class Camera2D extends Object2D implements Camera {
	/**
	 * このカメラがローカルであるか否か。
	 *
	 * 初期値は偽である。
	 * この値は参照のためにのみ公開されている。ゲーム開発者はこの値を直接変更してはならない。
	 */
	local: boolean;

	/**
	 * このカメラの名前。
	 * 初期値は `undefined` である。
	 */
	name: string | undefined;

	/**
	 * @private
	 */
	_modifiedCount: number;

	/**
	 * 与えられたシリアリゼーションでカメラを復元する。
	 *
	 * @param ser `Camera2D#serialize()` の戻り値
	 */
	static deserialize(ser: any): Camera2D {
		const s: Camera2DSerialization = ser;
		const ret = new Camera2D(s.param);
		return ret;
	}

	/**
	 * 指定されたパラメータで `Camera2D` のインスタンスを生成する。
	 * @param param 初期化に用いるパラメータのオブジェクト
	 */
	constructor(param: Camera2DParameterObject) {
		super(param);
		this.local = !!param.local;
		this.name = param.name;
		this._modifiedCount = 0;
	}

	/**
	 * カメラ状態の変更をエンジンに通知する。
	 *
	 * このメソッドの呼び出し後、このカメラのプロパティに対する変更が各 `Renderer` の描画に反映される。
	 * ただし逆は真ではない。すなわち、再描画は他の要因によって行われることもある。
	 * ゲーム開発者は、このメソッドを呼び出していないことをもって再描画が行われていないことを仮定してはならない。
	 *
	 * 本メソッドは、このオブジェクトの `Object2D` 由来のプロパティ (`x`, `y`, `angle` など) を変更した場合にも呼びだす必要がある。
	 */
	modified(): void {
		this._modifiedCount = (this._modifiedCount + 1) % 32768;
		if (this._matrix) this._matrix._modified = true;
	}

	/**
	 * このカメラをシリアライズする。
	 *
	 * このメソッドの戻り値を `Camera2D#deserialize()` に渡すことで同じ値を持つカメラを復元することができる。
	 */
	serialize(): any {
		const ser: Camera2DSerialization = {
			param: {
				local: this.local,
				name: this.name,
				x: this.x,
				y: this.y,
				width: this.width,
				height: this.height,
				opacity: this.opacity,
				scaleX: this.scaleX,
				scaleY: this.scaleY,
				angle: this.angle,
				anchorX: this.anchorX,
				anchorY: this.anchorY,
				compositeOperation: this.compositeOperation
			}
		};
		return ser;
	}

	/**
	 * @private
	 */
	_applyTransformToRenderer(renderer: Renderer): void {
		if (this.angle || this.scaleX !== 1 || this.scaleY !== 1 || this.anchorX !== 0 || this.anchorY !== 0) {
			// Note: this.scaleX/scaleYが0の場合描画した結果何も表示されない事になるが、特殊扱いはしない
			renderer.transform(this.getMatrix()._matrix);
		} else {
			renderer.translate(-this.x, -this.y);
		}
		if (this.opacity !== 1) renderer.opacity(this.opacity);
	}

	/**
	 * @private
	 */
	override _updateMatrix(): void {
		if (!this._matrix) return;
		// カメラの angle, x, y はエンティティと逆方向に作用することに注意。
		if (this.angle || this.scaleX !== 1 || this.scaleY !== 1 || this.anchorX !== 0 || this.anchorY !== 0) {
			this._matrix.updateByInverse(
				this.width,
				this.height,
				this.scaleX,
				this.scaleY,
				this.angle,
				this.x,
				this.y,
				this.anchorX,
				this.anchorY
			);
		} else {
			this._matrix.reset(-this.x, -this.y);
		}
	}
}

import type { CommonArea, CommonOffset } from "@akashic/pdi-types";
import type { E } from "./entities/E";
import { Util } from "./Util";

// 外積の絶対値
function absCross(v1: CommonOffset, v2: CommonOffset): number {
	return v1.x * v2.y - v1.y * v2.x;
}

// 二次元ベクトルの減算
function sub(v1: CommonOffset, v2: CommonOffset): CommonOffset {
	return { x: v1.x - v2.x, y: v1.y - v2.y };
}

/**
 * オブジェクトなどの衝突判定機能を提供する。
 */
export module Collision {
	/**
	 * 二つのエンティティの衝突判定を行い、その結果を返す。
	 *
	 * 回転・拡大されたエンティティや、親の異なるエンティティ同士も扱える汎用の衝突判定処理。
	 * ただし計算量が多いので、大量のエンティティ間のすべての衝突を確認するような状況では利用を避けることが望ましい。
	 * 親が同じで回転・拡大を行わないエンティティ同士の場合は、より軽量な Collision.intersectAreas() を利用すること。
	 * 親が同じで中心座標同士の距離だけで判定してよい場合は、より軽量な Collision.withinAreas() を利用すること。
	 *
	 * 対象のエンティティの座標や大きさなどを変更した場合、
	 * この関数の呼び出し前にそのエンティティの modified() を呼び出しておく必要がある。
	 *
	 * @param e1 衝突判定するエンティティ
	 * @param e2 衝突判定するエンティティ
	 * @param area1 e1 の当たり判定領域。省略された場合、`{ x: 0, y: 0, width: e1.width, hegiht: e1.height }`
	 * @param area2 e2 の当たり判定領域。省略された場合、`{ x: 0, y: 0, width: e2.width, hegiht: e2.height }`
	 */
	export function intersectEntities(e1: E, e2: E, area1?: CommonArea | null, area2?: CommonArea | null): boolean {
		const lca = e1._findLowestCommonAncestorWith(e2);
		if (!lca) return false;

		const r1 = area1
			? { left: area1.x, top: area1.y, right: area1.x + area1.width, bottom: area1.y + area1.height }
			: { left: 0, top: 0, right: e1.width, bottom: e1.height };
		const r2 = area2
			? { left: area2.x, top: area2.y, right: area2.x + area2.width, bottom: area2.y + area2.height }
			: { left: 0, top: 0, right: e2.width, bottom: e2.height };

		const mat1 = e1._calculateMatrixTo(lca);
		const mat2 = e2._calculateMatrixTo(lca);

		// 座標系を合わせる: 共通祖先の座標系に合わせたそれぞれの四隅の点を求める。
		const lt1 = mat1.multiplyPoint({ x: r1.left, y: r1.top });
		const rt1 = mat1.multiplyPoint({ x: r1.right, y: r1.top });
		const lb1 = mat1.multiplyPoint({ x: r1.left, y: r1.bottom });
		const rb1 = mat1.multiplyPoint({ x: r1.right, y: r1.bottom });
		const lt2 = mat2.multiplyPoint({ x: r2.left, y: r2.top });
		const rt2 = mat2.multiplyPoint({ x: r2.right, y: r2.top });
		const lb2 = mat2.multiplyPoint({ x: r2.left, y: r2.bottom });
		const rb2 = mat2.multiplyPoint({ x: r2.right, y: r2.bottom });

		// AABB で枝狩りする。(高速化だけでなく後続の条件を単純化するのにも必要である点に注意)
		const minX1 = Math.min(lt1.x, rt1.x, lb1.x, rb1.x);
		const maxX1 = Math.max(lt1.x, rt1.x, lb1.x, rb1.x);
		const minX2 = Math.min(lt2.x, rt2.x, lb2.x, rb2.x);
		const maxX2 = Math.max(lt2.x, rt2.x, lb2.x, rb2.x);
		if (maxX1 < minX2 || maxX2 < minX1) return false;
		const minY1 = Math.min(lt1.y, rt1.y, lb1.y, rb1.y);
		const maxY1 = Math.max(lt1.y, rt1.y, lb1.y, rb1.y);
		const minY2 = Math.min(lt2.y, rt2.y, lb2.y, rb2.y);
		const maxY2 = Math.max(lt2.y, rt2.y, lb2.y, rb2.y);
		if (maxY1 < minY2 || maxY2 < minY1) return false;

		// 二つの四角形それぞれのいずれかの辺同士が交差するなら衝突している。
		if (
			Collision.intersectLineSegments(lt1, rt1, lt2, rt2) ||
			Collision.intersectLineSegments(lt1, rt1, rt2, rb2) ||
			Collision.intersectLineSegments(lt1, rt1, rb2, lb2) ||
			Collision.intersectLineSegments(lt1, rt1, lb2, lt2) ||
			Collision.intersectLineSegments(rt1, rb1, lt2, rt2) ||
			Collision.intersectLineSegments(rt1, rb1, rt2, rb2) ||
			Collision.intersectLineSegments(rt1, rb1, rb2, lb2) ||
			Collision.intersectLineSegments(rt1, rb1, lb2, lt2) ||
			Collision.intersectLineSegments(rb1, lb1, lt2, rt2) ||
			Collision.intersectLineSegments(rb1, lb1, rt2, rb2) ||
			Collision.intersectLineSegments(rb1, lb1, rb2, lb2) ||
			Collision.intersectLineSegments(rb1, lb1, lb2, lt2) ||
			Collision.intersectLineSegments(lb1, lt1, lt2, rt2) ||
			Collision.intersectLineSegments(lb1, lt1, rt2, rb2) ||
			Collision.intersectLineSegments(lb1, lt1, rb2, lb2) ||
			Collision.intersectLineSegments(lb1, lt1, lb2, lt2)
		) {
			return true;
		}

		// そうでない場合、e1 が e2 を包含しているなら衝突している。
		// ここで辺は交差していないので、e1 が e2 の頂点一つ (lt2) を包含しているなら、全体を包含している。
		// cf. https://ksta.skr.jp/topic/diaryb09.html#040528 "各辺の内側判定による内外判定"
		const s1 = absCross(sub(lt1, rt1), sub(lt2, rt1));
		if (
			s1 * absCross(sub(lb1, lt1), sub(lt2, lt1)) >= 0 &&
			s1 * absCross(sub(rb1, lb1), sub(lt2, lb1)) >= 0 &&
			s1 * absCross(sub(rt1, rb1), sub(lt2, rb1)) >= 0
		) {
			return true;
		}

		// そうでない場合、e2 が e1 を包含しているなら衝突している。
		const s2 = absCross(sub(lt2, rt2), sub(lt1, rt2));
		return (
			s2 * absCross(sub(lb2, lt2), sub(lt1, lt2)) >= 0 &&
			s2 * absCross(sub(rb2, lb2), sub(lt1, lb2)) >= 0 &&
			s2 * absCross(sub(rt2, rb2), sub(lt1, rb2)) >= 0
		);
	}

	/**
	 * 線分同士の衝突判定 (交差判定) を行い、その結果を返す。
	 *
	 * @param {CommonOffset} p1 線分の端点の一つ
	 * @param {CommonOffset} p2 線分の端点の一つ
	 * @param {CommonOffset} q1 もう一つの線分の端点の一つ
	 * @param {CommonOffset} q2 もう一つの線分の端点の一つ
	 */
	export function intersectLineSegments(p1: CommonOffset, p2: CommonOffset, q1: CommonOffset, q2: CommonOffset): boolean {
		// cf. https://ksta.skr.jp/topic/diaryb09.html#040518
		const p = sub(p2, p1);
		const q = sub(q2, q1);
		return (
			absCross(sub(q1, p1), p) * absCross(sub(q2, p1), p) <= 0 && absCross(sub(p1, q1), q) * absCross(sub(p2, q1), q) <= 0 // 符号が違うことを積の符号で判定している
		);
	}

	/**
	 * 矩形交差による衝突判定を行い、その結果を返す。
	 * 戻り値は、二つの矩形t1, t2が交差しているとき真、でなければ偽。
	 *
	 * @param {number} x1 t1のX座標
	 * @param {number} y1 t1のY座標
	 * @param {number} width1 t1の幅
	 * @param {number} height1 t1の高さ
	 * @param {number} x2 t2のX座標
	 * @param {number} y2 t2のY座標
	 * @param {number} width2 t2の幅
	 * @param {number} height2 t2の高さ
	 */
	export function intersect(
		x1: number,
		y1: number,
		width1: number,
		height1: number,
		x2: number,
		y2: number,
		width2: number,
		height2: number
	): boolean {
		return x1 <= x2 + width2 && x2 <= x1 + width1 && y1 <= y2 + height2 && y2 <= y1 + height1;
	}

	/**
	 * 矩形交差による衝突判定を行い、その結果を返す。
	 * 戻り値は、矩形t1, t2が交差しているとき真、でなければ偽。
	 *
	 * 特に、回転・拡大を利用していない、親が同じエンティティ同士の衝突判定に利用することができる。
	 * 条件を満たさない場合は `withinAreas()` や、より重いが正確な `intersectEntities()` の利用を検討すること。
	 *
	 * @param {CommonArea} t1 矩形1
	 * @param {CommonArea} t2 矩形2
	 */
	export function intersectAreas(t1: CommonArea, t2: CommonArea): boolean {
		return Collision.intersect(t1.x, t1.y, t1.width, t1.height, t2.x, t2.y, t2.width, t2.height);
	}

	/**
	 * 2点間の距離による衝突判定を行い、その結果を返す。
	 * 戻り値は、2点間の距離が閾値以内であるとき真、でなければ偽。
	 * @param {number} t1x 一点の X 座標
	 * @param {number} t1y 一点の Y 座標
	 * @param {number} t2x もう一点の X 座標
	 * @param {number} t2y もう一点の Y 座標
	 * @param {number} [distance=1] 衝突判定閾値 [pixel]
	 */
	export function within(t1x: number, t1y: number, t2x: number, t2y: number, distance: number = 1): boolean {
		return distance >= Util.distance(t1x, t1y, t2x, t2y);
	}

	/**
	 * 2つの矩形の中心座標間距離による衝突判定を行い、その結果を返す。
	 * 戻り値は、2点間の距離が閾値以内であるとき真、でなければ偽。
	 * @param {CommonArea} t1 矩形1
	 * @param {CommonArea} t2 矩形2
	 * @param {number} [distance=1] 衝突判定閾値 [pixel]
	 */
	export function withinAreas(t1: CommonArea, t2: CommonArea, distance: number = 1): boolean {
		return distance >= Util.distanceBetweenAreas(t1, t2);
	}
}

import type { Asset } from "@akashic/pdi-types";
import { CameraCancellingE } from "./entities/CameraCancellingE";
import { FilledRect } from "./entities/FilledRect";
import type { Game } from "./Game";
import { LoadingScene } from "./LoadingScene";
import type { Scene } from "./Scene";

/**
 * `DefaultLoadingScene` のコンストラクタに渡すことができるパラメータ。
 * 汎用性のあるクラスではなく、カスタマイズすべき余地は大きくないので LoadingSceneParameterObject は継承していない。
 */
export interface DefaultLoadingSceneParameterObject {
	/**
	 * このシーンが属する `Game` 。
	 */
	game: Game;
	style?: "default" | "compact";
}

/**
 * デフォルトローディングシーン。
 *
 * `Game#_defaultLoadingScene` の初期値として利用される。
 * このシーンはいかなるアセットも用いてはならない。
 */
export class DefaultLoadingScene extends LoadingScene {
	private _totalWaitingAssetCount: number;
	private _gauge: FilledRect;
	private _gaugeUpdateCount: number;
	private _barWidth: number;
	private _barHeight: number;
	private _style: "default" | "compact";

	/**
	 * `DefaultLoadingScene` のインスタンスを生成する。
	 * @param param 初期化に用いるパラメータのオブジェクト
	 */
	constructor(param: DefaultLoadingSceneParameterObject) {
		super({ game: param.game, name: "akashic:default-loading-scene" });
		if (param.style === "compact") {
			this._barWidth = this.game.width / 4;
			this._barHeight = 5;
			this._style = "compact";
		} else {
			this._barWidth = Math.min(this.game.width, Math.max(100, this.game.width / 2));
			this._barHeight = 5;
			this._style = "default";
		}
		this._gauge = undefined!;
		this._gaugeUpdateCount = 0;
		this._totalWaitingAssetCount = 0;
		this.onLoad.add(this._handleLoad, this);
		this.onTargetReset.add(this._handleTargetReset, this);
		this.onTargetAssetLoad.add(this._handleTargetAssetLoad, this);
	}

	/**
	 * @private
	 */
	_handleLoad(): boolean {
		let barX, barY, bgColor;
		if (this._style === "compact") {
			const margin = Math.min(this.game.width, this.game.height) * 0.05;
			barX = this.game.width - margin - this._barWidth;
			barY = this.game.height - margin - this._barHeight;
			bgColor = "transparent";
		} else {
			barX = (this.game.width - this._barWidth) / 2;
			barY = (this.game.height - this._barHeight) / 2;
			bgColor = "rgba(0, 0, 0, 0.8)";
		}
		let gauge: FilledRect;
		this.append(
			new CameraCancellingE({
				scene: this,
				children: [
					new FilledRect({
						scene: this,
						width: this.game.width,
						height: this.game.height,
						cssColor: bgColor,
						children: [
							new FilledRect({
								scene: this,
								x: barX,
								y: barY,
								width: this._barWidth,
								height: this._barHeight,
								cssColor: "gray",
								children: [
									(gauge = new FilledRect({
										scene: this,
										width: 0,
										height: this._barHeight,
										cssColor: "white"
									}))
								]
							})
						]
					})
				]
			})
		);
		gauge.onUpdate.add(this._handleUpdate, this);
		this._gauge = gauge;
		return true; // Trigger 登録を解除する
	}

	/**
	 * @private
	 */
	_handleUpdate(): void {
		const BLINK_RANGE = 50;
		const BLINK_PER_SEC = 2 / 3;
		++this._gaugeUpdateCount;

		// 白を上限に sin 波で明滅させる (updateしていることの確認)
		const c = Math.round(
			255 - BLINK_RANGE + Math.sin((this._gaugeUpdateCount / this.game.fps) * BLINK_PER_SEC * (2 * Math.PI)) * BLINK_RANGE
		);
		this._gauge.cssColor = "rgb(" + c + "," + c + "," + c + ")";
		this._gauge.modified();
	}

	/**
	 * @private
	 */
	_handleTargetReset(targetScene: Scene): void {
		if (this._gauge) {
			this._gauge.width = 0;
			this._gauge.modified();
		}
		this._totalWaitingAssetCount = targetScene._sceneAssetHolder.waitingAssetsCount;
	}

	/**
	 * @private
	 */
	_handleTargetAssetLoad(_asset: Asset): void {
		const waitingAssetsCount = this._targetScene._sceneAssetHolder.waitingAssetsCount;
		this._gauge.width = Math.ceil((1 - waitingAssetsCount / this._totalWaitingAssetCount) * this._barWidth);
		this._gauge.modified();
	}
}

import { CameraCancellingE } from "./entities/CameraCancellingE";
import type { FilledRectParameterObject } from "./entities/FilledRect";
import { FilledRect } from "./entities/FilledRect";
import type { SceneParameterObject } from "./Scene";
import { Scene } from "./Scene";

/**
 * @ignore
 */
function easeInOutQuad(t: number, b: number, c: number, d: number): number {
	t /= d / 2;
	if (t < 1) return (c / 2) * t * t + b;
	--t;
	return (-c / 2) * (t * (t - 2) - 1) + b;
}

/**
 * @ignore
 */
function easingInOutQuadWithSaturation(t: number, b: number, c: number, d: number): number {
	const threshold = d * 0.15;
	return 0 < t && t < threshold ? easeInOutQuad(t, b, c, threshold) : b + c;
}

/**
 * @ignore
 */
interface EasingFilledRectParameterObject extends FilledRectParameterObject {
	offsetDurationFrame: number;
	easingDurationFrame: number;
	valueFrom: number;
	valueTo: number;
	easing: (t: number, b: number, c: number, d: number) => number;
}

/**
 * @ignore
 */
class EasingFilledRect extends FilledRect {
	offsetDurationFrame: number;
	easingDurationFrame: number;
	valueFrom: number;
	valueTo: number;
	easing: (t: number, b: number, c: number, d: number) => number;

	private age: number = 0;

	constructor(param: EasingFilledRectParameterObject) {
		super(param);
		this.offsetDurationFrame = param.offsetDurationFrame;
		this.easingDurationFrame = param.easingDurationFrame;
		this.valueFrom = param.valueFrom;
		this.valueTo = param.valueTo;
		this.easing = param.easing;
		this.onUpdate.add(this._incrementAge, this);
		this.onUpdate.add(this._updateColor, this);
	}

	private _incrementAge(): void {
		this.age++;
	}

	private _updateColor(): void {
		const cssColor = this._calculateCSSColor();
		if (this.cssColor !== cssColor) {
			this.cssColor = cssColor;
			this.modified();
		}
	}

	private _calculateCSSColor(): string {
		const { age, offsetDurationFrame, easingDurationFrame, valueFrom, valueTo, easing } = this;

		const t = Math.max(age - offsetDurationFrame, 0) % easingDurationFrame;
		const b = valueFrom;
		const c = valueTo - valueFrom;
		const d = easingDurationFrame;
		const col = easing(t, b, c, d);

		return `rgb(${col}, ${col}, ${col})`;
	}
}

/**
 * `DefaultSkippingScene` のコンストラクタに渡すことができるパラメータ。
 */
export interface DefaultSkippingSceneParameterObject extends SceneParameterObject {
	style: "none" | "indicator";
}

/**
 * デフォルトスキッピングシーン。
 *
 * `Game#_defaultSkippingScene` の初期値として利用される。
 */
export class DefaultSkippingScene extends Scene {
	/**
	 * `DefaultSkippingScene` のインスタンスを生成する。
	 * @param param 初期化に用いるパラメータのオブジェクト
	 */
	constructor(param: DefaultSkippingSceneParameterObject) {
		super({ game: param.game, local: "full-local", name: "akashic:default-skipping-scene" });

		if (param.style === "indicator") {
			this.onLoad.addOnce(this._handleLoadForIndicator, this);
		}
	}

	/**
	 * @private
	 */
	private _handleLoadForIndicator(): void {
		const game = this.game;
		const rectSize = (Math.min(game.width, game.height) * 0.03) | 0;
		const margin = (Math.min(game.width, game.height) * 0.03) | 0;
		const marginRight = (Math.min(game.width, game.height) * 0.05) | 0;
		const marginBottom = (Math.min(game.width, game.height) * 0.05) | 0;
		const offsetDurationFrame = 400 / (1000 / game.fps);
		const easingDurationFrame = 2500 / (1000 / game.fps);
		const valueFrom = 255 - 50;
		const valueTo = 255;
		const easing = easingInOutQuadWithSaturation;

		this.append(
			new CameraCancellingE({
				scene: this,
				children: [3, 2, 1, 0].map((offsetIndex, i) => {
					return new EasingFilledRect({
						scene: this,
						cssColor: `rgb(${valueTo}, ${valueTo}, ${valueTo})`,
						width: rectSize,
						height: rectSize,
						x: game.width - i * (rectSize + margin) - marginRight,
						y: game.height - marginBottom,
						anchorX: 1,
						anchorY: 1,
						offsetDurationFrame: offsetDurationFrame * offsetIndex,
						easingDurationFrame,
						valueFrom,
						valueTo,
						easing
					});
				})
			})
		);
	}
}

