	/**
	 * 非表示フラグ。
	 */
	Hidden = 1 << 0,
	/**
	 * 描画結果がキャッシュ済みであることを示すフラグ。
	 */
	Cached = 1 << 1,
	/**
	 * modifiedされ、描画待ちであることを示すフラグ。
	 */
	Modified = 1 << 2,
	/**
