/**
 * ポインティング操作を表すイベントの基底クラス。
 * PointEvent#targetでそのポインティング操作の対象が、
 * PointEvent#pointでその対象からの相対座標が取得できる。
 *
 * 本イベントはマルチタッチに対応しており、PointEvent#pointerIdを参照することで識別することが出来る。
 *
 * abstract
 */
export class PointEventBase<T extends PointTarget> implements Event {
	/**
	 * 本クラスはどのtypeにも属さない。
	 */
	// @ts-ignore
	type: "point-down" | "point-move" | "point-up";
	eventFlags: number;
	local: boolean;
	player: Player | undefined;
	pointerId: number;
	point: CommonOffset;
	target: T | undefined;
	button: number;

	constructor(
		pointerId: number,
		target: T | undefined,
		point: CommonOffset,
		player?: Player,
		local?: boolean,
		eventFlags?: number,
		button?: number
	) {
		// @ts-ignore TODO: eventFlags のデフォルト値の扱い
		this.eventFlags = eventFlags;
		this.local = !!local;
		this.player = player;
		this.pointerId = pointerId;
		this.target = target;
		this.point = point;
		this.button = button ?? 0;
	}
}

/**
 * ポインティング操作の開始を表すイベントの基底クラス。
 */
export class PointDownEventBase<T extends PointTarget> extends PointEventBase<T> {
	override type: "point-down" = "point-down";
}

/**
 * ポインティング操作の終了を表すイベントの基底クラス。
 * PointDownEvent後にのみ発生する。
 *
 * PointUpEvent#startDeltaによってPointDownEvent時からの移動量が、
 * PointUpEvent#prevDeltaによって直近のPointMoveEventからの移動量が取得出来る。
 * PointUpEvent#pointにはPointDownEvent#pointと同じ値が格納される。
 */
export class PointUpEventBase<T extends PointTarget> extends PointEventBase<T> {
	override type: "point-up" = "point-up";
	startDelta: CommonOffset;
	prevDelta: CommonOffset;

	constructor(
		pointerId: number,
		target: T | undefined,
		point: CommonOffset,
		prevDelta: CommonOffset,
		startDelta: CommonOffset,
		player?: Player,
		local?: boolean,
		eventFlags?: number,
		button?: number
	) {
		super(pointerId, target, point, player, local, eventFlags, button);
		this.prevDelta = prevDelta;
		this.startDelta = startDelta;
	}
}

/**
 * ポインティング操作の移動を表すイベント。
 * PointDownEvent後にのみ発生するため、MouseMove相当のものが本イベントとして発生することはない。
 *
 * PointMoveEvent#startDeltaによってPointDownEvent時からの移動量が、
 * PointMoveEvent#prevDeltaによって直近のPointMoveEventからの移動量が取得出来る。
 * PointMoveEvent#pointにはPointMoveEvent#pointと同じ値が格納される。
 *
 * 本イベントは、プレイヤーがポインティングデバイスを移動していなくても、
 * カメラの移動等視覚的にポイントが変化している場合にも発生する。
 */
export class PointMoveEventBase<T extends PointTarget> extends PointEventBase<T> {
	override type: "point-move" = "point-move";
	startDelta: CommonOffset;
	prevDelta: CommonOffset;

	constructor(
		pointerId: number,
		target: T | undefined,
		point: CommonOffset,
		prevDelta: CommonOffset,
		startDelta: CommonOffset,
		player?: Player,
		local?: boolean,
		eventFlags?: number,
		button?: number
	) {
		super(pointerId, target, point, player, local, eventFlags, button);
		this.prevDelta = prevDelta;
		this.startDelta = startDelta;
	}
}

/**
 * 汎用的なメッセージを表すイベント。
 * MessageEvent#dataによってメッセージ内容を取得出来る。
 */
export class MessageEvent implements Event {
	type: "message" = "message";
	eventFlags: number;
	local: boolean;
	player: Player | undefined;
	data: any;

	constructor(data: any, player?: Player, local?: boolean, eventFlags?: number) {
		// @ts-ignore TODO: eventFlags のデフォルト値の扱い
		this.eventFlags = eventFlags;
		this.local = !!local;
		this.player = player;
		this.data = data;
	}
}

/**
 * 操作プラグインが通知する操作を表すイベント。
 * プラグインを識別する `OperationEvent#code` と、プラグインごとの内容 `OperationEvent#data` を持つ。
 */
export class OperationEvent implements Event {
	type: "operation" = "operation";
	eventFlags: number;
	local: boolean;
	player: Player | undefined;
	code: number;
	data: any;

	constructor(code: number, data: any, player?: Player, local?: boolean, eventFlags?: number) {
		// @ts-ignore TODO: eventFlags のデフォルト値の扱い
		this.eventFlags = eventFlags;
		this.local = !!local;
		this.player = player;
		this.code = code;
		this.data = data;
	}
}

/**
 * プレイヤーの参加を表すイベント。
 * JoinEvent#playerによって、参加したプレイヤーを取得出来る。
 */
export class JoinEvent implements Event {
	type: "join" = "join";
	eventFlags: number;
	player: Player;

	// NOTE: 型の後方互換のために念のためプロパティのみ残しておく
	storageValues: unknown;

	constructor(player: Player, eventFlags?: number) {
		// @ts-ignore TODO: eventFlags のデフォルト値の扱い
		this.eventFlags = eventFlags;
		this.player = player;
	}
}

/**
 * プレイヤーの離脱を表すイベント。
 * LeaveEvent#playerによって、離脱したプレイヤーを取得出来る。
 */
export class LeaveEvent implements Event {
	type: "leave" = "leave";
	eventFlags: number;
	player: Player;

	constructor(player: Player, eventFlags?: number) {
		// @ts-ignore TODO: eventFlags のデフォルト値の扱い
		this.eventFlags = eventFlags;
		this.player = player;
	}
}

/**
 * タイムスタンプを表すイベント。
 */
export class TimestampEvent implements Event {
	type: "timestamp" = "timestamp";
	eventFlags: number;
	player: Player;
	timestamp: number;

	constructor(timestamp: number, player: Player, eventFlags?: number) {
		// @ts-ignore TODO: eventFlags のデフォルト値の扱い
		this.eventFlags = eventFlags;
		this.player = player;
		this.timestamp = timestamp;
	}
}

/**
 * プレイヤー情報を表すイベント。
 * PointInfoEvent#player.nameによってプレイヤー名を、PlayerInfoEvent#player.userDataによって送信者依存の追加データを取得できる。
 */
export class PlayerInfoEvent implements Event {
	type: "player-info" = "player-info";
	eventFlags: number;
	player: Player;

	constructor(player: Player, eventFlags?: number) {
		// @ts-ignore TODO: eventFlags のデフォルト値の扱い
		this.eventFlags = eventFlags;
		this.player = player;
	}
}

/**
 * 新しい乱数の発生を表すイベント。
 * SeedEvent#generatorによって、本イベントで発生したRandomGeneratorを取得出来る。
 */
export class SeedEvent implements Event {
	type: "seed" = "seed";
	eventFlags: number;
	generator: RandomGenerator;

	constructor(generator: RandomGenerator, eventFlags?: number) {
		// @ts-ignore TODO: eventFlags のデフォルト値の扱い
		this.eventFlags = eventFlags;
		this.generator = generator;
	}
}

import type { CommonOffset } from "@akashic/pdi-types";
import * as pl from "@akashic/playlog";
import type { E } from "./entities/E";
import { PointDownEvent, PointMoveEvent, PointUpEvent } from "./entities/E";
import type { Event } from "./Event";
import { JoinEvent, LeaveEvent, MessageEvent, OperationEvent, PlayerInfoEvent, TimestampEvent } from "./Event";
import { EventIndex } from "./EventIndex";
import { ExceptionFactory } from "./ExceptionFactory";
import type { InternalOperationPluginOperation } from "./OperationPluginOperation";
import type { Player } from "./Player";
import type { WeakRefKVS } from "./WeakRefKVS";

// TODO: Game を意識しないインターフェース を検討する
export interface EventConverterParameterObjectGameLike {
	db: WeakRefKVS<E>;
	_localDb: WeakRefKVS<E>;
	_decodeOperationPluginOperation: (code: number, op: (number | string)[]) => any;
}

export interface EventConverterParameterObject {
	game: EventConverterParameterObjectGameLike;
	playerId?: string;
}

/**
 * 本クラスのインスタンスをゲーム開発者が直接生成することはなく、ゲーム開発者が利用する必要もない。
 * @ignore
 */
export class EventConverter {
	_game: EventConverterParameterObjectGameLike;
	_playerId: string | null;
	_playerTable: { [key: string]: Player };

	constructor(param: EventConverterParameterObject) {
		this._game = param.game;
		this._playerId = param.playerId ?? null;
		this._playerTable = {};
	}

	/**
	 * playlog.Eventからg.Eventへ変換する。
	 */
	toGameEvent(pev: pl.Event): Event {
		let pointerId: number;
		let entityId: number;
		let target: E | undefined;
		let point: CommonOffset;
		let startDelta: CommonOffset;
		let prevDelta: CommonOffset;
		let local: boolean;
		let timestamp: number;
		let button: number;

		const eventCode = pev[EventIndex.General.Code];
		const prio = pev[EventIndex.General.EventFlags];
		const playerId = pev[EventIndex.General.PlayerId];
		// @ts-ignore
		let player = this._playerTable[playerId] || { id: playerId };
		switch (eventCode) {
			case pl.EventCode.Join:
				player = {
					id: playerId,
					name: pev[EventIndex.Join.PlayerName]
				};
				// @ts-ignore
				if (this._playerTable[playerId] && this._playerTable[playerId].userData != null) {
					// @ts-ignore
					player.userData = this._playerTable[playerId].userData;
				}
				// @ts-ignore
				this._playerTable[playerId] = player;

				return new JoinEvent(player, prio);

			case pl.EventCode.Leave:
				delete this._playerTable[player.id];
				return new LeaveEvent(player, prio);

			case pl.EventCode.Timestamp:
				timestamp = pev[EventIndex.Timestamp.Timestamp];
				return new TimestampEvent(timestamp, player, prio);

			case pl.EventCode.PlayerInfo:
				const playerName = pev[EventIndex.PlayerInfo.PlayerName];
				const userData: any = pev[EventIndex.PlayerInfo.UserData];
				player = {
					id: playerId,
					name: playerName,
					userData
				};
				// @ts-ignore
				this._playerTable[playerId] = player;
				return new PlayerInfoEvent(player, prio);

			case pl.EventCode.Message:
				local = pev[EventIndex.Message.Local];
				return new MessageEvent(pev[EventIndex.Message.Message], player, local, prio);

			case pl.EventCode.PointDown:
				local = pev[EventIndex.PointDown.Local];
				pointerId = pev[EventIndex.PointDown.PointerId];
				entityId = pev[EventIndex.PointDown.EntityId];
				target = entityId == null ? undefined : entityId >= 0 ? this._game.db.get(entityId) : this._game._localDb.get(entityId);
				point = {
					x: pev[EventIndex.PointDown.X],
					y: pev[EventIndex.PointDown.Y]
				};
				button = pev[EventIndex.PointDown.Button];
				return new PointDownEvent(pointerId, target, point, player, local, prio, button);

			case pl.EventCode.PointMove:
				local = pev[EventIndex.PointMove.Local];
				pointerId = pev[EventIndex.PointMove.PointerId];
				entityId = pev[EventIndex.PointMove.EntityId];
				target = entityId == null ? undefined : entityId >= 0 ? this._game.db.get(entityId) : this._game._localDb.get(entityId);
				point = {
					x: pev[EventIndex.PointMove.X],
					y: pev[EventIndex.PointMove.Y]
				};
				startDelta = {
					x: pev[EventIndex.PointMove.StartDeltaX],
					y: pev[EventIndex.PointMove.StartDeltaY]
				};
				prevDelta = {
					x: pev[EventIndex.PointMove.PrevDeltaX],
					y: pev[EventIndex.PointMove.PrevDeltaY]
				};
				button = pev[EventIndex.PointMove.Button];
				return new PointMoveEvent(pointerId, target, point, prevDelta, startDelta, player, local, prio, button);

			case pl.EventCode.PointUp:
				local = pev[EventIndex.PointUp.Local];
				pointerId = pev[EventIndex.PointUp.PointerId];
				entityId = pev[EventIndex.PointUp.EntityId];
				target = entityId == null ? undefined : entityId >= 0 ? this._game.db.get(entityId) : this._game._localDb.get(entityId);
				point = {
					x: pev[EventIndex.PointUp.X],
					y: pev[EventIndex.PointUp.Y]
				};
				startDelta = {
					x: pev[EventIndex.PointUp.StartDeltaX],
					y: pev[EventIndex.PointUp.StartDeltaY]
				};
				prevDelta = {
					x: pev[EventIndex.PointUp.PrevDeltaX],
					y: pev[EventIndex.PointUp.PrevDeltaY]
				};
				button = pev[EventIndex.PointUp.Button];
				return new PointUpEvent(pointerId, target, point, prevDelta, startDelta, player, local, prio, button);

			case pl.EventCode.Operation:
				local = pev[EventIndex.Operation.Local];
				const operationCode = pev[EventIndex.Operation.OperationCode];
				const operationData = pev[EventIndex.Operation.OperationData];
				const decodedData = this._game._decodeOperationPluginOperation(operationCode, operationData);
				return new OperationEvent(operationCode, decodedData, player, local, prio);

			default:
				// TODO handle error
				throw ExceptionFactory.createAssertionError("EventConverter#toGameEvent");
		}
	}

	/**
	 * g.Eventからplaylog.Eventに変換する。
	 */
	toPlaylogEvent(e: Event, preservePlayer?: boolean): pl.Event {
		let targetId: number | null;
		let playerId: string | null;
		switch (e.type) {
			case "join":
			case "leave":
				// akashic-engine は決して Join と Leave を生成しない
				throw ExceptionFactory.createAssertionError("EventConverter#toPlaylogEvent: Invalid type: " + e.type);
			case "timestamp":
				const ts = e as TimestampEvent;
				playerId = preservePlayer ? (ts.player.id ?? null) : this._playerId;
				return [
					pl.EventCode.Timestamp, // 0: イベントコード
					ts.eventFlags, //          1: イベントフラグ値
					playerId, //               2: プレイヤーID
					ts.timestamp //            3: タイムスタンプ
				];
			case "player-info":
				const playerInfo = e as PlayerInfoEvent;
				playerId = preservePlayer ? (playerInfo.player.id ?? null) : this._playerId;
				return [
					pl.EventCode.PlayerInfo, //   0: イベントコード
					playerInfo.eventFlags, //     1: イベントフラグ値
					playerId, //                  2: プレイヤーID
					playerInfo.player.name, //    3: プレイヤー名
					playerInfo.player.userData // 4: ユーザデータ
				];
			case "point-down":
				const pointDown = e as PointDownEvent;
				targetId = pointDown.target ? pointDown.target.id : null;
				playerId = preservePlayer && pointDown.player ? (pointDown.player.id ?? null) : this._playerId;
				return [
					pl.EventCode.PointDown, // 0: イベントコード
					pointDown.eventFlags, //   1: イベントフラグ値
					playerId, //               2: プレイヤーID
					pointDown.pointerId, //    3: ポインターID
					pointDown.point.x, //      4: X座標
					pointDown.point.y, //      5: Y座標
					targetId, //               6?: エンティティID
					pointDown.button, //       7?: ボタンの種類
					!!pointDown.local //       8?: ローカルイベントかどうか
				];
			case "point-move":
				const pointMove = e as PointMoveEvent;
				targetId = pointMove.target ? pointMove.target.id : null;
				playerId = preservePlayer && pointMove.player ? (pointMove.player.id ?? null) : this._playerId;
				return [
					pl.EventCode.PointMove, // 0: イベントコード
					pointMove.eventFlags, //   1: イベントフラグ値
					playerId, //               2: プレイヤーID
					pointMove.pointerId, //    3: ポインターID
					pointMove.point.x, //      4: X座標
					pointMove.point.y, //      5: Y座標
					pointMove.startDelta.x, // 6: ポイントダウンイベントからのX座標の差
					pointMove.startDelta.y, // 7: ポイントダウンイベントからのY座標の差
					pointMove.prevDelta.x, //  8: 直前のポイントムーブイベントからのX座標の差
					pointMove.prevDelta.y, //  9: 直前のポイントムーブイベントからのY座標の差
					targetId, //               10?: エンティティID
					pointMove.button, //       11?:
					!!pointMove.local //       12?: ローカルイベントかどうか
				];
			case "point-up":
				const pointUp = e as PointUpEvent;
				targetId = pointUp.target ? pointUp.target.id : null;
				playerId = preservePlayer && pointUp.player ? (pointUp.player.id ?? null) : this._playerId;
				return [
					pl.EventCode.PointUp, // 0: イベントコード
					pointUp.eventFlags, //   1: イベントフラグ値
					playerId, //             2: プレイヤーID
					pointUp.pointerId, //    3: ポインターID
					pointUp.point.x, //      4: X座標
					pointUp.point.y, //      5: Y座標
					pointUp.startDelta.x, // 6: ポイントダウンイベントからのX座標の差
					pointUp.startDelta.y, // 7: ポイントダウンイベントからのY座標の差
					pointUp.prevDelta.x, //  8: 直前のポイントムーブイベントからのX座標の差
					pointUp.prevDelta.y, //  9: 直前のポイントムーブイベントからのY座標の差
					targetId, //             10?: エンティティID
					pointUp.button, //       11?:
					!!pointUp.local //       12?: ローカルイベントかどうか
				];
			case "message":
				const message = e as MessageEvent;
				playerId = preservePlayer && message.player ? (message.player.id ?? null) : this._playerId;
				return [
					pl.EventCode.Message, // 0: イベントコード
					message.eventFlags, //   1: イベントフラグ値
					playerId, //             2: プレイヤーID
					message.data, //         3: 汎用的なデータ
					!!message.local //       4?: ローカル
				];
			case "operation":
				const op = e as OperationEvent;
				playerId = preservePlayer && op.player ? (op.player.id ?? null) : this._playerId;
				return [
					pl.EventCode.Operation, // 0: イベントコード
					op.eventFlags, //          1: イベントフラグ値
					playerId, //               2: プレイヤーID
					op.code, //                3: 操作プラグインコード
					op.data, //                4: 操作プラグインデータ
					!!op.local //              5?: ローカル
				];
			default:
				throw ExceptionFactory.createAssertionError("Unknown type: " + e.type);
		}
	}

	makePlaylogOperationEvent(op: InternalOperationPluginOperation): pl.Event {
		const playerId = this._playerId;
		const eventFlags = op.priority != null ? op.priority & pl.EventFlagsMask.Priority : 0;
		return [
			pl.EventCode.Operation, // 0: イベントコード
			eventFlags, //             1: イベントフラグ値
			playerId, //               2: プレイヤーID
			op._code, //               3: 操作プラグインコード
			op.data, //                4: 操作プラグインデータ
			!!op.local //              5: ローカル
		];
	}
}

import type { Event } from "@akashic/playlog";
import type { EventFilterController } from "./EventFilterController";

/**
 * イベントフィルタ。
 *
 * 詳細は `Game#addEventFilter()` のドキュメントを参照。
 */
export type EventFilter = (events: Event[], controller: EventFilterController) => Event[];

import type { Event } from "@akashic/playlog";

/**
 * イベントフィルタ内で利用可能なコントローラ。
 */
export interface EventFilterController {
	/**
	 * 引数に指定したイベントを次のイベントフィルタの呼び出し時に処理する。
	 * @param pev イベント
	 */
	processNext(pev: Event): void;
}

export const enum EventPriority {
	Lowest = 0,
	Unjoined = 1,
	Joined = 2,
	System = 3
}

import type { AssertionError, AssetLoadError, TypeMismatchError } from "@akashic/pdi-types";
import type { RequestAssetDetail, RequestAssetLoadError } from "./errors";

/**
 * 例外生成ファクトリ。
 * エンジン内部での例外生成に利用するもので、ゲーム開発者は通常本モジュールを利用する必要はない。
 */
export module ExceptionFactory {
	export function createAssertionError(message: string, cause?: any): AssertionError {
		const e: AssertionError = new Error(message) as AssertionError;
		e.name = "AssertionError";
		e.cause = cause;
		return e;
	}

	export function createTypeMismatchError(methodName: string, expected: any, actual?: any, cause?: any): TypeMismatchError {
		let message = "Type mismatch on " + methodName + "," + " expected type is " + expected;
		if (arguments.length > 2) {
			// actual 指定時
			try {
				let actualString: string;
				if (actual && actual.constructor && actual.constructor.name) {
					actualString = actual.constructor.name;
				} else {
					actualString = typeof actual;
				}
				message += ", actual type is " + (actualString.length > 40 ? actualString.substr(0, 40) : actualString);
			} catch (_ex) {
				// メッセージ取得時に例外が発生したらactualの型情報出力はあきらめる
			}
		}
		message += ".";
		const e: TypeMismatchError = new Error(message) as TypeMismatchError;
		e.name = "TypeMismatchError";
		e.cause = cause;
		e.expected = expected;
		e.actual = actual;
		return e;
	}

	export function createAssetLoadError(
		message: string,
		retriable: boolean = true,
		_type: unknown = null, // 歴史的経緯により残っている値。利用していない。
		cause?: any
	): AssetLoadError {
		const e: AssetLoadError = new Error(message) as AssetLoadError;
		e.name = "AssetLoadError";
		e.cause = cause;
		e.retriable = retriable;
		return e;
	}

	export function createRequestAssetLoadError(message: string, detail: RequestAssetDetail, cause?: any): RequestAssetLoadError {
		const e = new Error(message) as RequestAssetLoadError;
		e.name = "RequestAssetLoadError";
		e.detail = detail;
		e.cause = cause;
		return e;
	}
}

import type { Glyph } from "@akashic/pdi-types";
import type { TextMetrics } from "./TextMetrics";
import { Util } from "./Util";

/**
 * フォント。
 */
export abstract class Font {
	/**
	 * フォントサイズ。
	 *
	 * この値は参照のためにのみ公開されている。ゲーム開発者はこの値を変更すべきではない。
	 */
	// @ts-ignore
	size: number;

	/**
	 * グリフの取得。
	 *
	 * 取得に失敗するとnullが返る。
	 *
	 * @param code 文字コード
	 */
	abstract glyphForCharacter(code: number): Glyph | null;

	abstract destroy(): void;

	abstract destroyed(): boolean;

	/**
	 * 対象の文字列を一行で描画した際の計測情報を返す。
	 *
	 * @param text 文字列
	 */
	measureText(text: string): TextMetrics {
		let width = 0;
		let actualBoundingBoxLeft = 0;
		let actualBoundingBoxRight = 0;
		let lastGlyph: Glyph | null = null;

		for (let i = 0; i < text.length; i++) {
			const code = Util.charCodeAt(text, i);
			if (!code) continue;

			const glyph = this.glyphForCharacter(code);
			if (!glyph || glyph.x < 0 || glyph.y < 0 || glyph.width < 0 || glyph.height < 0) continue;

			if (i === 0) {
				actualBoundingBoxLeft = -glyph.offsetX;
			}

			lastGlyph = glyph;
			width += glyph.advanceWidth;
		}

		if (lastGlyph) {
			actualBoundingBoxRight = width + lastGlyph.offsetX + lastGlyph.width - lastGlyph.advanceWidth;
		}

		return {
			width,
			actualBoundingBoxLeft,
			actualBoundingBoxRight
		};
	}
}

