	lastLocalTickMode: LocalTickModeString | null;

	/**
	 * 直近の `Scene#tickGenerationMode` の値。
	 *
	 * この値は参照のためにのみ公開されている。ゲーム開発者はこの値を変更すべきではない。
	 */
	lastTickGenerationMode: TickGenerationModeString | null;

	/**
	 * ゲーム全体で共有するサーフェスアトラス。
