}

/**
 * `Scene` のコンストラクタに渡すことができるパラメータ。
 * 説明のない各メンバの詳細は `Scene` の同名メンバの説明を参照すること。
 */
export interface SceneParameterObject {
	/**
	 * このシーンの属するゲーム。
	 */
	game: Game;

	/**
	 * このシーンで用いるアセットIDの配列。
	 *
	 * アセットIDとは、 game.jsonのassetsオブジェクトの各プロパティのキー文字列である。
	 * アセットIDでなくパスで指定したい場合は `assetPaths` を利用できる。両方指定してもよい。
	 *
	 * @default undefined
	 */
	assetIds?: (string | DynamicAssetConfiguration)[];

	/**
	 * このシーンで用いるアセットのファイルパスの配列。
	 *
	 * 各要素は `/` から始まる絶対パスでなければならない。
	 * ここでルートディレクトリ `/` はgame.json のあるディレクトリを指す。
	 * ただしオーディオアセットに限り、拡張子を含まないパスであること。
	 * (e.g. `/image/character01.png`, `/audio/bgm01`)
	 *
	 * パスでなくアセットIDで指定したい場合は `assetIds` を利用できる。両方指定してもよい。
	 * game.jsonのassetsに定義がないアセット(ダイナミックアセット)は指定できない。
	 *
	 * @default undefined
	 */
	assetPaths?: string[];

	/**
	 * このシーンのローカルティック消化ポリシー。
	 *
	 * * `"full-local"` が与えられた場合、このシーンはローカルシーンと呼ばれる。
	 *   ローカルシーンでは、他プレイヤーと独立な時間進行処理(ローカルティックの消化)が行われる。
	 * * `"non-local"` が与えられた場合、このシーンは非ローカルシーンと呼ばれる。
	 *   非ローカルシーンでは、他プレイヤーと共通の時間進行処理((非ローカル)ティックの消化)が行われる(onUpdateがfireされる)。
	 *   ローカルティックを消化することはない。
	 * * `"interpolate-local"` が与えられた場合、このシーンはローカルティック補間シーンと呼ばれる。
	 *   ローカルティック補間シーンでは、非ローカルシーン同様にティックを消化するが、
	 *   消化すべき非ローカルティックがない場合にローカルティックが補間され消化される。
	 *
	 * ローカルシーンに属するエンティティは、すべてローカルである(強制的にローカルエンティティとして生成される)。
	 * ローカルシーンは特にアセットロード中のような、他プレイヤーと同期すべきでないシーンのために存在する機能である。
	 *
	 * `LocalTickModeString` の代わりに `boolean` を与えることもできる。
	 * 偽は `"non-local"` 、 真は `"full-local"` と解釈される。
	 * @default "non-local"
	 */
	local?: boolean | LocalTickModeString;

	/**
	 * このシーンの識別用の名前。
	 * @default undefined
	 */
	name?: string;

	/**
	 * 時間経過の契機(ティック)をどのように生成するか。
	 *
	 * 省略された場合、 `"by-clock"` 。
	 * `Manual` を指定した場合、 `Game#raiseTick()` を呼び出さない限りティックが生成されない(時間経過しない)。
	 * ただしローカルティック(ローカルシーンの間などの「各プレイヤー間で独立な時間経過処理」)はこの値の影響を受けない。
	 * またこのシーンへの遷移直後、一度だけこの値に関わらずティックが生成される。
	 */
	tickGenerationMode?: TickGenerationModeString;

	/**
	 * シーンスタック上のこのシーンが描画される時、それに先んじてこのシーンの直下のシーンを描画するかどうか。
	 * このシーン自体は `seethrough` の値に関わらず常に描画されることに注意。
	 * ただし `seethrough` が true の時でもこのシーン以外の onUpdate は実行されない。そのため下のシーンの描画内容も更新されない。この挙動は実験的なものであり、将来的に変更されうる。
	 * @default false
	 */
	seethrough?: boolean;
}

/**
 * そのSceneの状態を表す列挙子。
 *
 * - "destroyed": すでに破棄されているシーンで、再利用が不可能になっている状態を表す
 * - "standby": 初期化された状態のシーンで、シーンスタックへ追加されることを待っている状態を表す
 * - "active": シーンスタックの一番上にいるシーンで、ゲームのカレントシーンとして活性化されている状態を表す
 * - "deactive": シーンスタックにいるが一番上ではないシーンで、裏側で非活性状態になっていることを表す
 * - "before-destroyed": これから破棄されるシーンで、再利用が不可能になっている状態を表す
 */
export type SceneStateString = "destroyed" | "standby" | "active" | "deactive" | "before-destroyed";

export type SceneLoadStateString = "initial" | "ready" | "ready-fired" | "loaded-fired";

/**
 * シーンを表すクラス。
 */
export class Scene {
	/**
	 * このシーンの子エンティティ。
	 *
	 * エンティティは `Scene#append()` によって追加され、 `Scene#remove()` によって削除される。
	 */
	children: E[];

	/**
	 * このシーンで利用できるアセット。
	 *
	 * アセットID をkeyに、対応するアセットのインスタンスを得ることができる。
	 * keyはこのシーンの生成時、コンストラクタの第二引数 `assetIds` に渡された配列に含まれる文字列でなければならない。
	 */
	assets: { [key: string]: Asset };

	/**
	 * このシーンで利用できるアセットへのアクセッサ。
	 *
	 * 歴史的経緯による `assets` との違いに注意。
	 * `assets` は「このシーンの生成時に読み込んだアセット」に「アセットIDをキーにして」アクセスするテーブルである。
	 * 他方この `asset` は `getImageById()`, `getAllTexts()` などのメソッドを持つオブジェクトである。
	 * アセットIDだけでなくパスでのアクセスや、複数アセットの一括取得ができる点で異なる。
	 */
	asset: AssetAccessor;

	/**
	 * このシーンの属するゲーム。
	 */
	game: Game;

	/**
	 * このシーンのローカルティック消化ポリシー。
	 *
	 * * `"non-local"` が与えられた場合、このシーンは非ローカルシーンと呼ばれる。
	 *   非ローカルシーンでは、他プレイヤーと共通の時間進行処理((非ローカル)ティックの消化)が行われる(onUpdateがfireされる)。
	 * * `"full-local"` が与えられた場合、このシーンはローカルシーンと呼ばれる。
	 *   ローカルシーンでは、他プレイヤーと独立な時間進行処理(ローカルティックの消化)が行われる。
	 * * `"interpolate-local"` が与えられた場合、このシーンはローカルティック補間シーンと呼ばれる。
	 *   ローカルティック補間シーンは、非ローカルシーン同様にティックを消化するが、
	 *   消化すべき非ローカルティックがない場合にローカルティックが補間され消化される。
	 *
	 * ローカルシーンとローカルティック補間シーンに属するエンティティは、
	 * すべてローカルである(強制的にローカルエンティティとして生成される)。
	 * ローカルシーンは特にアセットロード中のような、他プレイヤーと同期すべきでないシーンのために存在する機能である。
	 *
	 * この値は参照のためにのみ公開されている。ゲーム開発者はこの値を変更すべきではない。
	 */
	local: LocalTickModeString;

	/**
	 * 時間経過の契機(ティック)をどのように生成するか。
	 * `"manual"` の場合、 `Game#raiseTick()` を呼び出さない限りティックが生成されない(時間経過しない)。
	 * ただしローカルティック(ローカルシーンの間などの「各プレイヤー間で独立な時間経過処理」)はこの値の影響を受けない。
	 * またこのシーンへの遷移直後、一度だけこの値に関わらずティックが生成される。
	 *
	 * この値は参照のためにのみ公開されている。ゲーム開発者はこの値を変更すべきではない。
	 */
	tickGenerationMode: TickGenerationModeString;

	/**
	 * シーンの識別用の名前。
	 */
	name: string | undefined;

	/**
	 * シーンスタック上のこのシーンが描画される時、それに先んじてこのシーンの直下のシーンを描画するかどうか。
	 * このシーン自体は `seethrough` の値に関わらず常に描画されることに注意。
	 * ただし `seethrough` が true の時でもこのシーン以外の onUpdate は実行されない。そのため下のシーンの描画内容も更新されない。この挙動は実験的なものであり、将来的に変更されうる。
	 */
	seethrough: boolean;

	/**
	 * 時間経過イベント。本イベントの一度のfireにつき、常に1フレーム分の時間経過が起こる。
	 */
	onUpdate: Trigger<void>;

	/**
	 * 読み込み完了イベント。
	 *
	 * このシーンの生成時に(コンストラクタで)指定されたすべてのアセットの読み込みが終了した後、一度だけfireされる。
	 * このシーンのアセットを利用するすべての処理は、このイベントのfire後に実行されなければならない。
	 */
	onLoad: Trigger<Scene>;

	/**
	 * アセット読み込み成功イベント。
	 *
	 * このシーンのアセットが一つ読み込まれる度にfireされる。
	 * アセット読み込み中の動作をカスタマイズしたい場合に用いる。
	 */
	onAssetLoad: Trigger<Asset>;

	/**
	 * アセット読み込み失敗イベント。
	 *
	 * このシーンのアセットが一つ読み込みに失敗する度にfireされる。
	 * アセット読み込み中の動作をカスタマイズしたい場合に用いる。
	 * このイベントをhandleする場合、ハンドラは `AssetLoadFailureInfo#cancelRetry` を真にすることでゲーム続行を断念することができる。
	 */
	onAssetLoadFailure: Trigger<AssetLoadFailureInfo>;

	/**
	 * アセット読み込み完了イベント。
	 *
	 * このシーンのアセットが一つ読み込みに失敗または成功する度にfireされる。
	 * アセット読み込み中の動作をカスタマイズしたい場合に用いる。
	 */
	onAssetLoadComplete: Trigger<Asset>;

	/**
	 * シーンの状態。
	 */
	state: SceneStateString;

	/**
	 * シーンの状態変更イベント。
	 * 状態が初期化直後の `"standby"` 状態以外に変化するときfireされる。
	 */
	onStateChange: Trigger<SceneStateString>;

	/**
	 * 汎用メッセージイベント。
	 */
	onMessage: Trigger<MessageEvent>;

	/**
	 * シーン内でのpoint downイベント。
	 *
	 * このイベントは `E#onPointDown` とは独立にfireされる。
	 * すなわち、シーン内に同じ位置でのpoint downイベントに反応する `E` がある場合もない場合もこのイベントはfireされる。
	 */
	onPointDownCapture: Trigger<PointDownEvent>;

	/**
	 * シーン内でのpoint moveイベント。
	 *
	 * このイベントは `E#onPointMove` とは独立にfireされる。
	 * すなわち、シーン内に同じ位置でのpoint moveイベントに反応する `E` がある場合もない場合もこのイベントはfireされる。
	 */
	onPointMoveCapture: Trigger<PointMoveEvent>;

	/**
	 * シーン内でのpoint upイベント。
	 *
	 * このイベントは `E#onPointUp` とは独立にfireされる。
	 * すなわち、シーン内に同じ位置でのpoint upイベントに反応する `E` がある場合もない場合もこのイベントはfireされる。
	 */
	onPointUpCapture: Trigger<PointUpEvent>;

	/**
	 * シーン内での操作イベント。
	 */
	onOperation: Trigger<OperationEvent>;

	/**
	 * 時間経過イベント。本イベントの一度のfireにつき、常に1フレーム分の時間経過が起こる。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onUpdate` を利用すること。
	 */
	update: Trigger<void>;

	/**
	 * 読み込み完了イベント。
	 *
	 * このシーンの生成時に(コンストラクタで)指定されたすべてのアセットの読み込みが終了した後、一度だけfireされる。
	 * このシーンのアセットを利用するすべての処理は、このイベントのfire後に実行されなければならない。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onLoad` を利用すること。
	 */
	loaded: Trigger<Scene>;

	/**
	 * アセット読み込み成功イベント。
	 *
	 * このシーンのアセットが一つ読み込まれる度にfireされる。
	 * アセット読み込み中の動作をカスタマイズしたい場合に用いる。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onAssetLoad` を利用すること。
	 */
	assetLoaded: Trigger<Asset>;

	/**
	 * アセット読み込み失敗イベント。
	 *
	 * このシーンのアセットが一つ読み込みに失敗する度にfireされる。
	 * アセット読み込み中の動作をカスタマイズしたい場合に用いる。
	 * このイベントをhandleする場合、ハンドラは `AssetLoadFailureInfo#cancelRetry` を真にすることでゲーム続行を断念することができる。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onAssetLoadFailure` を利用すること。
	 */
	assetLoadFailed: Trigger<AssetLoadFailureInfo>;

	/**
	 * アセット読み込み完了イベント。
	 *
	 * このシーンのアセットが一つ読み込みに失敗または成功する度にfireされる。
	 * アセット読み込み中の動作をカスタマイズしたい場合に用いる。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onAssetLoadComplete` を利用すること。
	 */
	assetLoadCompleted: Trigger<Asset>;

	/**
	 * 汎用メッセージイベント。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onMessage` を利用すること。
	 */
	message: Trigger<MessageEvent>;

	/**
	 * シーン内でのpoint downイベント。
	 *
	 * このイベントは `E#onPointDown` とは独立にfireされる。
	 * すなわち、シーン内に同じ位置でのpoint downイベントに反応する `E` がある場合もない場合もこのイベントはfireされる。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onPointDownCapture` を利用すること。
	 */
	pointDownCapture: Trigger<PointDownEvent>;

	/**
	 * シーン内でのpoint moveイベント。
	 *
	 * このイベントは `E#onPointMove` とは独立にfireされる。
	 * すなわち、シーン内に同じ位置でのpoint moveイベントに反応する `E` がある場合もない場合もこのイベントはfireされる。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onPointMoveCapture` を利用すること。
	 */
	pointMoveCapture: Trigger<PointMoveEvent>;

	/**
	 * シーン内でのpoint upイベント。
	 *
	 * このイベントは `E#onPointUp` とは独立にfireされる。
	 * すなわち、シーン内に同じ位置でのpoint upイベントに反応する `E` がある場合もない場合もこのイベントはfireされる。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onPointUpCapture` を利用すること。
	 */
	pointUpCapture: Trigger<PointUpEvent>;

	/**
	 * シーン内での操作イベント。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onOperation` を利用すること。
	 */
	operation: Trigger<OperationEvent>;

	/**
	 * ゲーム開発者向けのコンテナ。
	 *
	 * この値はゲームエンジンのロジックからは使用されず、ゲーム開発者は任意の目的に使用してよい。
	 */
	vars: any;

	/**
	 * アセットとストレージの読み込みが終わったことを通知するTrigger。
	 * @private
	 */
	_onReady: Trigger<Scene>;

	/**
	 * アセットとストレージの読み込みが終わったことを通知するTrigger。
	 * @private
	 * @deprecated 非推奨である。将来的に削除される。代わりに `_onReady` を利用すること。
	 */
	_ready: Trigger<Scene>;

	/**
	 * 読み込みが開始されたか否か。
	 * すなわち、 `_load()` が呼び出された後か否か。
	 *
	 * 歴史的経緯により、このフラグの意味は「読み込みが終わった後」でも「onLoadがfireされた後」でもない点に注意。
	 * なお前者「(アセットとストレージの)読み込みが終わった後」は `_loadingState === "ready"` に与えられる。
	 *
	 * シーンの読み込みは概ね次の順で処理が進行する。
	 * * `_loaded` が真になる
	 * * 各種読み込みが完了する
	 * * `_loadingState` が `"ready"` になる
	 * * `_onReady` がfireされる
	 * * `_loadingState` が `"ready-fired"` になる
	 * * `onLoad` がfireされる
	 * * `_loadingState` が `"loaded-fired"` になる
	 * @private
	 */
	_loaded: boolean;

	/**
	 * 先読みが要求されたか否か。
	 * すなわち、 `prefetch()` が呼び出された後か否か。
	 * @private
	 */
	_prefetchRequested: boolean;

	/**
	 * アセットとストレージの読み込みが終わった後か否か。
	 * 「 `onLoad` がfireされた後」ではない点に注意。
	 * @private
	 */
	_loadingState: SceneLoadStateString;

	/**
	 * タイマー。通常は本変数直接ではなく、createTimer/deleteTimer/setInterval/clearInterval等の機構を利用する。
	 * @private
	 */
	_timer: TimerManager;

	/**
	 * シーンのアセットの保持者。
	 * @private
	 */
	_sceneAssetHolder: AssetHolder<SceneRequestAssetHandler>;

	/**
	 * `Scene#requestAssets()` で動的に要求されたアセットの保持者。
	 * @private
	 */
	_assetHolders: AssetHolder<SceneRequestAssetHandler>[];

	/**
	 * @private
	 */
	_waitingPrepare: ((done: () => void) => void) | undefined;

	/**
	 * 各種パラメータを指定して `Scene` のインスタンスを生成する。
	 * @param param 初期化に用いるパラメータのオブジェクト
	 */
	constructor(param: SceneParameterObject) {
		const game = param.game;
		const local =
			param.local === undefined
				? "non-local"
				: param.local === false
					? "non-local"
					: param.local === true
						? "full-local"
						: param.local;
		const tickGenerationMode = param.tickGenerationMode !== undefined ? param.tickGenerationMode : "by-clock";

		this.name = param.name;
		this.game = game;
		this.local = local;
		this.tickGenerationMode = tickGenerationMode;

		this.onLoad = new Trigger<Scene>();
		this.loaded = this.onLoad;
		this._onReady = new Trigger<Scene>();
		this._ready = this._onReady;
		this.assets = {};
		this.asset = game.asset;
		this.vars = {};

		this._loaded = false;
		this._prefetchRequested = false;
		this._loadingState = "initial";

		this.onUpdate = new Trigger<void>();
		this.update = this.onUpdate;
		this._timer = new TimerManager(this.onUpdate, this.game.fps);

		this.onAssetLoad = new Trigger<Asset>();
		this.onAssetLoadFailure = new Trigger<AssetLoadFailureInfo>();
		this.onAssetLoadComplete = new Trigger<Asset>();
		this.assetLoaded = this.onAssetLoad;
		this.assetLoadFailed = this.onAssetLoadFailure;
		this.assetLoadCompleted = this.onAssetLoadComplete;

		this.onMessage = new Trigger<MessageEvent>();
		this.onPointDownCapture = new Trigger<PointDownEvent>();
		this.onPointMoveCapture = new Trigger<PointMoveEvent>();
		this.onPointUpCapture = new Trigger<PointUpEvent>();
		this.onOperation = new Trigger<OperationEvent>();
		this.message = this.onMessage;
		this.pointDownCapture = this.onPointDownCapture;
		this.pointMoveCapture = this.onPointMoveCapture;
		this.pointUpCapture = this.onPointUpCapture;
		this.operation = this.onOperation;

		this.children = [];
		this.state = "standby";
		this.onStateChange = new Trigger<SceneStateString>();

		this._assetHolders = [];
		this._sceneAssetHolder = new AssetHolder<SceneRequestAssetHandler>({
			assetManager: this.game._assetManager,
			assetIds: param.assetIds,
			assetPaths: param.assetPaths,
			handlerSet: {
				owner: this,
				handleLoad: this._handleSceneAssetLoad,
				handleLoadFailure: this._handleSceneAssetLoadFailure,
				handleFinish: this._handleSceneAssetLoadFinish
			},
			userData: null
		});
		this.seethrough = param.seethrough != null ? param.seethrough : false;
	}

	/**
	 * このシーンが変更されたことをエンジンに通知する。
	 *
	 * このメソッドは、このシーンに紐づいている `E` の `modified()` を呼び出すことで暗黙に呼び出される。
	 * 通常、ゲーム開発者がこのメソッドを呼び出す必要はない。
	 * @param _isBubbling この関数をこのシーンの子の `modified()` から呼び出す場合、真を渡さなくてはならない。省略された場合、偽。
	 */
	modified(_isBubbling?: boolean): void {
		this.game.modified();
	}

	/**
	 * このシーンを破棄する。
	 *
	 * 破棄処理の開始時に、このシーンの `onStateChange` が引数 `BeforeDestroyed` でfireされる。
	 * 破棄処理の終了時に、このシーンの `onStateChange` が引数 `Destroyed` でfireされる。
	 * このシーンに紐づいている全ての `E` と全てのTimerは破棄される。
	 * `Scene#setInterval()`, `Scene#setTimeout()` に渡された関数は呼び出されなくなる。
	 *
	 * このメソッドは `Scene#end` や `Game#popScene` などによって要求されたシーンの遷移時に暗黙に呼び出される。
	 * 通常、ゲーム開発者がこのメソッドを呼び出す必要はない。
	 */
	destroy(): void {
		this.state = "before-destroyed";
		this.onStateChange.fire(this.state);

		// TODO: (GAMEDEV-483) Sceneスタックがそれなりの量になると重くなるのでScene#dbが必要かもしれない
		for (const db of [this.game.db, this.game._localDb]) {
			for (const key of db.keys()) {
				const e = db.get(key);
				if (e?.scene === this) {
					e.destroy();
				}
			}
		}

		this._timer.destroy();
		this.onUpdate.destroy();
		this.onMessage.destroy();
		this.onPointDownCapture.destroy();
		this.onPointMoveCapture.destroy();
		this.onPointUpCapture.destroy();
		this.onOperation.destroy();
		this.onLoad.destroy();
		this.onAssetLoad.destroy();
		this.onAssetLoadFailure.destroy();
		this.onAssetLoadComplete.destroy();
		this.assets = {};
		this.vars = {};

		// アセットを参照しているEより先に解放しないよう最後に解放する
		for (let i = 0; i < this._assetHolders.length; ++i) this._assetHolders[i].destroy();
		this._sceneAssetHolder.destroy();

		this.game = undefined!;
		this._waitingPrepare = undefined;

		this.state = "destroyed";
		this.onStateChange.fire(this.state);
		this.onStateChange.destroy();
	}

	/**
	 * 破棄済みであるかを返す。
	 */
	destroyed(): boolean {
		return this.game === undefined;
	}

	/**
	 * 一定間隔で定期的に処理を実行するTimerを作成して返す。
	 *
	 * 戻り値は作成されたTimerである。
	 * 通常は `Scene#setInterval` を利用すればよく、ゲーム開発者がこのメソッドを呼び出す必要はない。
	 * `Timer` はフレーム経過処理(`Scene#onUpdate`)で実現される疑似的なタイマーである。実時間の影響は受けない。
	 * @param interval Timerの実行間隔（ミリ秒）
	 */
	createTimer(interval: number): Timer {
		return this._timer.createTimer(interval);
	}

	/**
	 * Timerを削除する。
	 * `Scene#createTimer()`と同様に、通常はゲーム開発者がこのメソッドを呼び出す必要はない。
	 * このメソッドを利用する場合、メソッド実行前に対象のTimerのonElapseに登録したハンドラを全て削除しておく必要がある。
	 * @param timer 削除するTimer
	 */
	deleteTimer(timer: Timer): void {
		this._timer.deleteTimer(timer);
	}

	/**
	 * 一定間隔で定期的に実行される処理を作成する。
	 *
	 * `interval` ミリ秒おきに `owner` を `this` として `handler` を呼び出す。
	 * 戻り値は `Scene#clearInterval` の引数に指定して定期実行を解除するために使える値である。
	 * このタイマーはフレーム経過処理(`Scene#onUpdate`)で実現される疑似的なタイマーである。実時間の影響は受けない。
	 * 関数は指定時間の経過直後ではなく、経過後最初のフレームで呼び出される。
	 * @param handler 処理
	 * @param interval 実行間隔(ミリ秒)
	 * @param owner handlerの所有者。省略された場合、null
	 */
	setInterval(handler: () => void, interval: number, owner?: any): TimerIdentifier {
		return this._timer.setInterval(handler, interval, owner);
	}

	/**
	 * setIntervalで作成した定期処理を解除する。
	 * @param identifier 解除対象
	 */
	clearInterval(identifier: TimerIdentifier): void {
		this._timer.clearInterval(identifier);
	}

	/**
	 * 一定時間後に一度だけ実行される処理を作成する。
	 *
	 * `milliseconds` ミリ秒後(以降)に、一度だけ `owner` を `this` として `handler` を呼び出す。
	 * 戻り値は `Scene#clearTimeout` の引数に指定して処理を削除するために使える値である。
	 *
	 * このタイマーはフレーム経過処理(`Scene#onUpdate`)で実現される疑似的なタイマーである。実時間の影響は受けない。
	 * 関数は指定時間の経過直後ではなく、経過後最初のフレームで呼び出される。
	 * (理想的なケースでは、30FPSなら50msのコールバックは66.6ms時点で呼び出される)
	 * 時間経過に対して厳密な処理を行う必要があれば、自力で `Scene#onUpdate` 通知を処理すること。
	 *
	 * @param handler 処理
	 * @param milliseconds 時間(ミリ秒)
	 * @param owner handlerの所有者。省略された場合、null
	 */
	setTimeout(handler: () => void, milliseconds: number, owner?: any): TimerIdentifier {
		return this._timer.setTimeout(handler, milliseconds, owner);
	}

	/**
	 * setTimeoutで作成した処理を削除する。
	 * @param identifier 解除対象
	 */
	clearTimeout(identifier: TimerIdentifier): void {
		this._timer.clearTimeout(identifier);
	}

	/**
	 * このシーンが現在のシーンであるかどうかを返す。
	 */
	isCurrentScene(): boolean {
		return this.game.scene() === this;
	}

	/**
	 * 次のシーンへの遷移を要求する。
	 *
	 * このメソッドは、 `toPush` が真ならば `Game#pushScene()` の、でなければ `Game#replaceScene` のエイリアスである。
	 * このメソッドは要求を行うだけである。呼び出し直後にはシーン遷移は行われていないことに注意。
	 * このシーンが現在のシーンでない場合、 `AssertionError` がthrowされる。
	 * @param next 遷移後のシーン
	 * @param toPush 現在のシーンを残したままにするなら真、削除して遷移するなら偽を指定する。省略された場合偽
	 */
	gotoScene(next: Scene, toPush?: boolean): void {
		if (!this.isCurrentScene()) throw ExceptionFactory.createAssertionError("Scene#gotoScene: this scene is not the current scene");
		if (toPush) {
			this.game.pushScene(next);
		} else {
			this.game.replaceScene(next);
		}
	}

	/**
	 * このシーンの削除と、一つ前のシーンへの遷移を要求する。
	 *
	 * このメソッドは `Game#popScene()` のエイリアスである。
	 * このメソッドは要求を行うだけである。呼び出し直後にはシーン遷移は行われていないことに注意。
	 * このシーンが現在のシーンでない場合、 `AssertionError` がthrowされる。
	 */
	end(): void {
		if (!this.isCurrentScene()) throw ExceptionFactory.createAssertionError("Scene#end: this scene is not the current scene");

		this.game.popScene();
	}

	/**
	 * このSceneにエンティティを登録する。
	 *
	 * このメソッドは各エンティティに対して暗黙に呼び出される。ゲーム開発者がこのメソッドを明示的に呼び出す必要はない。
	 * @param e 登録するエンティティ
	 */
	register(e: E): void {
		this.game.register(e);
		e.scene = this;
	}

	/**
	 * このSceneからエンティティの登録を削除する。
	 *
	 * このメソッドは各エンティティに対して暗黙に呼び出される。ゲーム開発者がこのメソッドを明示的に呼び出す必要はない。
	 * @param e 登録を削除するエンティティ
	 */
	unregister(e: E): void {
		// @ts-ignore
		e.scene = undefined;
		this.game.unregister(e);
	}

	/**
	 * 子エンティティを追加する。
	 *
	 * `this.children` の末尾に `e` を追加する(`e` はそれまでに追加されたすべての子エンティティより手前に表示される)。
	 *
	 * @param e 子エンティティとして追加するエンティティ
	 */
	append(e: E): void {
		this.insertBefore(e, undefined);
	}

	/**
	 * 子エンティティを挿入する。
	 *
	 * `this.children` の`target`の位置に `e` を挿入する。
	 * `target` が`this` の子でない場合、`append(e)`と同じ動作となる。
	 *
	 * @param e 子エンティティとして追加するエンティティ
	 * @param target 挿入位置にある子エンティティ
	 */
	insertBefore(e: E, target: E | undefined): void {
		if (e.parent) e.remove();

		e.parent = this;

		let index = -1;
		if (target !== undefined && (index = this.children.indexOf(target)) > -1) {
			this.children.splice(index, 0, e);
		} else {
			this.children.push(e);
		}
		this.modified(true);
	}

	/**
	 * 子エンティティを削除する。
	 * `this` の子から `e` を削除する。 `e` が `this` の子でない場合、何もしない。
	 * @param e 削除する子エンティティ
	 */
	remove(e: E): void {
		const index = this.children.indexOf(e);
		if (index === -1) return;
		this.children[index].parent = undefined;
		this.children.splice(index, 1);
		this.modified(true);
	}

	/**
	 * シーン内でその座標に反応する `PointSource` を返す。
	 * @param point 対象の座標
	 * @param force touchable指定を無視する場合真を指定する。指定されなかった場合偽
	 * @param camera 対象のカメラ。指定されなかった場合undefined
	 */
	findPointSourceByPoint(point: CommonOffset, force?: boolean, camera?: Camera): PointSource {
		const mayConsumeLocalTick = this.local !== "non-local";
		const children = this.children;
		const m = camera && camera instanceof Camera2D ? camera.getMatrix() : undefined;

		for (let i = children.length - 1; i >= 0; --i) {
			const ret = children[i].findPointSourceByPoint(point, m, force);
			if (ret) {
				ret.local = (ret.target && ret.target.local) || mayConsumeLocalTick;
				return ret;
			}
		}
		return { target: undefined, point: undefined, local: mayConsumeLocalTick };
	}

	/**
	 * アセットの先読みを要求する。
	 *
	 * `Scene` に必要なアセットは、通常、`Game#pushScene()` などによるシーン遷移にともなって暗黙に読み込みが開始される。
	 * ゲーム開発者はこのメソッドを呼び出すことで、シーン遷移前にアセット読み込みを開始する(先読みする)ことができる。
	 * 先読み開始後、シーン遷移時までに読み込みが完了していない場合、通常の読み込み処理同様にローディングシーンが表示される。
	 */
	prefetch(): void {
		if (this._loaded) {
			// _load() 呼び出し後に prefetch() する意味はない(先読みではない)。
			return;
		}
		if (this._prefetchRequested) return;
		this._prefetchRequested = true;
		this._sceneAssetHolder.request();
	}

	requestAssets(
		assetIdsOrConf: (string | DynamicAssetConfiguration | AssetGenerationConfiguration)[] | SceneRequestAssetsParameterObject,
		handler: SceneRequestAssetHandler
	): void {
		if (this._loadingState !== "ready-fired" && this._loadingState !== "loaded-fired") {
			// このメソッドは読み込み完了前には呼び出せない。これは実装上の制限である。
			// やろうと思えば _load() で読み込む対象として加えることができる。が、その場合 `handler` を呼び出す方法が単純でないので対応を見送る。
			throw ExceptionFactory.createAssertionError("Scene#requestAssets(): can be called after loaded.");
		}

		let assetIds: (string | DynamicAssetConfiguration | AssetGenerationConfiguration)[];
		let alwaysNotifyFinish: boolean;
		if (Array.isArray(assetIdsOrConf)) {
			assetIds = assetIdsOrConf;
			alwaysNotifyFinish = false;
		} else {
			assetIds = assetIdsOrConf.assetIds;
			alwaysNotifyFinish = !!assetIdsOrConf.notifyErrorOnCallback;
		}

		const holder = new AssetHolder<SceneRequestAssetHandler>({
			assetManager: this.game._assetManager,
			assetIds,
			alwaysNotifyFinish,
			handlerSet: {
				owner: this,
				handleLoad: this._handleSceneAssetLoad,
				handleLoadFailure: this._handleSceneAssetLoadFailure,
				handleFinish: this._handleSceneAssetLoadFinish
			},
			userData: () => {
				// 不要なクロージャは避けたいが生存チェックのため不可避
				if (!this.destroyed()) {
					const failureAssetIds = holder._getFailureAssetIds();
					if (failureAssetIds.length) {
						// このパスに入るのは AssetHolder の alwaysNotifyFinish フラグを真にした時のみであることに注意
						const error = ExceptionFactory.createRequestAssetLoadError(
							"Scene#requestAssets(): failed to load the asset. refer to the 'detail' property for more information.",
							{ failureAssetIds }
						);
						handler(error);
					} else {
						handler();
					}
				}
			}
		});
		this._assetHolders.push(holder);
		holder.request();
	}

	/**
	 * @private
	 */
	_activate(): void {
		this.state = "active";
		this.onStateChange.fire(this.state);
	}

	/**
	 * @private
	 */
	_deactivate(): void {
		this.state = "deactive";
		this.onStateChange.fire(this.state);
	}

	/**
	 * @private
	 */
	_needsLoading(): boolean {
		return this._sceneAssetHolder.waitingAssetsCount > 0 || !!this._waitingPrepare;
	}

	/**
	 * @private
	 */
	_load(): void {
		if (this._loaded) return;
		this._loaded = true;

		if (!this._sceneAssetHolder.request()) {
			this._notifySceneReady();
		}
	}

	/**
	 * @private
	 */
	_handleSceneAssetLoad(asset: Asset): void {
		this.assets[asset.id] = asset;
		this.onAssetLoad.fire(asset);
		this.onAssetLoadComplete.fire(asset);
	}

	/**
	 * @private
	 */
	_handleSceneAssetLoadFailure(failureInfo: AssetLoadFailureInfo): void {
		this.onAssetLoadFailure.fire(failureInfo);
		this.onAssetLoadComplete.fire(failureInfo.asset);
	}

	/**
	 * @private
	 */
	_handleSceneAssetLoadFinish(holder: AssetHolder<SceneRequestAssetHandler>, succeed: boolean): void {
		if (!succeed) {
			this.game.terminateGame();
			return;
		}

		// 動的アセット (`requestAssets()` 由来) の場合
		if (holder.userData) {
			this.game._pushPostTickTask(holder.userData, null);
			return;
		}

		if (!this._loaded) {
			// prefetch() で開始されたアセット読み込みを完了したが、_load() がまだ呼ばれていない。
			// _notifySceneReady() は _load() 呼び出し後まで遅延する。
			return;
		}
		this._notifySceneReady();
	}

	/**
	 * @private
	 */
	_notifySceneReady(): void {
		// 即座に `_onReady` をfireすることはしない。tick()のタイミングで行うため、リクエストをgameに投げておく。
		this._loadingState = "ready";
		this.game._pushPostTickTask(this._fireReady, this);
	}

	/**
	 * @private
	 */
	_fireReady(): void {
		if (this.destroyed()) return;
		this._onReady.fire(this);
		this._loadingState = "ready-fired";
	}

	/**
	 * @private
	 */
	_fireLoaded(): void {
		if (this.destroyed()) return;
		if (this._loadingState === "loaded-fired") return;
		this.onLoad.fire(this);
		this._loadingState = "loaded-fired";
	}
}

import type { ScriptAsset } from "@akashic/pdi-types";
import { ExceptionFactory } from "./ExceptionFactory";
import type { Module } from "./Module";
import type { RequireCacheable } from "./RequireCacheable";

/**
 * `ScriptAsset` の実行コンテキスト。
 * 通常スクリプトアセットを実行するためにはこのクラスを経由する。
 *
 * ゲーム開発者がこのクラスを利用する必要はない。
 * スクリプトアセットを実行する場合は、暗黙にこのクラスを利用する `require()` を用いること。
 */
export class ScriptAssetContext implements RequireCacheable {
	/**
	 * @private
	 */
	_asset: ScriptAsset;

	/**
	 * @private
	 */
	_module: Module;

	/**
	 * @private
	 */
	_started: boolean;

	constructor(asset: ScriptAsset, module: Module) {
		this._asset = asset;
		this._module = module;
		this._started = false;
	}

	/**
	 * @private
	 */
	_cachedValue(): any {
		if (!this._started) throw ExceptionFactory.createAssertionError("ScriptAssetContext#_cachedValue: not executed yet.");
		return this._module.exports;
	}

	/**
	 * @private
	 */
	_executeScript(currentModule?: Module): any {
		if (this._started) return this._module.exports;

		if (currentModule) {
			// Node.js 互換挙動: Module#parent は一番最初に require() した module になる
			this._module.parent = currentModule;
			// Node.js 互換挙動: 親 module の children には自身が実行中の段階で既に追加されている
			currentModule.children.push(this._module);
		}

		this._started = true;
		this._asset.execute(this._module._runtimeValue);
		this._module.loaded = true;
		return this._module.exports;
	}
}

import type { ShaderProgram as PdiShaderProgram, ShaderUniform } from "@akashic/pdi-types";

/**
 * `ShaderProgram` のコンストラクタに渡すことができるパラメータ。
 * 各メンバの詳細は `ShaderProgram` の同名メンバの説明を参照すること。
 */
export interface ShaderProgramParameterObject {
	/**
	 * フラグメントシェーダの文字列。
	 *
	 * フラグメントシェーダは GLSL 1.0 に準拠した記述でなければならない。
	 * またフラグメントシェーダには以下の varying, uniform 値がエンジンによって与えられる。
	 * * uniform float uAlpha
	 *   * 描画時の透過度
	 * * uniform sampler2D uSampler
	 *   * 描画元テクスチャ番号
	 * * varying vec2 vTexCoord
	 *   * 描画元テクスチャの座標
	 *   * gl_FragColor = texture2D(uSampler, vTexCoord); のような形で描画元テクスチャのピクセルを参照できる
	 *
	 * @default undefined
	 */
	fragmentShader?: string;

	/**
	 * フラグメントシェーダに指定可能なuniform値のマップ。
	 * @default undefined
	 */
	uniforms?: { [key: string]: ShaderUniform };
}

/**
 * akashic-engineにおけるシェーダ機能を提供するクラス。
 * 現バージョンのakashic-engineではフラグメントシェーダのみをサポートする。
 */
export class ShaderProgram implements PdiShaderProgram {
	/**
	 * フラグメントシェーダの文字列。
	 *
	 * フラグメントシェーダは GLSL 1.0 に準拠した記述でなければならない。
	 * またフラグメントシェーダには以下の varying, uniform 値がエンジンによって与えられる。
	 * * uniform float uAlpha
	 *   * 描画時の透過度
	 * * uniform sampler2D uSampler
	 *   * 描画元テクスチャ番号
	 * * varying vec2 vTexCoord
	 *   * 描画元テクスチャの座標
	 *   * gl_FragColor = texture2D(uSampler, vTexCoord); のような形で描画元テクスチャのピクセルを参照できる
	 *
	 * この値は本クラスの生成時にのみ指定可能であり、直接書き換えてはならない。
	 */
	fragmentShader: string | undefined;

	/**
	 * 各シェーダに与えられるuniform値のマップ。
	 * この値は本クラスの生成時にのみ指定可能であり、 `ShaderUniform#value` 以外の値を直接書き換えてはならない。
	 */
	uniforms: { [name: string]: ShaderUniform } | undefined;

	/**
	 * シェーダプログラムの実体。
	 * @private
	 */
	_program: any;

	/**
	 * 各種パラメータを指定して `ShaderProgram` のインスタンスを生成する。
	 * @param param `ShaderProgram` に設定するパラメータ
	 */
	constructor(param: ShaderProgramParameterObject) {
		this.fragmentShader = param.fragmentShader;
		this.uniforms = param.uniforms;
	}
}

export interface SnapshotSaveRequest {
	/**
	 * ゲームの実行状態を表すスナップショット。
	 * JSONとして妥当な値でなければならない。
	 */
	snapshot: any;

	/**
	 * スナップショット生成時の時刻。
	 * `g.TimestampEvent` を利用するゲームの場合、それらと同じ基準の時間情報を与えなければならない。
	 */
	timestamp?: number;
}

import type { Camera } from "./Camera";
import type { E } from "./entities/E";
import { Sprite } from "./entities/Sprite";
import { ExceptionFactory } from "./ExceptionFactory";
import type { Scene } from "./Scene";

export class SpriteFactory {
	/**
	 * e の描画内容を持つ Sprite を生成する。
	 * @param scene 作成したSpriteを登録するScene
	 * @param e Sprite化したいE
	 * @param camera 使用カメラ
	 */
	static createSpriteFromE(scene: Scene, e: E, camera?: Camera): Sprite {
		const oldX = e.x;
		const oldY = e.y;
		let x = 0;
		let y = 0;
		let width = e.width;
		let height = e.height;

		const boundingRect = e.calculateBoundingRect();
		if (!boundingRect) {
			throw ExceptionFactory.createAssertionError("SpriteFactory.createSpriteFromE: camera must look e");
		}

		width = boundingRect.right - boundingRect.left;
		height = boundingRect.bottom - boundingRect.top;

		if (boundingRect.left < e.x) x = e.x - boundingRect.left;
		if (boundingRect.top < e.y) y = e.y - boundingRect.top;

		e.moveTo(x, y);
		// 再描画フラグを立てたくないために e._matrix を直接触っている
		if (e._matrix) e._matrix._modified = true;

		const surface = scene.game.resourceFactory.createSurface(Math.ceil(width), Math.ceil(height));
		const renderer = surface.renderer();
		renderer.begin();
		e.render(renderer, camera);
		renderer.end();

		const s = new Sprite({
			scene: scene,
			src: surface,
			width: width,
			height: height
		});
		s.moveTo(boundingRect.left, boundingRect.top);

		e.moveTo(oldX, oldY);
		if (e._matrix) e._matrix._modified = true;

		return s;
	}

	/**
	 * scene の描画内容を持つ Sprite を生成する。
	 * @param toScene 作ったSpriteを登録するScene
	 * @param fromScene Sprite化したいScene
	 * @param camera 使用カメラ
	 */
	static createSpriteFromScene(toScene: Scene, fromScene: Scene, camera?: Camera): Sprite {
		const surface = toScene.game.resourceFactory.createSurface(Math.ceil(fromScene.game.width), Math.ceil(fromScene.game.height));
		const renderer = surface.renderer();
		renderer.begin();

		const children = fromScene.children;
		for (let i = 0; i < children.length; ++i) children[i].render(renderer, camera);

		renderer.end();

		return new Sprite({
			scene: toScene,
			src: surface,
			width: fromScene.game.width,
			height: fromScene.game.height
		});
	}
}

import type * as pdi from "@akashic/pdi-types";
import { SurfaceAtlasSlot } from "./SurfaceAtlasSlot";

function getSurfaceAtlasSlot(slot: SurfaceAtlasSlot, width: number, height: number): SurfaceAtlasSlot | null {
	while (slot) {
		if (slot.width >= width && slot.height >= height) {
			return slot;
		}
		// @ts-ignore
		slot = slot.next;
	}

	return null;
}

/**
 * サーフェスアトラス。
 *
 * 与えられたサーフェスの指定された領域をコピーし一枚のサーフェスにまとめる。
 *
 * 本クラスのインスタンスをゲーム開発者が直接生成することはなく、ゲーム開発者が利用する必要もない。
 */
export class SurfaceAtlas {
	/**
	 * @private
	 */
	_surface: pdi.Surface;

	/**
	 * @private
	 */
	_emptySurfaceAtlasSlotHead: SurfaceAtlasSlot;

	/**
	 * @private
	 */
	_accessScore: number;

	/**
	 * @private
	 */
	_usedRectangleAreaSize: pdi.CommonSize;

	constructor(surface: pdi.Surface) {
		this._surface = surface;
		this._emptySurfaceAtlasSlotHead = new SurfaceAtlasSlot(0, 0, this._surface.width, this._surface.height);
		this._accessScore = 0;
		this._usedRectangleAreaSize = { width: 0, height: 0 };
	}

	reset(): void {
		const renderer = this._surface.renderer();
		renderer.begin();
		renderer.clear();
		renderer.end();
		this._emptySurfaceAtlasSlotHead = new SurfaceAtlasSlot(0, 0, this._surface.width, this._surface.height);
		this._accessScore = 0;
		this._usedRectangleAreaSize.width = 0;
		this._usedRectangleAreaSize.height = 0;
	}

	/**
	 * @private
	 */
	_acquireSurfaceAtlasSlot(width: number, height: number): SurfaceAtlasSlot | null {
		// Renderer#drawImage()でサーフェス上の一部を描画するとき、
		// 指定した部分に隣接する画素がにじみ出る現象が確認されている。
		// ここれではそれを避けるため1pixelの余白を与えている。
		width += 1;
		height += 1;

		const slot = getSurfaceAtlasSlot(this._emptySurfaceAtlasSlotHead, width, height);

		if (!slot) {
			return null;
		}

		const remainWidth = slot.width - width;
		const remainHeight = slot.height - height;
		let left: SurfaceAtlasSlot;
		let right: SurfaceAtlasSlot;
		if (remainWidth <= remainHeight) {
			left = new SurfaceAtlasSlot(slot.x + width, slot.y, remainWidth, height);
			right = new SurfaceAtlasSlot(slot.x, slot.y + height, slot.width, remainHeight);
		} else {
			left = new SurfaceAtlasSlot(slot.x, slot.y + height, width, remainHeight);
			right = new SurfaceAtlasSlot(slot.x + width, slot.y, remainWidth, slot.height);
		}

		left.prev = slot.prev;
		left.next = right;
		if (left.prev === null) {
			// left is head
			this._emptySurfaceAtlasSlotHead = left;
		} else {
			left.prev.next = left;
		}

		right.prev = left;
		right.next = slot.next;
		if (right.next) {
			right.next.prev = right;
		}

		const acquiredSlot = new SurfaceAtlasSlot(slot.x, slot.y, width, height);

		this._updateUsedRectangleAreaSize(acquiredSlot);

		return acquiredSlot;
	}

	/**
	 * @private
	 */
	_updateUsedRectangleAreaSize(slot: SurfaceAtlasSlot): void {
		const slotRight = slot.x + slot.width;
		const slotBottom = slot.y + slot.height;
		if (slotRight > this._usedRectangleAreaSize.width) {
			this._usedRectangleAreaSize.width = slotRight;
		}
		if (slotBottom > this._usedRectangleAreaSize.height) {
			this._usedRectangleAreaSize.height = slotBottom;
		}
	}

	/**
	 * サーフェスを追加する。
	 *
	 * @param surface 追加するサーフェス
	 * @param offsetX サーフェス内におけるX方向のオフセット位置。0以上の数値でなければならない
	 * @param offsetY サーフェス内におけるY方向のオフセット位置。0以上の数値でなければならない
	 * @param width サーフェス内における矩形の幅。0より大きい数値でなければならない
	 * @param height サーフェス内における矩形の高さ。0より大きい数値でなければならない
	 */
	addSurface(surface: pdi.Surface, offsetX: number, offsetY: number, width: number, height: number): SurfaceAtlasSlot | null {
		const slot = this._acquireSurfaceAtlasSlot(width, height);
		if (!slot) {
			return null;
		}

		const renderer = this._surface.renderer();
		renderer.begin();
		renderer.drawImage(surface, offsetX, offsetY, width, height, slot.x, slot.y);
		renderer.end();

		return slot;
	}

	/**
	 * このSurfaceAtlasの破棄を行う。
	 * 以後、このSurfaceを利用することは出来なくなる。
	 */
	destroy(): void {
		this._surface.destroy();
	}

	/**
	 * このSurfaceAtlasが破棄済であるかどうかを判定する。
	 */
	destroyed(): boolean {
		return this._surface.destroyed();
	}

	/**
	 * このSurfaceAtlasの大きさを取得する。
	 */
	getAtlasUsedSize(): pdi.CommonSize {
		return this._usedRectangleAreaSize;
	}

	getAccessScore(): number {
		return this._accessScore;
	}
}

import type { CommonSize, ResourceFactory } from "@akashic/pdi-types";
import type { Glyph } from "./Glyph";
import { SurfaceAtlas } from "./SurfaceAtlas";

function calcAtlasSize(hint: SurfaceAtlasSetHint): CommonSize {
	// @ts-ignore
	const width = Math.ceil(Math.min(hint.initialAtlasWidth!, hint.maxAtlasWidth));
	// @ts-ignore
	const height = Math.ceil(Math.min(hint.initialAtlasHeight!, hint.maxAtlasHeight));
	return { width: width, height: height };
}

/**
 * SurfaceAtlasが効率よく動作するためのヒント。
 *
 * ゲーム開発者はSurfaceAtlasが効率よく動作するための各種初期値・最大値などを提示できる。
 * SurfaceAtlasはこれを参考にするが、そのまま採用するとは限らない。
 */
export interface SurfaceAtlasSetHint {
	/**
	 * 初期アトラス幅。
	 */
	initialAtlasWidth?: number;

	/**
	 * 初期アトラス高さ。
	 */
	initialAtlasHeight?: number;

	/**
	 * 最大アトラス幅。
	 */
	maxAtlasWidth?: number;

	/**
	 * 最大アトラス高さ。
	 */
	maxAtlasHeight?: number;

	/**
	 * 最大アトラス保持数。
	 */
	maxAtlasNum?: number;
}

/**
 * SurfaceAtlasSet のコンストラクタに渡すことができるパラメータ。
 */
export interface SurfaceAtlasSetParameterObject {
	/**
	 * ゲームインスタンス。
	 */
	resourceFactory: ResourceFactory;

	/**
	 * ヒント。
	 *
	 * 詳細は `SurfaceAtlasSetHint` を参照。
	 */
	hint?: SurfaceAtlasSetHint;
}

/**
 * DynamicFont で使用される SurfaceAtlas を管理するクラス。
 *
 * 歴史的経緯のため、名前に反して DynamicFont 専用のクラスであり、汎用の SurfaceAtlas 管理クラスではない点に注意。
 */
export class SurfaceAtlasSet {
	/**
	 * SurfaceAtlas最大保持数初期値
	 */
	static INITIAL_MAX_SURFACEATLAS_NUM: number = 10;

	/**
	 * @private
	 */
	_surfaceAtlases: SurfaceAtlas[];

	/**
	 * @private
	 */
	_atlasGlyphsTable: Glyph[][];

	/**
	 * @private
	 */
	_maxAtlasNum: number;

	/**
	 * @private
	 */
	_resourceFactory: ResourceFactory;

	/**
	 * @private
	 */
	_atlasSize: CommonSize;

	/**
	 * @private
	 */
	_currentAtlasIndex: number;

	constructor(params: SurfaceAtlasSetParameterObject) {
		this._surfaceAtlases = [];
		this._atlasGlyphsTable = [];
		this._resourceFactory = params.resourceFactory;
		this._currentAtlasIndex = 0;
		const hint = params.hint ? params.hint : {};
		this._maxAtlasNum = hint.maxAtlasNum ? hint.maxAtlasNum : SurfaceAtlasSet.INITIAL_MAX_SURFACEATLAS_NUM;

		// 指定がないとき、やや古いモバイルデバイスでも確保できると言われる
		// 縦横512pxのテクスチャ一枚のアトラスにまとめる形にする
		// 2048x2048で確保してしまうと、Edge, Chrome にて処理が非常に遅くなることがある
		hint.initialAtlasWidth = hint.initialAtlasWidth ? hint.initialAtlasWidth : 512;
		hint.initialAtlasHeight = hint.initialAtlasHeight ? hint.initialAtlasHeight : 512;
		hint.maxAtlasWidth = hint.maxAtlasWidth ? hint.maxAtlasWidth : 512;
		hint.maxAtlasHeight = hint.maxAtlasHeight ? hint.maxAtlasHeight : 512;
		this._atlasSize = calcAtlasSize(hint);
	}

	/**
	 * @private
	 */
	_deleteAtlas(delteNum: number): void {
		for (let i = 0; i < delteNum; ++i) {
			const atlas = this._spliceLeastFrequentlyUsedAtlas();
			if (!atlas) return;
			atlas.destroy();
		}
	}

	/**
	 * surfaceAtlases の最も利用されていない SurfaceAtlas を探し、 そのインデックスを返す。
	 *
	 * _surfaceAtlases の長さが 0 の場合、 -1 を返す。
	 * @private
	 */
	_findLeastFrequentlyUsedAtlasIndex(): number {
		let minScore = Number.MAX_VALUE;
		let lowScoreAtlasIndex = -1;
		for (let i = 0; i < this._surfaceAtlases.length; ++i) {
			if (this._surfaceAtlases[i]._accessScore <= minScore) {
				minScore = this._surfaceAtlases[i]._accessScore;
				lowScoreAtlasIndex = i;
			}
		}
		return lowScoreAtlasIndex;
	}

	/**
	 * surfaceAtlases の最も利用されていない SurfaceAtlas を切り離して返す。
	 *
	 * 返された SurfaceAtlas に紐づいていたすべての Glyph はサーフェスを失う (_isSurfaceValid が偽になる) 。
	 * _surfaceAtlases の長さが 0 の場合、 何もせず null を返す。
	 * @private
	 */
	_spliceLeastFrequentlyUsedAtlas(): SurfaceAtlas | null {
		const idx = this._findLeastFrequentlyUsedAtlasIndex();
		if (idx === -1) return null;

		if (this._currentAtlasIndex >= idx) --this._currentAtlasIndex;

		const spliced = this._surfaceAtlases.splice(idx, 1)[0];
		const glyphs = this._atlasGlyphsTable.splice(idx, 1)[0];

		for (let i = 0; i < glyphs.length; i++) {
			const glyph = glyphs[i];
			glyph.surface = undefined;
			glyph.isSurfaceValid = false;
			glyph._atlas = null;
		}
		return spliced;
	}

	/**
	 * 空き領域のある SurfaceAtlas を探索する。
	 * glyph が持つ情報を SurfaceAtlas へ移動し、移動した SurfaceAtlas の情報で glyph を置き換える。
	 * glyph が持っていた surface は破棄される。
	 *
	 * 移動に成功した場合 `true` を、失敗した (空き領域が見つからなかった) 場合 `false` を返す。
	 * @private
	 */
	_moveGlyphSurface(glyph: Glyph): boolean {
		for (let i = 0; i < this._surfaceAtlases.length; ++i) {
			const index = (this._currentAtlasIndex + i) % this._surfaceAtlases.length;
			const atlas = this._surfaceAtlases[index];
			const slot = atlas.addSurface(glyph.surface!, glyph.x, glyph.y, glyph.width, glyph.height);

			if (slot) {
				this._currentAtlasIndex = index;
				if (glyph.surface) glyph.surface.destroy();
				glyph.surface = atlas._surface;
				glyph.x = slot.x;
				glyph.y = slot.y;
				glyph._atlas = atlas;
				this._atlasGlyphsTable[index].push(glyph);
				return true;
			}
		}
		return false;
	}

	/**
	 * サーフェスアトラスの再割り当てを行う。
	 * @private
	 */
	_reallocateAtlas(): void {
		let atlas: SurfaceAtlas = null!;
		if (this._surfaceAtlases.length >= this._maxAtlasNum) {
			atlas = this._spliceLeastFrequentlyUsedAtlas()!;
			atlas.reset();
		} else {
			atlas = new SurfaceAtlas(this._resourceFactory.createSurface(this._atlasSize.width, this._atlasSize.height));
		}
		this._surfaceAtlases.push(atlas);
		this._atlasGlyphsTable.push([]);
		this._currentAtlasIndex = this._surfaceAtlases.length - 1;
	}

	/**
	 * 引数で指定されたindexのサーフェスアトラスを取得する。
	 *
	 * 通常、ゲーム開発者がこのメソッドを呼び出す必要はない。
	 * @param index 取得対象のインデックス
	 */
	getAtlas(index: number): SurfaceAtlas {
		return this._surfaceAtlases[index];
	}

	/**
	 * サーフェスアトラスの保持数を取得する。
	 *
	 * 通常、ゲーム開発者がこのメソッドを呼び出す必要はない。
	 */
	getAtlasNum(): number {
		return this._surfaceAtlases.length;
	}

	/**
	 * 最大サーフェスアトラス保持数取得する。
	 */
	getMaxAtlasNum(): number {
		return this._maxAtlasNum;
	}

	/**
	 * 最大アトラス保持数設定する。
	 *
	 * 設定された値が、現在保持している_surfaceAtlasesの数より大きい場合、
	 * removeLeastFrequentlyUsedAtlas()で設定値まで削除する。
	 * @param value 設定値
	 */
	changeMaxAtlasNum(value: number): void {
		this._maxAtlasNum = value;
		if (this._surfaceAtlases.length > this._maxAtlasNum) {
			const diff = this._surfaceAtlases.length - this._maxAtlasNum;
			this._deleteAtlas(diff);
		}
	}

	/**
	 * サーフェスアトラスのサイズを取得する。
	 *
	 * 通常、ゲーム開発者がこのメソッドを呼び出す必要はない。
	 */
	getAtlasUsedSize(): CommonSize {
		return this._atlasSize;
	}

	/**
	 * グリフを追加する。
	 *
	 * glyph が持っていたサーフェスは破棄され、このクラスが管理するいずれかの (サーフェスアトラスの) サーフェスに紐づけられる。
	 * 追加に成功した場合 `true` を、失敗した (空き領域が見つからなかった) 場合 `false` を返す。
	 *
	 * 通常、ゲーム開発者がこのメソッドを呼び出す必要はない。
	 * @param glyph グリフ
	 */
	addGlyph(glyph: Glyph): boolean {
		// グリフがアトラスより大きいとき、`_atlasSet.addGlyph()`は失敗する。
		// `_reallocateAtlas()`でアトラス増やしてもこれは解決できない。
		// 無駄な空き領域探索とアトラスの再確保を避けるためにここでリターンする。
		if (glyph.width > this._atlasSize.width || glyph.height > this._atlasSize.height) {
			return false;
		}

		if (this._moveGlyphSurface(glyph)) return true;

		// retry
		this._reallocateAtlas();
		return this._moveGlyphSurface(glyph);
	}

	/**
	 * グリフの利用を通知する。
	 *
	 * サーフェスが不足した時、このクラスは最も利用頻度の低いサーフェスを解放して再利用する。
	 * このメソッドによるグリフの利用通知は、利用頻度の低いサーフェスを特定するために利用される。
	 *
	 * 通常、ゲーム開発者がこのメソッドを呼び出す必要はない。
	 * @param glyph グリフ
	 */
	touchGlyph(glyph: Glyph): void {
		// スコア更新
		// NOTE: LRUを捨てる方式なら単純なタイムスタンプのほうがわかりやすいかもしれない
		// NOTE: 正確な時刻は必要ないはずで、インクリメンタルなカウンタで代用すればDate()生成コストは省略できる
		if (glyph._atlas) glyph._atlas._accessScore += 1;
		for (let i = 0; i < this._surfaceAtlases.length; i++) {
			const atlas = this._surfaceAtlases[i];
			atlas._accessScore /= 2;
		}
	}

	/**
	 * このインスタンスを破棄する。
	 */
	destroy(): void {
		for (let i = 0; i < this._surfaceAtlases.length; ++i) {
			this._surfaceAtlases[i].destroy();
		}
		this._surfaceAtlases = undefined!;
		this._resourceFactory = undefined!;
		this._atlasGlyphsTable = undefined!;
	}

	/**
	 * このインスタンスが破棄済みであるかどうかを返す。
	 */
	destroyed(): boolean {
		return this._surfaceAtlases === undefined;
	}
}

/**
 * SurfaceAtlasの空き領域管理クラス。
 *
 * 本クラスのインスタンスをゲーム開発者が直接生成することはなく、ゲーム開発者が利用する必要もない。
 */
export class SurfaceAtlasSlot {
	x: number;
	y: number;
	width: number;
	height: number;
	prev: SurfaceAtlasSlot | null;
	next: SurfaceAtlasSlot | null;

	constructor(x: number, y: number, width: number, height: number) {
		this.x = x;
		this.y = y;
		this.width = width;
		this.height = height;
		this.prev = null;
		this.next = null;
	}
}

import type { CommonArea, CommonOffset, CommonRect, ImageAsset, Renderer, Surface } from "@akashic/pdi-types";
import { ExceptionFactory } from "./ExceptionFactory";

/**
 * Surface に関連するユーティリティ。
 */
export module SurfaceUtil {
	/**
	 * 引数 `src` が `undefined` または `Surface` でそのまま返す。
	 * そうでなくかつ `ImageAsset` であれば `Surface` に変換して返す。
	 *
	 * @param src
	 */
	export function asSurface(src: ImageAsset | Surface | undefined): Surface | undefined {
		if (!src) {
			return undefined;
		} else if ("type" in src && src.type === "image") {
			return src.asSurface();
		} else if ("_drawable" in src) {
			return src;
		}
		throw ExceptionFactory.createTypeMismatchError("SurfaceUtil#asSurface", "ImageAsset|Surface", src);
	}

	// TODO: 以下の型と関数については、Dynamicなsurfaceに関する処理を切り出して再利用性の高いオブジェクトを作成
	export type AnimatingHandler = {
		/**
		 * @private
		 */
		_handleAnimationStart: () => void;

		/**
		 * @private
		 */
		_handleAnimationStop: () => void;
	};

	/**
	 * サーフェスのアニメーティングイベントへのハンドラ登録。
	 *
	 * これはエンジンが利用するものであり、ゲーム開発者が呼び出す必要はない。
	 *
	 * @param animatingHandler アニメーティングハンドラ
	 * @param surface サーフェス
	 */
	export function setupAnimatingHandler(animatingHandler: AnimatingHandler, surface: Surface): void {
		if (surface.isPlaying()) {
			animatingHandler._handleAnimationStart();
		}
	}

	/**
	 * アニメーティングハンドラを別のサーフェスへ移動する。
	 *
	 * これはエンジンが利用するものであり、ゲーム開発者が呼び出す必要はない。
	 *
	 * @param animatingHandler アニメーティングハンドラ
	 * @param _beforeSurface ハンドラ登録を解除するサーフェス
	 * @param afterSurface ハンドラを登録するサーフェス
	 */
	export function migrateAnimatingHandler(animatingHandler: AnimatingHandler, _beforeSurface: Surface, afterSurface: Surface): void {
		animatingHandler._handleAnimationStop();

		if (afterSurface.isPlaying()) {
			animatingHandler._handleAnimationStart();
		}
	}

	/**
	 * 対象の `Surface` にナインパッチ処理された `Surface` を描画する。
	 *
	 * これは、画像素材の拡大・縮小において「枠」の表現を実現するものである。
	 * 画像の上下左右の「枠」部分の幅・高さを渡すことで、上下の「枠」を縦に引き延ばすことなく、
	 * また左右の「枠」を横に引き延ばすことなく画像を任意サイズに拡大・縮小できる。
	 * ゲームにおけるメッセージウィンドウやダイアログの表現に利用することを想定している。
	 *
	 * @param destSurface 描画先 `Surface`
	 * @param srcSurface 描画元 `Surface`
	 * @param borderWidth 上下左右の「拡大しない」領域の大きさ。すべて同じ値なら数値一つを渡すことができる。省略された場合、 `4`
	 */
	export function drawNinePatch(destSurface: Surface, srcSurface: Surface, borderWidth: CommonRect | number = 4): void {
		const renderer = destSurface.renderer();
		renderer.begin();
		renderer.clear();
		renderNinePatch(renderer, destSurface.width, destSurface.height, srcSurface, borderWidth);
		renderer.end();
	}

	/**
	 * 対象の `Renderer` にナインパッチ処理された `Surface` を描画する。
	 *
	 * 開発者は以下のような状況でこの関数を利用すべきである。
	 * * E を継承した独自の Entity を renderSelf() メソッドで描画する場合。この場合描画先の Surface が不明なので drawNinePatch() よりもこの関数の方が適している。
	 * * Surface全体ではなく部分的に描画したい場合。drawNinePatch() では Surface 全体の描画にしか対応していないため。
	 *
	 * @param renderer 描画先 `Renderer`
	 * @param width 描画先の横幅
	 * @param height 描画先の縦幅
	 * @param surface 描画元 `Surface`
	 * @param borderWidth 上下左右の「拡大しない」領域の大きさ。すべて同じ値なら数値一つを渡すことができる。省略された場合、 `4`
	 */
	export function renderNinePatch(
		renderer: Renderer,
		width: number,
		height: number,
		surface: Surface,
		borderWidth: CommonRect | number = 4
	): void {
		let border: CommonRect;
		if (typeof borderWidth === "number") {
			border = {
				top: borderWidth,
				bottom: borderWidth,
				left: borderWidth,
				right: borderWidth
			};
		} else {
			border = borderWidth;
		}
		//    x0  x1                          x2
		// y0 +-----------------------------------+
		//    | 1 |             5             | 2 |
		// y1 |---+---------------------------+---|
		//    |   |                           |   |
		//    | 7 |             9             | 8 |
		//    |   |                           |   |
		// y2 |---+---------------------------+---|
		//    | 3 |             6             | 4 |
		//    +-----------------------------------+
		//
		// 1-4: 拡縮無し
		// 5-6: 水平方向へ拡縮
		// 7-8: 垂直方向へ拡縮
		// 9  : 全方向へ拡縮

		const sx1 = border.left;
		const sx2 = surface.width - border.right;
		const sy1 = border.top;
		const sy2 = surface.height - border.bottom;
		const dx1 = border.left;
		const dx2 = width - border.right;
		const dy1 = border.top;
		const dy2 = height - border.bottom;

		// Draw corners
		const srcCorners: CommonArea[] = [
			{
				x: 0,
				y: 0,
				width: border.left,
				height: border.top
			},
			{
				x: sx2,
				y: 0,
				width: border.right,
				height: border.top
			},
			{
				x: 0,
				y: sy2,
				width: border.left,
				height: border.bottom
			},
			{
				x: sx2,
				y: sy2,
				width: border.right,
				height: border.bottom
			}
		];
		const destCorners: CommonOffset[] = [
			{ x: 0, y: 0 },
			{ x: dx2, y: 0 },
			{ x: 0, y: dy2 },
			{ x: dx2, y: dy2 }
		];
		for (let i = 0; i < srcCorners.length; ++i) {
			const c = srcCorners[i];
			renderer.save();
			renderer.translate(destCorners[i].x, destCorners[i].y);
			renderer.drawImage(surface, c.x, c.y, c.width, c.height, 0, 0);
			renderer.restore();
		}
		// Draw borders
		const srcBorders: CommonArea[] = [
			{ x: sx1, y: 0, width: sx2 - sx1, height: border.top },
			{ x: 0, y: sy1, width: border.left, height: sy2 - sy1 },
			{ x: sx2, y: sy1, width: border.right, height: sy2 - sy1 },
			{ x: sx1, y: sy2, width: sx2 - sx1, height: border.bottom }
		];
		const destBorders: CommonArea[] = [
			{ x: dx1, y: 0, width: dx2 - dx1, height: border.top },
			{ x: 0, y: dy1, width: border.left, height: dy2 - dy1 },
			{ x: dx2, y: dy1, width: border.right, height: dy2 - dy1 },
			{ x: dx1, y: dy2, width: dx2 - dx1, height: border.bottom }
		];
		for (let i = 0; i < srcBorders.length; ++i) {
			const s = srcBorders[i];
			const d = destBorders[i];
			renderer.save();
			renderer.translate(d.x, d.y);
			renderer.transform([d.width / s.width, 0, 0, d.height / s.height, 0, 0]);
			renderer.drawImage(surface, s.x, s.y, s.width, s.height, 0, 0);
			renderer.restore();
		}
		// Draw center
		const sw = sx2 - sx1;
		const sh = sy2 - sy1;
		const dw = dx2 - dx1;
		const dh = dy2 - dy1;
		renderer.save();
		renderer.translate(dx1, dy1);
		renderer.transform([dw / sw, 0, 0, dh / sh, 0, 0]);
		renderer.drawImage(surface, sx1, sy1, sw, sh, 0, 0);
		renderer.restore();
	}
}

/**
 * テキストの描画位置。
 * @deprecated 非推奨である。将来的に削除される。代わりに `TextAlignString` を利用すること。
 */
export enum TextAlign {
	/**
	 * 左寄せ。
	 */
	Left,
	/**
	 * 中央寄せ。
	 */
