import { Trigger } from "@akashic/trigger";

/**
 * 一定時間で繰り返される処理を表すタイマー。
 *
 * ゲーム開発者が本クラスのインスタンスを直接生成することはなく、
 * 通常はScene#setTimeout、Scene#setIntervalによって間接的に利用する。
 */
export class Timer {
	/**
	 * 実行間隔（ミリ秒）。
	 * この値は参照のみに利用され、直接値を変更することはできない。
	 */
	interval: number;

	/**
	 * `this.interval` 経過時にfireされるTrigger。
	 */
	onElapse: Trigger<void>;

	/**
	 * `this.interval` 経過時にfireされるTrigger。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onElapse` を利用すること。
	 */
	elapsed: Trigger<void>;

	/**
	 * @private
	 */
	// NOTE: 経過時間（ミリ秒）の計算はtick()の呼び出し時に1000 / fpsを計算する必要があるが、
	// 計算結果が浮動小数となる可能性があり、計算誤差が発生してしまう。
	// これを避けるために、経過時間をfps倍し、整数としたものthis._scaledElapsedとして管理する。
	// さらに比較対象となるintervalもfps倍し、this._scaledIntervalとして管理する。
	_scaledInterval: number;

	/**
	 * @private
	 */
	_scaledElapsed: number;

	constructor(interval: number, fps: number) {
		this.interval = interval;
		// NOTE: intervalが浮動小数の場合があるため念のため四捨五入する
		this._scaledInterval = Math.round(interval * fps);
		this.onElapse = new Trigger<void>();
		this.elapsed = this.onElapse;
		this._scaledElapsed = 0;
	}

	tick(): void {
		// NOTE: 1000 / fps * fps = 1000
		this._scaledElapsed += 1000;
		while (this._scaledElapsed >= this._scaledInterval) {
			// NOTE: this.elapsed.fire()内でdestroy()される可能性があるため、destroyed()を判定する
			if (!this.onElapse) {
				break;
			}
			this.onElapse.fire();
			this._scaledElapsed -= this._scaledInterval;
		}
	}

	canDelete(): boolean {
		return !this.onElapse || this.onElapse.length === 0;
	}

	destroy(): void {
		this.interval = undefined!;
		this.onElapse.destroy();
		this.onElapse = undefined!;
		this.elapsed = undefined!;
		this._scaledInterval = 0;
		this._scaledElapsed = 0;
	}

	destroyed(): boolean {
		return this.onElapse === undefined;
	}
}

import type { Trigger } from "@akashic/trigger";
import { ExceptionFactory } from "./ExceptionFactory";
import { Timer } from "./Timer";

/**
 * `Scene#setTimeout` や `Scene#setInterval` の実行単位を表す。
 * ゲーム開発者が本クラスのインスタンスを直接生成することはなく、
 * 本クラスの機能を直接利用することはない。
 */
export class TimerIdentifier {
	/**
	 * @ignore
	 */
	_timer: Timer;

	/**
	 * @ignore
	 */
	_handler: () => void;

	/**
	 * @ignore
	 */
	_handlerOwner: any;

	/**
	 * @ignore
	 */
	_fired: ((c: TimerIdentifier) => void) | undefined;

	/**
	 * @ignore
	 */
	_firedOwner: any;

	constructor(timer: Timer, handler: () => void, handlerOwner: any, fired?: (c: TimerIdentifier) => void, firedOwner?: any) {
		this._timer = timer;
		this._handler = handler;
		this._handlerOwner = handlerOwner;
		this._fired = fired;
		this._firedOwner = firedOwner;
		this._timer.onElapse.add(this._handleElapse, this);
	}

	destroy(): void {
		this._timer.onElapse.remove(this._handleElapse, this);
		this._timer = undefined!;
		this._handler = undefined!;
		this._handlerOwner = undefined!;
		this._fired = undefined;
		this._firedOwner = undefined;
	}

	destroyed(): boolean {
		return this._timer === undefined;
	}

	/**
	 * @private
	 */
	_handleElapse(): void {
		if (this.destroyed()) return;
		this._handler.call(this._handlerOwner);
		if (this._fired) {
			this._fired.call(this._firedOwner, this);
		}
	}
}

/**
 * Timerを管理する機構を提供する。
 * ゲーム開発者が本クラスを利用する事はない。
 */
export class TimerManager {
	/**
	 * @ignore
	 */
	_timers: Timer[];

	/**
	 * @ignore
	 */
	_trigger: Trigger<void>;

	/**
	 * @ignore
	 */
	_identifiers: TimerIdentifier[];

	/**
	 * @ignore
	 */
	_fps: number;

	/**
	 * @ignore
	 */
	_registered: boolean;

	constructor(trigger: Trigger<void>, fps: number) {
		this._timers = [];
		this._trigger = trigger;
		this._identifiers = [];
		this._fps = fps;
		this._registered = false;
	}

	destroy(): void {
		for (let i = 0; i < this._identifiers.length; ++i) {
			this._identifiers[i].destroy();
		}

		for (let i = 0; i < this._timers.length; ++i) {
			this._timers[i].destroy();
		}

		this._timers = undefined!;
		this._trigger = undefined!;
		this._identifiers = undefined!;
		this._fps = undefined!;
	}

	destroyed(): boolean {
		return this._timers === undefined;
	}

	/**
	 * 定期間隔で処理を実行するTimerを作成する。
	 * 本Timerはフレーム経過によって動作する疑似タイマーであるため、実時間の影響は受けない
	 * @param interval Timerの実行間隔（ミリ秒）
	 * @returns 作成したTimer
	 */
	createTimer(interval: number): Timer {
		if (!this._registered) {
			this._trigger.add(this._tick, this);
			this._registered = true;
		}

		if (interval < 0) throw ExceptionFactory.createAssertionError("TimerManager#createTimer: invalid interval");
		// NODE: intervalが0の場合に、Timer#tick()で無限ループとなるためintervalの最小値を1とする。
		if (interval < 1) interval = 1;

		// NOTE: Timerの_scaledElapsedと比較するため、this.fps倍した値を用いる
		// Math.min(1000 / this._fps * this.fps, interval * this._fps);
		const acceptableMargin = Math.min(1000, interval * this._fps);
		for (let i = 0; i < this._timers.length; ++i) {
			if (this._timers[i].interval === interval) {
				if (this._timers[i]._scaledElapsed < acceptableMargin) {
					return this._timers[i];
				}
			}
		}

		const timer = new Timer(interval, this._fps);
		this._timers.push(timer);

		return timer;
	}

	/**
	 * Timerを削除する。
	 * @param timer 削除するTimer
	 */
	deleteTimer(timer: Timer): void {
		if (!timer.canDelete()) return;

		const index = this._timers.indexOf(timer);
		if (index < 0) return;

		this._timers.splice(index, 1);
		timer.destroy();

		if (!this._timers.length) {
			if (!this._registered) return;
			this._trigger.remove(this._tick, this);
			this._registered = false;
		}
	}

	setTimeout(handler: () => void, milliseconds: number, owner?: any): TimerIdentifier {
		const timer = this.createTimer(milliseconds);
		const identifier = new TimerIdentifier(timer, handler, owner, this._onTimeoutFired, this);
		this._identifiers.push(identifier);
		return identifier;
	}

	clearTimeout(identifier: TimerIdentifier): void {
		this._clear(identifier);
	}

	setInterval(handler: () => void, interval: number, owner?: any): TimerIdentifier {
		const timer = this.createTimer(interval);
		const identifier = new TimerIdentifier(timer, handler, owner);
		this._identifiers.push(identifier);
		return identifier;
	}

	clearInterval(identifier: TimerIdentifier): void {
		this._clear(identifier);
	}

	/**
	 * すべてのTimerを時間経過させる。
	 * @private
	 */
	_tick(): void {
		const timers = this._timers.concat();
		for (let i = 0; i < timers.length; ++i) timers[i].tick();
	}

	/**
	 * @private
	 */
	_onTimeoutFired(identifier: TimerIdentifier): void {
		const index = this._identifiers.indexOf(identifier);
		if (index < 0) return;

		this._identifiers.splice(index, 1);

		const timer = identifier._timer;
		identifier.destroy();
		this.deleteTimer(timer);
	}

	/**
	 * @private
	 */
	_clear(identifier: TimerIdentifier): void {
		const index = this._identifiers.indexOf(identifier);
		if (index < 0) return;

		if (identifier.destroyed()) return;

		this._identifiers.splice(index, 1);

		const timer = identifier._timer;
		identifier.destroy();
		this.deleteTimer(timer);
	}
}

import type { CommonArea, CommonOffset, CompositeOperationString } from "@akashic/pdi-types";
import { CompositeOperation as CompOp } from "@akashic/pdi-types";

/**
 * ユーティリティ。
 */
export module Util {
	/**
	 * 2点間(P1..P2)の距離(pixel)を返す。
	 * @param {number} p1x P1-X
	 * @param {number} p1y P1-Y
	 * @param {number} p2x P2-X
	 * @param {number} p2y P2-Y
	 */
	export function distance(p1x: number, p1y: number, p2x: number, p2y: number): number {
		return Math.sqrt(Math.pow(p1x - p2x, 2) + Math.pow(p1y - p2y, 2));
	}

	/**
	 * 2点間(P1..P2)の距離(pixel)を返す。
	 * @param {CommonOffset} p1 座標1
	 * @param {CommonOffset} p2 座標2
	 */
	export function distanceBetweenOffsets(p1: CommonOffset, p2: CommonOffset): number {
		return Util.distance(p1.x, p1.y, p2.x, p2.y);
	}

	/**
	 * 2つの矩形の中心座標(P1..P2)間の距離(pixel)を返す。
	 * @param {CommonArea} p1 矩形1
	 * @param {CommonArea} p2 矩形2
	 */
	export function distanceBetweenAreas(p1: CommonArea, p2: CommonArea): number {
		return Util.distance(p1.x + p1.width / 2, p1.y + p1.height / 2, p2.x + p2.width / 2, p2.y + p2.height / 2);
	}

	/**
	 * idx文字目の文字のchar codeを返す。
	 *
	 * これはString#charCodeAt()と次の点で異なる。
	 * - idx文字目が上位サロゲートの時これを16bit左シフトし、idx+1文字目の下位サロゲートと論理和をとった値を返す。
	 * - idx文字目が下位サロゲートの時nullを返す。
	 *
	 * @param str 文字を取り出される文字列
	 * @param idx 取り出される文字の位置
	 */
	// highly based on https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/String/charCodeAt
	export function charCodeAt(str: string, idx: number): number | null {
		const code = str.charCodeAt(idx);

		if (0xd800 <= code && code <= 0xdbff) {
			const hi = code;
			const low = str.charCodeAt(idx + 1);
			return (hi << 16) | low;
		}

		if (0xdc00 <= code && code <= 0xdfff) {
			// Low surrogate
			return null;
		}

		return code;
	}

	/**
	 * enum の値の文字列を snake-case に変換した文字列を返す。
	 * @deprecated 非推奨である。非推奨の機能との互換性確保のために存在する。ゲーム開発者が使用すべきではない。
	 */
	export function enumToSnakeCase<T extends number, U extends string>(enumDef: { [key: number]: string }, val: T): U {
		const s = enumDef[val];
		// 呼び出し元で型が正しいことの保証が必要
		return (s[0].toLowerCase() + s.slice(1).replace(/[A-Z]/g, (c: string) => "-" + c.toLowerCase())) as U;
	}

	/**
	 * 数値を範囲内［min, max］に丸める
	 * @param num 丸める値
	 * @param min 値の下限
	 * @param max 値の上限
	 */
	export function clamp(num: number, min: number, max: number): number {
		return Math.min(Math.max(num, min), max);
	}

	/**
	 * CompositeOperation を CompositeOperationString に読み替えるテーブル。
	 * @deprecated 非推奨である。非推奨の機能との互換性のために存在する。ゲーム開発者が使用すべきではない。
	 */
	// enumToSnakeCase() で代用できるが、 CompositeOperation の変換は複数回実行されうるので専用のテーブルを作っている。
	export const compositeOperationStringTable: { [K in CompOp]: CompositeOperationString } = {
		[CompOp.SourceOver]: "source-over",
		[CompOp.SourceAtop]: "source-atop",
		[CompOp.Lighter]: "lighter",
		[CompOp.Copy]: "copy",
		[CompOp.ExperimentalSourceIn]: "experimental-source-in",
		[CompOp.ExperimentalSourceOut]: "experimental-source-out",
		[CompOp.ExperimentalDestinationAtop]: "experimental-destination-atop",
		[CompOp.ExperimentalDestinationIn]: "experimental-destination-in",
		[CompOp.DestinationOut]: "destination-out",
		[CompOp.DestinationOver]: "destination-over",
		[CompOp.Xor]: "xor",
		[CompOp.Difference]: "difference",
		[CompOp.Saturation]: "saturation"
	};
}

