/**
 * ポインティングソースによって対象となるエンティティを表すインターフェース。
 * エンティティとエンティティから見た相対座標によって構成される。
 */
export interface PointSource extends PointSourceBase<E> {}

export type PointEvent = PointEventBase<E>;

/**
 * ポインティング操作の開始を表すイベント。
 */
export class PointDownEvent extends PointDownEventBase<E> {}

/**
 * ポインティング操作の終了を表すイベント。
 * PointDownEvent後にのみ発生する。
 *
 * PointUpEvent#startDeltaによってPointDownEvent時からの移動量が、
 * PointUpEvent#prevDeltaによって直近のPointMoveEventからの移動量が取得出来る。
 * PointUpEvent#pointにはPointDownEvent#pointと同じ値が格納される。
 */
export class PointUpEvent extends PointUpEventBase<E> {}

/**
 * ポインティング操作の移動を表すイベント。
 * PointDownEvent後にのみ発生するため、MouseMove相当のものが本イベントとして発生することはない。
 *
 * PointMoveEvent#startDeltaによってPointDownEvent時からの移動量が、
 * PointMoveEvent#prevDeltaによって直近のPointMoveEventからの移動量が取得出来る。
 * PointMoveEvent#pointにはPointMoveEvent#pointと同じ値が格納される。
 *
 * 本イベントは、プレイヤーがポインティングデバイスを移動していなくても、
 * カメラの移動等視覚的にポイントが変化している場合にも発生する。
 */
export class PointMoveEvent extends PointMoveEventBase<E> {}

/**
 * `E` のコンストラクタに渡すことができるパラメータ。
 * 各メンバの詳細は `E` の同名メンバの説明を参照すること。
 */
export interface EParameterObject extends Object2DParameterObject {
	/**
	 * このエンティティが属するシーン。
	 */
	scene: Scene;

	/**
	 * このエンティティがローカルであるか否か。
	 * コンストラクタで真が指定された時、または属するシーンがローカルシーンまたはローカルティック補間シーンである時、この値は真である。
	 *
	 * この値が真である場合、このエンティティに対する point イベントはこのゲームインスタンスにのみ通知され、
	 * 他の参加者・視聴者には通知されない。また真である場合、 `id` の値の一意性は保証されない。
	 * @default false
	 */
	local?: boolean;

	/**
	 * このエンティティの親
	 * @default undefined
	 */
	parent?: E | Scene;

	/**
	 * このエンティティの全子エンティティ。
	 * @default undefined
	 */
	children?: E[];

	/**
	 * プレイヤーにとって触れられるオブジェクトであるかを表す。
	 * この値が偽である場合、ポインティングイベントの対象にならない。
	 * @default false
	 */
	touchable?: boolean;

	/**
	 * このエンティティの表示状態。
	 * @default false
	 */
	hidden?: boolean;

	/**
	 * このエンティティに割り振られる `E#id` の値。
	 * エンジンが一意の ID を設定するため、通常指定する必要はない。
	 * この値は、スナップショットローダがエンティティを復元する際にのみ指定されるべきである。
	 * @default undefined
	 */
	id?: number;

	/**
	 * ゲーム開発者向けのタグ情報管理コンテナ。
	 * この値はゲームエンジンのロジックからは使用されず、ゲーム開発者は任意の目的に使用してよい。
	 * @default undefined
	 */
	tag?: any;

	/**
	 * このエンティティの描画時に利用されるシェーダプログラム。
	 * このエンティティの `renderer#isSupportedShaderProgram()` が偽を返した場合、
	 * `renderer#setShaderProgram()` は呼ばれないことに注意。
	 *
	 * また `g.FilledRect` やその親エンティティに本値を指定した場合、対象の `g.FilledRect` の描画結果は不定である。
	 * これは実装上の制限に基づく現バージョンの仕様である。
	 *
	 * この値に `undefined` を指定した場合、親のシェーダプログラムを利用する。
	 * この値に `null` を指定した場合、明示的にデフォルトのシェーダプログラムを利用する。
	 *
	 * @default undefined
	 */
	shaderProgram?: ShaderProgram;
}

/**
 * akashic-engineに描画される全てのエンティティを表す基底クラス。
 * 本クラス単体に描画処理にはなく、直接利用する場合はchildrenを利用したコンテナとして程度で利用される。
 */
export class E extends Object2D implements CommonArea {
	/**
	 * このエンティティに割り振られる `Game` 単位で一意のID。(ただし `local` が真である場合を除く)
	 */
	id: number;

	/**
	 * このエンティティがローカルであるか否か。
	 * コンストラクタで真が指定された時、または属するシーンがローカルシーンまたはローカルティック補間シーンである時、この値は真である。
	 *
	 * この値が真である場合、このエンティティに対する point イベントはこのゲームインスタンスにのみ通知され、
	 * 他の参加者・視聴者には通知されない。また真である場合、 `id` の値の一意性は保証されない。
	 *
	 * この値は参照のためにのみ公開されている。ゲーム開発者はこの値を直接変更してはならない。
	 */
	local: boolean;

	/**
	 * このエンティティの全子エンティティ。
	 * 子エンティティが存在しない場合、本フィールドの値は `undefined` または空配列である。
	 */
	children: E[] | undefined;

	/**
	 * 親。
	 */
	parent: E | Scene | undefined;

	/**
	 * このエンティティが属するシーン。
	 */
	// @ts-ignore 外部クラスにより直接書き換えられる
	scene: Scene;

	/**
	 * 様々な状態を表すビットフラグ。
	 */
	state: EntityStateFlags;

	/**
	 * ゲーム開発者向けのタグ情報管理コンテナ。
	 * この値はゲームエンジンのロジックからは使用されず、ゲーム開発者は任意の目的に使用してよい。
	 */
	tag: any;

	/**
	 * このエンティティの描画時に利用されるシェーダプログラム。
	 * `isSupportedShaderProgram()` が偽を返す `g.Rendere` で描画される時、 `g.Renderer#setShaderProgram()` は呼ばれないことに注意。
	 *
	 * また `g.FilledRect` やその親エンティティに本値を指定した場合、対象の `g.FilledRect` の描画結果は不定である。
	 * これは実装上の制限に基づく現バージョンの仕様である。
	 *
	 * この値が `undefined` である場合、親のシェーダプログラムが利用される。
	 * この値が `null` である場合、明示的にデフォルトのシェーダプログラムが利用される。
	 *
	 * この値を変更した場合、 `this.modified()` を呼び出す必要がある。
	 */
	shaderProgram: ShaderProgram | null | undefined;

	/**
	 * 子にtouchableなものが含まれているかどうかを表す。
	 * @private
	 */
	_hasTouchableChildren: boolean;

	private _onUpdate: Trigger<void> | undefined;
	private _onMessage: Trigger<MessageEvent> | undefined;
	private _onPointDown: Trigger<PointDownEvent> | undefined;
	private _onPointUp: Trigger<PointUpEvent> | undefined;
	private _onPointMove: Trigger<PointMoveEvent> | undefined;
	private _touchable: boolean;

	/**
	 * 時間経過イベント。本イベントの一度のfireにつき、常に1フレーム分の時間経過が起こる。
	 */
	// Eの生成コスト低減を考慮し、参照された時のみ生成出来るようアクセサを使う
	get onUpdate(): Trigger<void> {
		if (!this._onUpdate) this._onUpdate = new ChainTrigger<void>(this.scene.onUpdate);
		return this._onUpdate;
	}
	// onUpdateは代入する必要がないのでsetterを定義しない

	/**
	 * このエンティティのmessageイベント。
	 */
	// Eの生成コスト低減を考慮し、参照された時のみ生成出来るようアクセサを使う
	get onMessage(): Trigger<MessageEvent> {
		if (!this._onMessage) this._onMessage = new ChainTrigger<MessageEvent>(this.scene.onMessage);
		return this._onMessage;
	}
	// onMessageは代入する必要がないのでsetterを定義しない

	/**
	 * このエンティティのpoint downイベント。
	 */
	// Eの生成コスト低減を考慮し、参照された時のみ生成出来るようアクセサを使う
	get onPointDown(): Trigger<PointDownEvent> {
		if (!this._onPointDown)
			this._onPointDown = new ChainTrigger<PointDownEvent>(this.scene.onPointDownCapture, this._isTargetOperation, this);
		return this._onPointDown;
	}
	// onPointDownは代入する必要がないのでsetterを定義しない

	/**
	 * このエンティティのpoint upイベント。
	 */
	// Eの生成コスト低減を考慮し、参照された時のみ生成出来るようアクセサを使う
	get onPointUp(): Trigger<PointUpEvent> {
		if (!this._onPointUp) this._onPointUp = new ChainTrigger<PointUpEvent>(this.scene.onPointUpCapture, this._isTargetOperation, this);
		return this._onPointUp;
	}
	// onPointUpは代入する必要がないのでsetterを定義しない

	/**
	 * このエンティティのpoint moveイベント。
	 */
	// Eの生成コスト低減を考慮し、参照された時のみ生成出来るようアクセサを使う
	get onPointMove(): Trigger<PointMoveEvent> {
		if (!this._onPointMove)
			this._onPointMove = new ChainTrigger<PointMoveEvent>(this.scene.onPointMoveCapture, this._isTargetOperation, this);
		return this._onPointMove;
	}
	// onPointMoveは代入する必要がないのでsetterを定義しない

	/**
	 * プレイヤーにとって触れられるオブジェクトであるかを表す。
	 *
	 * この値が偽である場合、ポインティングイベントの対象にならない。
	 * 初期値は `false` である。
	 *
	 * `E` の他のプロパティと異なり、この値の変更後に `this.modified()` を呼び出す必要はない。
	 */
	get touchable(): boolean {
		return this._touchable;
	}
	set touchable(v: boolean) {
		if (this._touchable === v) return;

		this._touchable = v;
		if (v) {
			this._enableTouchPropagation();
		} else {
			this._disableTouchPropagation();
		}
	}

	/**
	 * 時間経過イベント。本イベントの一度のfireにつき、常に1フレーム分の時間経過が起こる。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onUpdate` を利用すること。
	 */
	// Eの生成コスト低減を考慮し、参照された時のみ生成出来るようアクセサを使う
	get update(): Trigger<void> {
		return this.onUpdate;
	}
	// updateは代入する必要がないのでsetterを定義しない

	/**
	 * このエンティティのmessageイベント。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onMessage` を利用すること。
	 */
	// Eの生成コスト低減を考慮し、参照された時のみ生成出来るようアクセサを使う
	get message(): Trigger<MessageEvent> {
		return this.onMessage;
	}
	// messageは代入する必要がないのでsetterを定義しない

	/**
	 * このエンティティのpoint downイベント。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onPointDown` を利用すること。
	 */
	// Eの生成コスト低減を考慮し、参照された時のみ生成出来るようアクセサを使う
	get pointDown(): Trigger<PointDownEvent> {
		return this.onPointDown;
	}
	// pointDownは代入する必要がないのでsetterを定義しない

	/**
	 * このエンティティのpoint upイベント。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onPointUp` を利用すること。
	 */
	// Eの生成コスト低減を考慮し、参照された時のみ生成出来るようアクセサを使う
	get pointUp(): Trigger<PointUpEvent> {
		return this.onPointUp;
	}
	// pointUpは代入する必要がないのでsetterを定義しない

	/**
	 * このエンティティのpoint moveイベント。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onPointMove` を利用すること。
	 */
	// Eの生成コスト低減を考慮し、参照された時のみ生成出来るようアクセサを使う
	get pointMove(): Trigger<PointMoveEvent> {
		return this.onPointMove;
	}
	// pointMoveは代入する必要がないのでsetterを定義しない

	/**
	 * 各種パラメータを指定して `E` のインスタンスを生成する。
	 * @param param 初期化に用いるパラメータのオブジェクト
	 */
	constructor(param: EParameterObject) {
		super(param);
		this.children = undefined;
		this.parent = undefined;
		this._touchable = false;
		this.state = EntityStateFlags.None;
		this._hasTouchableChildren = false;
		this._onUpdate = undefined;
		this._onMessage = undefined;
		this._onPointDown = undefined;
		this._onPointMove = undefined;
		this._onPointUp = undefined;
		this.tag = param.tag;
		this.shaderProgram = param.shaderProgram;

		// local は Scene#register() や this.append() の呼び出しよりも先に立てなければならない
		// ローカルシーン・ローカルティック補間シーンのエンティティは強制的に local (ローカルティックが来て他プレイヤーとずれる可能性がある)
		this.local = param.scene.local !== "non-local" || !!param.local;

		if (param.children) {
			for (let i = 0; i < param.children.length; ++i) this.append(param.children[i]);
		}
		if (param.parent) {
			param.parent.append(this);
		}
		if (param.touchable != null) this.touchable = param.touchable;
		if (!!param.hidden) this.hide();

		// set id, scene
		// @ts-ignore NOTE: Game クラスで割り当てられるため、ここでは undefined を許容している
		this.id = param.id;
		param.scene.register(this);
	}

	/**
	 * 自分自身と子孫の内容を描画する。
	 *
	 * このメソッドは、 `Renderer#draw()` からエンティティのツリー構造をトラバースする過程で暗黙に呼び出される。
	 * 通常、ゲーム開発者がこのメソッドを呼び出す必要はない。
	 * @param renderer 描画先に対するRenderer
	 * @param camera 対象のカメラ。省略された場合、undefined
	 */
	render(renderer: Renderer, camera?: Camera): void {
		this.state &= ~EntityStateFlags.Modified;

		if (this.state & EntityStateFlags.Hidden) return;

		if (this.state & EntityStateFlags.ContextLess) {
			renderer.translate(this.x, this.y);
			const goDown = this.renderSelf(renderer, camera);
			if (goDown && this.children) {
				const children = this.children;
				const len = children.length;
				for (let i = 0; i < len; ++i) children[i].render(renderer, camera);
			}
			renderer.translate(-this.x, -this.y);
			return;
		}

		renderer.save();
		if (this.angle || this.scaleX !== 1 || this.scaleY !== 1 || this.anchorX !== 0 || this.anchorY !== 0) {
			// Note: this.scaleX/scaleYが0の場合描画した結果何も表示されない事になるが、特殊扱いはしない
			renderer.transform(this.getMatrix()._matrix);
		} else {
			// Note: 変形なしのオブジェクトはキャッシュもとらずtranslateのみで処理
			renderer.translate(this.x, this.y);
		}

		if (this.opacity !== 1) renderer.opacity(this.opacity);

		const op = this.compositeOperation;
		if (op !== undefined) {
			renderer.setCompositeOperation(typeof op === "string" ? op : Util.compositeOperationStringTable[op]);
		}

		if (this.shaderProgram !== undefined && renderer.isSupportedShaderProgram()) renderer.setShaderProgram(this.shaderProgram);

		const goDown = this.renderSelf(renderer, camera);

		if (goDown && this.children) {
			// Note: concatしていないのでunsafeだが、render中に配列の中身が変わる事はない前提とする
			const children = this.children;
			for (let i = 0; i < children.length; ++i) children[i].render(renderer, camera);
		}
		renderer.restore();
	}

	/**
	 * 自分自身の内容を描画する。
	 *
	 * このメソッドは、 `Renderer#draw()` からエンティティのツリー構造をトラバースする過程で暗黙に呼び出される。
	 * 通常、ゲーム開発者がこのメソッドを呼び出す必要はない。
	 *
	 * 戻り値は、このエンティティの子孫の描画をスキップすべきであれば偽、でなければ真である。
	 * (この値は、子孫の描画方法をカスタマイズする一部のサブクラスにおいて、通常の描画パスをスキップするために用いられる)
	 *
	 * @param _renderer 描画先に対するRenderer
	 * @param _camera 対象のカメラ
	 */
	renderSelf(_renderer: Renderer, _camera?: Camera): boolean {
		// nothing to do
		return true;
	}

	/**
	 * このエンティティが属する `Game` を返す。
	 */
	game(): Game {
		return this.scene.game;
	}

	/**
	 * 子を追加する。
	 *
	 * @param e 子エンティティとして追加するエンティティ
	 */
	append(e: E): void {
		this.insertBefore(e, undefined);
	}

	/**
	 * 子を挿入する。
	 *
	 * `target` が`this` の子でない場合、`append(e)` と同じ動作となる。
	 *
	 * @param e 子エンティティとして追加するエンティティ
	 * @param target 挿入位置にある子エンティティ
	 */
	insertBefore(e: E, target: E | undefined): void {
		if (e.parent) e.remove();
		if (!this.children) this.children = [];

		e.parent = this;

		let index = -1;
		if (target !== undefined && (index = this.children.indexOf(target)) > -1) {
			this.children.splice(index, 0, e);
		} else {
			this.children.push(e);
		}
		if (e._touchable || e._hasTouchableChildren) {
			this._hasTouchableChildren = true;
			this._enableTouchPropagation();
		}
		this.modified(true);
	}

	/**
	 * 子を削除する。
	 *
	 * `e` が `this` の子でない場合、 `AssertionError` がthrowされる。
	 * `e === undefined` であり親がない場合、 `AssertionError` がthrowされる。
	 *
	 * @param e 削除する子エンティティ。省略された場合、自身を親から削除する
	 */
	remove(e?: E): void {
		if (e === undefined) {
			this.parent!.remove(this);
			return;
		}

		const index = this.children ? this.children.indexOf(e) : -1;
		if (index < 0) throw ExceptionFactory.createAssertionError("E#remove: invalid child");
		this.children![index].parent = undefined;
		this.children!.splice(index, 1);

		if (e._touchable || e._hasTouchableChildren) {
			if (!this._findTouchableChildren(this)) {
				this._hasTouchableChildren = false;
				this._disableTouchPropagation();
			}
		}
		this.modified(true);
	}

	/**
	 * このエンティティを破棄する。
	 *
	 * 親がある場合、親からは `remove()` される。
	 * 子孫を持っている場合、子孫も破棄される。
	 */
	destroy(): void {
		if (this.destroyed()) return;

		if (this.parent) this.remove();

		if (this.children) {
			for (let i = this.children.length - 1; i >= 0; --i) {
				this.children[i].destroy();
			}
			if (this.children.length !== 0)
				throw ExceptionFactory.createAssertionError("E#destroy: can not destroy all children, " + this.children.length);

			this.children = undefined;
		}

		// この解放はstringとforeachを使って書きたいが、minifyする時は.アクセスの方がいいのでやむを得ない
		if (this._onUpdate) {
			this._onUpdate.destroy();
			this._onUpdate = undefined;
		}
		if (this._onMessage) {
			this._onMessage.destroy();
			this._onMessage = undefined;
		}
		if (this._onPointDown) {
			this._onPointDown.destroy();
			this._onPointDown = undefined;
		}
		if (this._onPointMove) {
			this._onPointMove.destroy();
			this._onPointMove = undefined;
		}
		if (this._onPointUp) {
			this._onPointUp.destroy();
			this._onPointUp = undefined;
		}

		this.scene.unregister(this);
	}

	/**
	 * このエンティティが破棄済みであるかを返す。
	 */
	destroyed(): boolean {
		return this.scene === undefined;
	}

	/**
	 * このエンティティに対する変更をエンジンに通知する。
	 *
	 * このメソッドの呼び出し後、 `this` に対する変更が各 `Renderer` の描画に反映される。
	 * ただし逆は真ではない。すなわち、再描画は他の要因によって行われることもある。
	 * ゲーム開発者は、このメソッドを呼び出していないことをもって再描画が行われていないことを仮定してはならない。
	 *
	 * 本メソッドは、このオブジェクトの `Object2D` 由来のプロパティ (`x`, `y`, `angle` など) を変更した場合にも呼びだす必要がある。
	 * 本メソッドは、描画キャッシュの無効化処理を含まない。描画キャッシュを持つエンティティは、このメソッドとは別に `invalidate()` を提供している。
	 * 描画キャッシュの無効化も必要な場合は、このメソッドではなくそちらを呼び出す必要がある。
	 * @param _isBubbling 通常ゲーム開発者が指定する必要はない。この変更通知が、(このエンティティ自身のみならず)子孫の変更の通知を含む場合、真を渡さなければならない。省略された場合、偽。
	 */
	modified(_isBubbling?: boolean): void {
		// _matrixの用途は描画に限らない(e.g. E#findPointSourceByPoint)ので、Modifiedフラグと無関係にクリアする必要がある
		if (this._matrix) this._matrix._modified = true;

		if (
			this.angle ||
			this.scaleX !== 1 ||
			this.scaleY !== 1 ||
			this.anchorX !== 0 ||
			this.anchorY !== 0 ||
			this.opacity !== 1 ||
			this.compositeOperation !== undefined ||
			this.shaderProgram !== undefined
		) {
			this.state &= ~EntityStateFlags.ContextLess;
		} else {
			this.state |= EntityStateFlags.ContextLess;
		}

		if (this.state & EntityStateFlags.Modified) return;
		this.state |= EntityStateFlags.Modified;

		if (this.parent) this.parent.modified(true);
	}

	/**
	 * このメソッドは、 `E#findPointSourceByPoint()` 内で子孫の探索をスキップすべきか判断するために呼ばれる。
	 * 通常、子孫の描画方法をカスタマイズする一部のサブクラスにおいて、与えられた座標に対する子孫の探索を制御する場合に利用する。
	 * ゲーム開発者がこのメソッドを呼び出す必要はない。
	 *
	 * 戻り値は、子孫の探索をスキップすべきであれば偽、でなければ真である。
	 *
	 * @param _point このエンティティ（`this`）の位置を基準とした相対座標
	 */
	shouldFindChildrenByPoint(_point: CommonOffset): boolean {
		// nothing to do
		return true;
	}

	/**
	 * 自身と自身の子孫の中で、その座標に反応する `PointSource` を返す。
	 *
	 * 戻り値は、対象が見つかった場合、 `target` に見つかったエンティティを持つ `PointSource` である。
	 * 対象が見つからなかった場合、 `undefined` である。戻り値が `undefined` でない場合、その `target` プロパティは次を満たす:
	 * - このエンティティ(`this`) またはその子孫である
	 * - `E#touchable` が真である
	 *
	 * @param point 対象の座標
	 * @param m `this` に適用する変換行列。省略された場合、単位行列
	 * @param force touchable指定を無視する場合真を指定する。省略された場合、偽
	 */
	findPointSourceByPoint(point: CommonOffset, m?: Matrix, force?: boolean): PointSource | undefined {
		if (this.state & EntityStateFlags.Hidden) return undefined;

		m = m ? m.multiplyNew(this.getMatrix()) : this.getMatrix().clone();
		const p = m.multiplyInverseForPoint(point);

		if (this._hasTouchableChildren || (force && this.children && this.children.length)) {
			const children = this.children!;
			if (this.shouldFindChildrenByPoint(p)) {
				for (let i = children.length - 1; i >= 0; --i) {
					const child = children[i];
					if (force || child._touchable || child._hasTouchableChildren) {
						const target = child.findPointSourceByPoint(point, m, force);
						if (target) return target;
					}
				}
			}
		}

		if (!(force || this._touchable)) return undefined;

		// 逆行列をポイントにかけた結果がEにヒットしているかを計算
		if (0 <= p.x && this.width > p.x && 0 <= p.y && this.height > p.y) {
			return {
				target: this,
				point: p
			};
		}

		return undefined;
	}

	/**
	 * このEが表示状態であるかどうかを返す。
	 */
	visible(): boolean {
		return (this.state & EntityStateFlags.Hidden) !== EntityStateFlags.Hidden;
	}

	/**
	 * このEを表示状態にする。
	 *
	 * `this.hide()` によって非表示状態にされたエンティティを表示状態に戻す。
	 * 生成直後のエンティティは表示状態であり、 `hide()` を呼び出さない限りこのメソッドを呼び出す必要はない。
	 */
	show(): void {
		if (!(this.state & EntityStateFlags.Hidden)) return;
		this.state &= ~EntityStateFlags.Hidden;
		if (this.parent) {
			this.parent.modified(true);
		}
	}

	/**
	 * このEを非表示状態にする。
	 *
	 * `this.show()` が呼ばれるまでの間、このエンティティは各 `Renderer` によって描画されない。
	 * また `Game#findPointSource()` で返されることもなくなる。
	 * `this#pointDown`, `pointMove`, `pointUp` なども通常の方法ではfireされなくなる。
	 */
	hide(): void {
		if (this.state & EntityStateFlags.Hidden) return;
		this.state |= EntityStateFlags.Hidden;
		if (this.parent) {
			this.parent.modified(true);
		}
	}

	/**
	 * このEの包含矩形を計算する。
	 */
	calculateBoundingRect(): CommonRect | undefined {
		return this._calculateBoundingRect(undefined);
	}

	/**
	 * このEの位置を基準とした相対座標をゲームの左上端を基準とした座標に変換する。
	 * @param offset Eの位置を基準とした相対座標
	 */
	localToGlobal(offset: CommonOffset): CommonOffset {
		let point = offset;
		for (let entity: E | Scene | undefined = this; entity instanceof E; entity = entity.parent) {
			point = entity.getMatrix().multiplyPoint(point);
		}
		return point;
	}

	/**
	 * ゲームの左上端を基準とした座標をこのEの位置を基準とした相対座標に変換する。
	 * @param offset ゲームの左上端を基準とした座標
	 */
	globalToLocal(offset: CommonOffset): CommonOffset {
		const matrix: Matrix = new PlainMatrix();
		for (let entity: E | Scene | undefined = this; entity instanceof E; entity = entity.parent) {
			matrix.multiplyLeft(entity.getMatrix());
		}
		return matrix.multiplyInverseForPoint(offset);
	}

	/**
	 * このエンティティの座標系を、指定された祖先エンティティ (またはシーン) の座標系に変換する行列を求める。
	 *
	 * 指定されたエンティティが、このエンティティの祖先でない時、その値は無視される。
	 * 指定されたシーンが、このエンティティの属するシーン出ない時、その値は無視される。
	 *
	 * @param target 座標系の変換先エンティティまたはシーン。省略した場合、このエンティティの属するシーン(グローバル座標系への変換行列になる)
	 * @private
	 */
	_calculateMatrixTo(target?: E | Scene): Matrix {
		const matrix: Matrix = new PlainMatrix();
		for (let entity: E | Scene | undefined = this; entity instanceof E && entity !== target; entity = entity.parent) {
			matrix.multiplyLeft(entity.getMatrix());
		}
		return matrix;
	}

	/**
	 * このエンティティと与えられたエンティティの共通祖先のうち、もっとも子孫側にあるものを探す。
	 * 共通祖先がない場合、 `undefined` を返す。
	 *
	 * @param target このエンティティとの共通祖先を探すエンティティ
	 * @private
	 */
	_findLowestCommonAncestorWith(target: E): E | Scene | undefined {
		const seen: { [id: number]: boolean } = {};
		for (let p: E | Scene | undefined = this; p instanceof E; p = p.parent) {
			seen[p.id] = true;
		}
		let ret: E | Scene | undefined = target;
		for (; ret instanceof E; ret = ret.parent) {
			if (seen.hasOwnProperty(ret.id)) break;
		}
		return ret;
	}

	/**
	 * @private
	 */
	_calculateBoundingRect(m?: Matrix): CommonRect | undefined {
		let matrix = this.getMatrix();
		if (m) {
			matrix = m.multiplyNew(matrix);
		}

		if (!this.visible()) {
			return undefined;
		}

		const thisBoundingRect: CommonRect = {
			left: 0,
			right: this.width,
			top: 0,
			bottom: this.height
		};

		const targetCoordinates: CommonOffset[] = [
			{ x: thisBoundingRect.left, y: thisBoundingRect.top },
			{ x: thisBoundingRect.left, y: thisBoundingRect.bottom },
			{ x: thisBoundingRect.right, y: thisBoundingRect.top },
			{ x: thisBoundingRect.right, y: thisBoundingRect.bottom }
		];

		let convertedPoint = matrix.multiplyPoint(targetCoordinates[0]);
		const result: CommonRect = {
			left: convertedPoint.x,
			right: convertedPoint.x,
			top: convertedPoint.y,
			bottom: convertedPoint.y
		};
		for (let i = 1; i < targetCoordinates.length; ++i) {
			convertedPoint = matrix.multiplyPoint(targetCoordinates[i]);
			if (result.left > convertedPoint.x) result.left = convertedPoint.x;
			if (result.right < convertedPoint.x) result.right = convertedPoint.x;
			if (result.top > convertedPoint.y) result.top = convertedPoint.y;
			if (result.bottom < convertedPoint.y) result.bottom = convertedPoint.y;
		}

		if (this.children !== undefined) {
			for (let i = 0; i < this.children.length; ++i) {
				const nowResult = this.children[i]._calculateBoundingRect(matrix);
				if (nowResult) {
					if (result.left > nowResult.left) result.left = nowResult.left;
					if (result.right < nowResult.right) result.right = nowResult.right;
					if (result.top > nowResult.top) result.top = nowResult.top;
					if (result.bottom < nowResult.bottom) result.bottom = nowResult.bottom;
				}
			}
		}
		return result;
	}

	/**
	 * @private
	 */
	_enableTouchPropagation(): void {
		let p = this.parent;
		while (p instanceof E && !p._hasTouchableChildren) {
			p._hasTouchableChildren = true;
			p = p.parent;
		}
	}

	/**
	 * @private
	 */
	_disableTouchPropagation(): void {
		let p = this.parent;
		while (p instanceof E && p._hasTouchableChildren) {
			if (this._findTouchableChildren(p)) break;
			p._hasTouchableChildren = false;
			p = p.parent;
		}
	}

	/**
	 * @private
	 */
	_isTargetOperation(e: PointEvent): boolean {
		if (this.state & EntityStateFlags.Hidden) return false;
		if (e instanceof PointEventBase) return this._touchable && e.target === this;

		return false;
	}

	private _findTouchableChildren(e: E): E | undefined {
		if (e.children) {
			for (let i = 0; i < e.children.length; ++i) {
				if (e.children[i].touchable) return e.children[i];
				const tmp = this._findTouchableChildren(e.children[i]);
				if (tmp) return tmp;
			}
		}
		return undefined;
	}
}

import type { Renderer } from "@akashic/pdi-types";
import { ExceptionFactory } from "../ExceptionFactory";
import type { EParameterObject } from "./E";
import { E } from "./E";

/**
 * `FilledRect` のコンストラクタに渡すことができるパラメータ。
 * 各メンバの詳細は `FilledRect` の同名メンバの説明を参照すること。
 */
export interface FilledRectParameterObject extends EParameterObject {
	/**
	 * 矩形を塗りつぶす色。
	 */
	cssColor: string;

	/**
	 * このオブジェクトの横幅。
	 */
	width: number;

	/**
	 * このオブジェクトの縦幅。
	 */
	height: number;
}

/**
 * 塗りつぶされた矩形を表すエンティティ。
 */
export class FilledRect extends E {
	/**
	 * 矩形を塗りつぶす色。
	 * この値を変更した場合、 `this.modified()` を呼び出す必要がある。
	 */
	cssColor: string;

	/**
	 * 各種パラメータを指定して `FilledRect` のインスタンスを生成する。
	 * @param param このエンティティに対するパラメータ
	 */
	constructor(param: FilledRectParameterObject) {
		super(param);
		if (typeof param.cssColor !== "string")
			throw ExceptionFactory.createTypeMismatchError("ColorBox#constructor(cssColor)", "string", param.cssColor);
		this.cssColor = param.cssColor;
	}

	/**
	 * このエンティティ自身の描画を行う。
	 * このメソッドはエンジンから暗黙に呼び出され、ゲーム開発者が呼び出す必要はない。
	 */
	override renderSelf(renderer: Renderer): boolean {
		renderer.fillRect(0, 0, this.width, this.height, this.cssColor);
		return true;
	}
}

import type { ImageAsset, Surface } from "@akashic/pdi-types";
import { Trigger } from "@akashic/trigger";
import type { Timer } from "../Timer";
import type { SpriteParameterObject } from "./Sprite";
import { Sprite } from "./Sprite";

/**
 * `FrameSprite` のコンストラクタに渡すことができるパラメータ。
 * 各メンバの詳細は `FrameSprite` の同名メンバの説明を参照すること。
 */
export interface FrameSpriteParameterObject extends SpriteParameterObject {
	/**
	 * 画像として使う `Surface` または `ImageAsset` 。
	 */
	src: Surface | ImageAsset;

	/**
	 * このエンティティの幅
	 */
	width: number;

	/**
	 * このエンティティの高さ
	 */
	height: number;

	/**
	 * 最初に表示される画像片のインデックス。
	 * `start()` 呼び出しによりタイマーで自動的に書き換えられていくが、ゲーム開発者が明示的に値を設定してもよい。
	 * @default 0
	 */
	frameNumber?: number;

	/**
	 * アニメーションの内容。
	 *
	 * アニメーションの各フレームでの表示内容を指定するインデックスの配列を指定する。
	 * インデックスは、コンストラクタに渡された画像を幅 `srcWidth`, 高さ `srcHeight` 単位の小さな画像(画像片)の集まりであるとみなして、
	 * 各画像片を特定する値である。左上の画像片を 0, その右隣の画像片を 1 として左上から右下に順に割り振られる。
	 * @default [0]
	 */
	frames?: number[];

	/**
	 * アニメーションの更新頻度(ミリ秒)。
	 * 省略された場合、 `start()` 時にFPSの逆数に設定される。(つまり、1フレームごとに画像が切り替わっていく)
	 * @default (1000 / game.fps)
	 */
	interval?: number;

	/**
	 * アニメーションをループ再生させるか否か。
	 * @default true
	 */
	loop?: boolean;
}

/**
 * フレームとタイマーによるアニメーション機構を持つ `Sprite` 。
 *
 * このクラスは、コンストラクタで渡された画像を、
 * 幅 `srcWidth`, 高さ `srcHeight` 単位で区切られた小さな画像(以下、画像片)の集まりであると解釈する。
 * 各画像片は、左上から順に 0 から始まるインデックスで参照される。
 *
 * ゲーム開発者は、このインデックスからなる配列を `FrameSprite#frames` に設定する。
 * `FrameSprite` は、 `frames` に指定されたインデックス(が表す画像片)を順番に描画することでアニメーションを実現する。
 * アニメーションは `interval` ミリ秒ごとに進み、 `frames` の内容をループする。
 *
 * このクラスにおける `srcWidth`, `srcHeight` の扱いは、親クラスである `Sprite` とは異なっていることに注意。
 */
export class FrameSprite extends Sprite {
	/**
	 * 現在表示されている画像片のインデックス。
	 *
	 * `start()` 呼び出しによりタイマーで自動的に書き換えられていくが、ゲーム開発者が明示的に値を設定してもよい。
	 * 初期値は `0` である。
	 * この値を変更した場合、 `this.modified()` を呼び出す必要がある。
	 */
	frameNumber: number;

	/**
	 * アニメーションの内容。
	 *
	 * アニメーションの各フレームでの表示内容を指定するインデックスの配列を指定する。初期値は `[0]` である。
	 * インデックスは、コンストラクタに渡された画像を幅 `srcWidth`, 高さ `srcHeight` 単位の小さな画像(画像片)の集まりであるとみなして、
	 * 各画像片を特定する値である。左上の画像片を 0, その右隣の画像片を 1 として左上から右下に順に割り振られる。
	 *
	 * この値を変更した場合、 `this.modified()` を呼び出す必要がある。
	 */
	frames: number[];

	/**
	 * アニメーションの更新頻度(ミリ秒)。
	 * 指定しなかった場合、 `start()` 時にFPSの逆数に設定される。(つまり、1フレームごとに画像が切り替わっていく)
	 * この値を変更した場合、反映には `this.start()` を呼び出す必要がある。
	 */
	interval: number | undefined;

	/**
	 * アニメーションをループ再生させるか否か。
	 * 初期値は `true` である。
	 */
	loop: boolean;

	/**
	 * アニメーション終了時にfireされるTrigger。
	 * 本Triggerは loop: false の場合にのみfireされる。
	 */
	onFinish: Trigger<void>;

	/**
	 * アニメーション終了時にfireされるTrigger。
	 * 本Triggerは loop: false の場合にのみfireされる。
	 * @deprecated 非推奨である。将来的に削除される。代わりに `onFinish` を利用すること。
	 */
	finished: Trigger<void>;

	/**
	 * @private
	 */
	_timer: Timer | undefined;

	/**
	 * @private
	 */
	_lastUsedIndex: number;

	/**
	 * `Sprite` から `FrameSprite` を作成する。
	 * @param sprite 画像として使う`Sprite`
	 * @param width 作成されるエンティティの高さ。省略された場合、 `sprite.width`
	 * @param height 作成されるエンティティの高さ。省略された場合、 `sprite.height`
	 */
	static createBySprite(sprite: Sprite, width?: number, height?: number): FrameSprite {
		const frameSprite = new FrameSprite({
			scene: sprite.scene,
			src: sprite.src,
			width: width === undefined ? sprite.width : width,
			height: height === undefined ? sprite.height : height
		});
		frameSprite.srcHeight = height === undefined ? sprite.srcHeight : height;
		frameSprite.srcWidth = width === undefined ? sprite.srcWidth : width;
		return frameSprite;
	}

	/**
	 * 各種パラメータを指定して `FrameSprite` のインスタンスを生成する。
	 * @param param `FrameSprite` に設定するパラメータ
	 */
	constructor(param: FrameSpriteParameterObject) {
		super(param);
		this._lastUsedIndex = 0;
		this.frameNumber = param.frameNumber || 0;
		this.frames = param.frames != null ? param.frames : [0];
		this.interval = param.interval;
		this._timer = undefined;
		this.loop = param.loop != null ? param.loop : true;
		this.onFinish = new Trigger<void>();
		this.finished = this.onFinish;
		this._modifiedSelf();
	}

	/**
	 * アニメーションを開始する。
	 */
	start(): void {
		if (this.interval === undefined) this.interval = 1000 / this.game().fps;

		if (this._timer) this._free();

		this._timer = this.scene.createTimer(this.interval);
		this._timer.onElapse.add(this._handleElapse, this);
	}

	/**
	 * このエンティティを破棄する。
	 * デフォルトでは利用している `Surface` の破棄は行わない点に注意。
	 * @param destroySurface trueを指定した場合、このエンティティが抱える `Surface` も合わせて破棄する
	 */
	override destroy(destroySurface?: boolean): void {
		this.stop();
		super.destroy(destroySurface);
	}

	/**
	 * アニメーションを停止する。
	 */
	stop(): void {
		if (this._timer) this._free();
	}

	/**
	 * このエンティティに対する変更をエンジンに通知する。詳細は `E#modified()` のドキュメントを参照。
	 */
	override modified(isBubbling?: boolean): void {
		this._modifiedSelf(isBubbling);
		super.modified(isBubbling);
	}

	/**
	 * @private
	 */
	_handleElapse(): void {
		if (this.frameNumber === this.frames.length - 1) {
			if (this.loop) {
				this.frameNumber = 0;
			} else {
				this.stop();
				this.onFinish.fire();
			}
		} else {
			this.frameNumber++;
		}

		this.modified();
	}

	/**
	 * @private
	 */
	_free(): void {
		if (!this._timer) return;

		this._timer.onElapse.remove(this._handleElapse, this);
		if (this._timer.canDelete()) this.scene.deleteTimer(this._timer);

		this._timer = undefined;
	}

	/**
	 * @private
	 */
	_changeFrame(): void {
		const frame = this.frames[this.frameNumber];
		const sep = Math.floor(this._surface.width / this.srcWidth);
		this.srcX = (frame % sep) * this.srcWidth;
		this.srcY = Math.floor(frame / sep) * this.srcHeight;
		this._lastUsedIndex = frame;
	}

	private _modifiedSelf(_isBubbling?: boolean): void {
		if (this._lastUsedIndex !== this.frames[this.frameNumber]) this._changeFrame();
	}
}

import type { Glyph, Renderer } from "@akashic/pdi-types";
import type { Font } from "../Font";
import { TextAlign } from "../TextAlign";
import type { TextAlignString } from "../TextAlignString";
import { Util } from "../Util";
import type { CacheableEParameterObject } from "./CacheableE";
import { CacheableE } from "./CacheableE";

/**
 * `Label` のコンストラクタに渡すことができるパラメータ。
 * 各メンバの詳細は `Label` の同名メンバの説明を参照すること。
 */
export interface LabelParameterObject extends CacheableEParameterObject {
	/**
	 * 描画する文字列。
	 */
	text: string;

	/**
	 * 描画に利用されるフォント。
	 */
	font: Font;

	/**
	 * フォントサイズ。
	 * 0 以上の数値でなければならない。そうでない場合、動作は不定である。
	 *
	 * これは `LabelParameterObject#font` で
	 * 与えられたフォントを `fontSize` フォントサイズ相当で描画するよう指示する値である。
	 * 歴史的経緯によりフォントサイズと説明されているが、実際には拡大縮小率を求めるため
	 * に用いられている。
	 * @default LabelParameterObject#font.size
	 */
	fontSize?: number;

	/**
	 * 文字列の描画位置。
	 * `"left"` (または非推奨の旧称 `g.TextAlign.Left`) 以外にする場合、
	 * `widthAutoAdjust` を `false` にすべきである。(`widthAutoAdjust` の項を参照)
	 * @default TextAlign.Left
	 */
	textAlign?: TextAlign | TextAlignString;

	/**
	 * このラベルの最大幅。
	 * @default undefined
	 */
	maxWidth?: number;

	/**
	 * `width` プロパティを `this.text` の描画に必要な幅で自動的に更新するかを表す。
	 * `textAlign` を `"left"` (または非推奨の旧称 `g.TextAlign.Left`) 以外にする場合、この値は `false` にすべきである。
	 * (`textAlign` は `width` を元に描画位置を調整するため、 `true` の場合左寄せで右寄せでも描画結果が変わらなくなる)
	 * @default true
	 */
	widthAutoAdjust?: boolean;

	/**
	 * 文字列の描画色をCSS Color形式で指定する。
	 * 元の描画色に重ねて表示されるため、アルファ値を指定した場合は元の描画色が透けて表示される。
	 * 省略された場合、この場合描画色の変更を行わない。
	 * @default undefined
	 */
	textColor?: string;
}

/**
 * 単一行のテキストを描画するエンティティ。
 * 本クラスの利用には `BitmapFont` または `DynamicFont` が必要となる。
 */
export class Label extends CacheableE {
	/**
	 * 描画する文字列。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 */
	text: string;

	/**
	 * 描画に利用されるフォント。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 */
	font: Font;

	/**
	 * 文字列の描画位置。
	 * `"left"` (または非推奨の旧称 `TextAlign.Left`) 以外にする場合、
	 * `widthAutoAdjust` を `false` にすべきである。(`widthAutoAdjust` の項を参照)
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 *
	 * @default `TextAlign.Left`
	 */
	textAlign: TextAlign | TextAlignString;

	/**
	 * キャッシュされたグリフ情報。
	 * 通常、ゲーム開発者がこのプロパティを参照する必要はない。
	 */
	glyphs: Glyph[];

	/**
	 * フォントサイズ。
	 * 0 以上の数値でなければならない。そうでない場合、動作は不定である。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 *
	 * @default Label#font.size
	 */
	fontSize: number;

	/**
	 * このラベルの最大幅。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 */
	maxWidth: number | undefined;

	/**
	 * `width` プロパティを `this.text` の描画に必要な幅で自動的に更新するかを表す。
	 * 初期値は `true` である。
	 * `textAlign` を `"left"` (または非推奨の旧称 `g.TextAlign.Left`) 以外にする場合、この値は `false` にすべきである。
	 * (`textAlign` は `width` を元に描画位置を調整するため、 `true` の場合左寄せで右寄せでも描画結果が変わらなくなる)
	 *
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 */
	widthAutoAdjust: boolean;

	/**
	 * 文字列の描画色をCSS Color形式で指定する。
	 * 元の描画色に重ねて表示されるため、アルファ値を指定した場合は元の描画色が透けて表示される。
	 * 初期値は `undefined` となり、 描画色の変更を行わない。
	 */
	textColor: string | undefined;

	/**
	 * @private
	 */
	_realTextAlign: TextAlignString;

	/**
	 * @private
	 */
	_textWidth: number;

	/**
	 * @private
	 * 最初の文字が描画の基準点から左にはみだす量。
	 */
	_overhangLeft: number;

	/**
	 * @private
	 * 最後の文字が glyph.advanceWidth から右にはみだす量。
	 */
	_overhangRight: number;

	/**
	 * 各種パラメータを指定して `Label` のインスタンスを生成する。
	 * @param param このエンティティに指定するパラメータ
	 */
	constructor(param: LabelParameterObject) {
		super(param);
		this.text = param.text;
		this.font = param.font;
		this.textAlign = param.textAlign != null ? param.textAlign : TextAlign.Left;
		this.glyphs = new Array(param.text.length);
		this.fontSize = param.fontSize != null ? param.fontSize : param.font.size;
		this.maxWidth = param.maxWidth;
		this.widthAutoAdjust = param.widthAutoAdjust != null ? param.widthAutoAdjust : true;
		this.textColor = param.textColor;
		this._realTextAlign = "left";
		this._textWidth = 0;
		this._overhangLeft = 0;
		this._overhangRight = 0;
		this._invalidateSelf();
	}

	/**
	 * `width` と `textAlign` を設定し、 `widthAutoAdjust` を `false` に設定する。
	 *
	 * このメソッドは `this.textAlign` を設定するためのユーティリティである。
	 * `textAlign` を `"left"` (または非推奨の旧称 `TextAlign.Left`) 以外に設定する場合には、
	 * 通常 `width` や `widthAutoAdjust` も設定する必要があるため、それらをまとめて行う。
	 * このメソッドの呼び出し後、 `this.invalidate()` を呼び出す必要がある。
	 * @param width 幅
	 * @param textAlign テキストの描画位置
	 */
	aligning(width: number, textAlign: TextAlign | TextAlignString): void {
		this.width = width;
		this.widthAutoAdjust = false;
		this.textAlign = textAlign;
	}

	/**
	 * このエンティティの描画キャッシュ無効化をエンジンに通知する。
	 * このメソッドを呼び出し後、描画キャッシュの再構築が行われ、各 `Renderer` に描画内容の変更が反映される。
	 */
	override invalidate(): void {
		this._invalidateSelf();
		super.invalidate();
	}

	/**
	 * Label自身の描画を行う。
	 */
	override renderSelfFromCache(renderer: Renderer): void {
		// glyphのはみ出し量に応じて、描画先のX座標を調整する。
		let destOffsetX;
		switch (this._realTextAlign) {
			case "center":
				destOffsetX = this.widthAutoAdjust ? this._overhangLeft : 0;
				break;
			case "right":
				destOffsetX = this.widthAutoAdjust ? this._overhangLeft : this._overhangRight;
				break;
			default:
				destOffsetX = this._overhangLeft;
				break;
		}

		renderer.drawImage(this._cache!, 0, 0, this._cacheSize.width, this._cacheSize.height, destOffsetX, 0);
	}

	renderCache(renderer: Renderer): void {
		if (!this.fontSize || this.height <= 0 || this._textWidth <= 0) {
			return;
		}

		const scale = this.maxWidth && this.maxWidth > 0 && this.maxWidth < this._textWidth ? this.maxWidth / this._textWidth : 1;
		let offsetX = 0;
		switch (this._realTextAlign) {
			case "center":
				offsetX = this.width / 2 - ((this._textWidth + this._overhangLeft) / 2) * scale;
				break;
			case "right":
				offsetX = this.width - (this._textWidth + this._overhangLeft) * scale;
				break;
			default:
				offsetX -= this._overhangLeft * scale;
				break;
		}

		renderer.translate(Math.round(offsetX), 0);

		if (scale !== 1) {
			renderer.transform([scale, 0, 0, 1, 0, 0]);
		}

		renderer.save();
		const glyphScale = this.fontSize / this.font.size;
		let cumulativeOffset = 0;
		for (let i = 0; i < this.glyphs.length; ++i) {
			let glyph: Glyph | null = this.glyphs[i];
			const glyphWidth = glyph.advanceWidth * glyphScale;

			const code = glyph.code;
			if (!glyph.isSurfaceValid) {
				glyph = this.font.glyphForCharacter(code);
				if (!glyph) {
					this._outputOfWarnLogWithNoGlyph(code, "renderCache()");
					continue;
				}
			}

			if (glyph.surface) {
				// 非空白文字
				renderer.save();
				renderer.translate(Math.round(cumulativeOffset), 0);
				renderer.transform([glyphScale, 0, 0, glyphScale, 0, 0]);
				renderer.drawImage(glyph.surface, glyph.x, glyph.y, glyph.width, glyph.height, glyph.offsetX, glyph.offsetY);
				renderer.restore();
			}
			cumulativeOffset += glyphWidth;
		}
		renderer.restore();

		renderer.save();
		if (this.textColor) {
			renderer.setCompositeOperation("source-atop");
			renderer.fillRect(0, 0, this._textWidth, this.height, this.textColor);
		}
		renderer.restore();
	}

	/**
	 * このエンティティを破棄する。
	 * 利用している `BitmapFont` の破棄は行わないため、 `BitmapFont` の破棄はコンテンツ製作者が明示的に行う必要がある。
	 */
	override destroy(): void {
		super.destroy();
	}

	private _invalidateSelf(): void {
		this.glyphs.length = 0;
		this._textWidth = 0;

		const align = this.textAlign;
		this._realTextAlign = typeof align === "string" ? align : Util.enumToSnakeCase<TextAlign, TextAlignString>(TextAlign, align);

		if (!this.fontSize) {
			this.height = 0;
			return;
		}

		let effectiveTextLastIndex = this.text.length - 1;
		// 右のはみだし量を求めるため、text内での有効な最後の glyph のindexを解決する。
		for (let i = this.text.length - 1; i >= 0; --i) {
			const code = Util.charCodeAt(this.text, i);
			if (!code) {
				continue;
			}
			const glyph = this.font.glyphForCharacter(code);
			if (glyph && glyph.width !== 0 && glyph.advanceWidth !== 0) {
				effectiveTextLastIndex = i;
				break;
			}
		}

		let maxHeight = 0;
		const glyphScale = this.font.size > 0 ? this.fontSize / this.font.size : 0;
		for (let i = 0; i <= effectiveTextLastIndex; ++i) {
			const code = Util.charCodeAt(this.text, i);
			if (!code) {
				continue;
			}

			const glyph = this.font.glyphForCharacter(code);
			if (!glyph) {
				this._outputOfWarnLogWithNoGlyph(code, "_invalidateSelf()");
				continue;
			}

			if (glyph.width < 0 || glyph.height < 0) {
				continue;
			}
			if (glyph.x < 0 || glyph.y < 0) {
				continue;
			}
			this.glyphs.push(glyph);

			// Font に StrokeWidth が設定されている場合、文字の描画内容は、描画の基準点よりも左にはみ出る場合や、glyph.advanceWidth より右にはみ出る場合がある。
			// キャッシュサーフェスの幅は、最初の文字と最後の文字のはみ出し部分を考慮して求める必要がある。
			let overhang = 0;
			if (i === 0) {
				this._overhangLeft = Math.min(glyph.offsetX, 0);
				overhang = -this._overhangLeft;
			}

			if (i === effectiveTextLastIndex) {
				this._overhangRight = Math.max(glyph.width + glyph.offsetX - glyph.advanceWidth, 0);
				overhang += this._overhangRight;
			}

			this._textWidth += (glyph.advanceWidth + overhang) * glyphScale;

			const height = glyph.offsetY + glyph.height;
			if (maxHeight < height) {
				maxHeight = height;
			}
		}
		if (this.widthAutoAdjust) {
			this.width = this._textWidth;
		}

		this.height = maxHeight * glyphScale;
	}

	private _outputOfWarnLogWithNoGlyph(code: number, functionName: string): void {
		const str = code & 0xffff0000 ? String.fromCharCode((code & 0xffff0000) >>> 16, code & 0xffff) : String.fromCharCode(code);
		console.warn(
			"Label#" +
				functionName +
				": failed to get a glyph for '" +
				str +
				"' " +
				"(BitmapFont might not have the glyph or DynamicFont might create a glyph larger than its atlas)."
		);
	}
}

import type { CommonArea, CommonOffset, CommonRect, ImageAsset, Renderer, Surface } from "@akashic/pdi-types";
import type { Camera } from "../Camera";
import { EntityStateFlags } from "../EntityStateFlags";
import type { Matrix } from "../Matrix";
import type { SurfaceEffector } from "../SurfaceEffector";
import { SurfaceUtil } from "../SurfaceUtil";
import type { CacheableEParameterObject } from "./CacheableE";
import { CacheableE } from "./CacheableE";

/**
 * `Pane` のコンストラクタに渡すことができるパラメータ。
 * 各メンバの詳細は `Pane` の同名メンバの説明を参照すること。
 */
export interface PaneParameterObject extends CacheableEParameterObject {
	/**
	 * このオブジェクトの横幅。実際の表示領域としてはscaleX, scaleY, angleの値も考慮する必要がある。
	 */
	width: number;

	/**
	 * このオブジェクトの縦幅。実際の表示領域としてはscaleX, scaleY, angleの値も考慮する必要がある。
	 */
	height: number;

	/**
	 * 背景画像として使う `ImageAsset` または `Surface` 。
	 * 省略された場合、背景には何も描かれない。
	 * @default undefined
	 */
	backgroundImage?: ImageAsset | Surface;

	/**
	 * 子孫エンティティの描画位置・クリッピングサイズを決めるパディング。
	 * @default 0
	 */
	padding?: CommonRect | number;

	/**
	 * 背景画像の描画方法を指定する `SurfaceEffector` 。
	 * `undefined` の場合、描画方法をカスタマイズしない。
	 * @deprecated 非推奨である。将来的に削除される予定である。
	 * @default undefined
	 */
	backgroundEffector?: SurfaceEffector;
}
/**
 * 枠を表すエンティティ。
 * クリッピングやパディング、バックグラウンドイメージの演出等の機能を持つため、
 * メニューやメッセージ、ステータスのウィンドウ等に利用されることが期待される。
 * このエンティティの子要素は、このエンティティの持つ `Surface` に描画される。
 */
export class Pane extends CacheableE {
	/**
	 * 背景画像の `ImageAsset` または `Surface` 。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 */
	backgroundImage: ImageAsset | Surface | undefined;

	/**
	 * 背景画像の拡大・縮小に用いられる `SurfaceEffector` 。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 * @deprecated 非推奨である。将来的に削除される予定である。
	 */
	backgroundEffector: SurfaceEffector | undefined;

	/**
	 * @private
	 */
	_backgroundImageSurface: Surface | undefined;

	/**
	 * @private
	 */
	_beforeBackgroundImage: ImageAsset | Surface | undefined;

	/**
	 * @private
	 */
	_padding: CommonRect | number;

	/**
	 * @private
	 */
	_paddingChanged: boolean;

	/**
	 * @private
	 */
	// @ts-ignore
	_normalizedPadding: CommonRect;

	/**
	 * @private
	 */
	// Effect済み背景画像の描画サーフェス
	_bgSurface: Surface | undefined;

	/**
	 * @private
	 */
	_oldWidth: number;

	/**
	 * @private
	 */
	_oldHeight: number;

	/**
	 * @private
	 */
	// @ts-ignore
	_childrenArea: CommonArea;

	/**
	 * @private
	 */
	// @ts-ignore
	_childrenSurface: Surface;

	/**
	 * @private
	 */
	// @ts-ignore
	_childrenRenderer: Renderer;

	/**
	 * 各種パラメータを指定して `Pane` のインスタンスを生成する。
	 * @param param このエンティティに指定するパラメータ
	 */
	constructor(param: PaneParameterObject) {
		super(param);
		this._oldWidth = param.width;
		this._oldHeight = param.height;
		this.backgroundImage = param.backgroundImage;
		this._beforeBackgroundImage = param.backgroundImage;
		this._backgroundImageSurface = SurfaceUtil.asSurface(param.backgroundImage);
		this.backgroundEffector = param.backgroundEffector;
		this._shouldRenderChildren = false;
		this._padding = param.padding || 0;
		this._initialize();
		this._paddingChanged = false;
	}

	/**
	 * パディング。
	 * このエンティティの子孫は、パディングに指定された分だけ右・下にずれた場所に描画され、またパディングの矩形サイズでクリッピングされる。
	 */
	// NOTE: paddingの変更は頻繁に行われるものでは無いと思われるので、フラグを立てるためにアクセサを使う
	set padding(padding: CommonRect | number) {
		this._padding = padding;
		this._paddingChanged = true;
	}

	get padding(): CommonRect | number {
		return this._padding;
	}

	/**
	 * このエンティティに対する変更をエンジンに通知する。
	 * このメソッドの呼び出し後、 `this` に対する変更が各 `Renderer` の描画に反映される。
	 * このメソッドは描画キャッシュの無効化を保証しない。描画キャッシュの無効化も必要な場合、 `invalidate()`を呼び出さなければならない。
	 * 詳細は `E#modified()` のドキュメントを参照。
	 */
	override modified(isBubbling?: boolean): void {
		if (isBubbling) this.state &= ~EntityStateFlags.Cached;
		super.modified();
	}

	override shouldFindChildrenByPoint(point: CommonOffset): boolean {
		const p = this._normalizedPadding;
		if (p.left < point.x && this.width - p.right > point.x && p.top < point.y && this.height - p.bottom > point.y) {
			return true;
		}
		return false;
	}

	renderCache(renderer: Renderer, camera?: Camera): void {
		if (this.width <= 0 || this.height <= 0) {
			return;
		}
		this._renderBackground();
		this._renderChildren(camera);

		if (this._bgSurface) {
			renderer.drawImage(this._bgSurface, 0, 0, this.width, this.height, 0, 0);
		} else if (this._backgroundImageSurface) {
			renderer.drawImage(this._backgroundImageSurface, 0, 0, this.width, this.height, 0, 0);
		}
		if (this._childrenArea.width <= 0 || this._childrenArea.height <= 0) {
			return;
		}
		renderer.save();
		if (this._childrenArea.x !== 0 || this._childrenArea.y !== 0) {
			renderer.translate(this._childrenArea.x, this._childrenArea.y);
		}
		renderer.drawImage(this._childrenSurface, 0, 0, this._childrenArea.width, this._childrenArea.height, 0, 0);
		renderer.restore();
	}

	/**
	 * このエンティティを破棄する。また、バックバッファで利用している `Surface` も合わせて破棄される。
	 * ただし、 `backgroundImage` に利用している `Surface` の破棄は行わない。
	 * @param destroySurface trueを指定した場合、 `backgroundImage` に利用している `Surface` も合わせて破棄する。
	 */
	override destroy(destroySurface?: boolean): void {
		if (destroySurface && this._backgroundImageSurface && !this._backgroundImageSurface.destroyed()) {
			this._backgroundImageSurface.destroy();
		}
		if (this._bgSurface && !this._bgSurface.destroyed()) {
			this._bgSurface.destroy();
		}
		if (this._childrenSurface && !this._childrenSurface.destroyed()) {
			this._childrenSurface.destroy();
		}
		this.backgroundImage = undefined;
		this._backgroundImageSurface = undefined;
		this._beforeBackgroundImage = undefined;
		this._bgSurface = undefined;
		this._childrenSurface = undefined!;
		super.destroy();
	}

	/**
	 * @private
	 */
	_renderBackground(): void {
		if (this.backgroundImage !== this._beforeBackgroundImage) {
			this._backgroundImageSurface = SurfaceUtil.asSurface(this.backgroundImage);
			this._beforeBackgroundImage = this.backgroundImage;
		}
		if (this._backgroundImageSurface && this.backgroundEffector) {
			const bgSurface = this.backgroundEffector.render(this._backgroundImageSurface, this.width, this.height);
			if (this._bgSurface !== bgSurface) {
				if (this._bgSurface && !this._bgSurface.destroyed()) {
					this._bgSurface.destroy();
				}
				this._bgSurface = bgSurface;
			}
		} else {
			this._bgSurface = undefined;
		}
	}

	/**
	 * @private
	 */
	_renderChildren(camera?: Camera): void {
		const isNew = this._oldWidth !== this.width || this._oldHeight !== this.height || this._paddingChanged;
		if (isNew) {
			this._initialize();
			this._paddingChanged = false;
			this._oldWidth = this.width;
			this._oldHeight = this.height;
		}
		this._childrenRenderer.begin();
		if (!isNew) {
			this._childrenRenderer.clear();
		}

		if (this.children) {
			// Note: concatしていないのでunsafeだが、render中に配列の中身が変わる事はない前提とする
			const children = this.children;
			for (let i = 0; i < children.length; ++i) {
				children[i].render(this._childrenRenderer, camera);
			}
		}
		this._childrenRenderer.end();
	}

	/**
	 * @private
	 */
	_initialize(): void {
		const p = this._padding;
		let r: CommonRect;
		if (typeof p === "number") {
			r = { top: p, bottom: p, left: p, right: p };
		} else {
			r = p;
		}
		this._childrenArea = {
			x: r.left,
			y: r.top,
			width: this.width - r.left - r.right,
			height: this.height - r.top - r.bottom
		};
		const resourceFactory = this.scene.game.resourceFactory;
		if (this._childrenSurface && !this._childrenSurface.destroyed()) {
			this._childrenSurface.destroy();
		}
		this._childrenSurface = resourceFactory.createSurface(Math.ceil(this._childrenArea.width), Math.ceil(this._childrenArea.height));
		this._childrenRenderer = this._childrenSurface.renderer();
		this._normalizedPadding = r;
	}

	/**
	 * このPaneの包含矩形を計算する。
	 * Eを継承する他のクラスと異なり、Paneは子要素の位置を包括矩形に含まない。
	 * @private
	 */
	override _calculateBoundingRect(m?: Matrix): CommonRect | undefined {
		let matrix = this.getMatrix();
		if (m) {
			matrix = m.multiplyNew(matrix);
		}

		if (!this.visible()) {
			return undefined;
		}

		const thisBoundingRect: CommonRect = {
			left: 0,
			right: this.width,
			top: 0,
			bottom: this.height
		};

		const targetCoordinates: CommonOffset[] = [
			{ x: thisBoundingRect.left, y: thisBoundingRect.top },
			{ x: thisBoundingRect.left, y: thisBoundingRect.bottom },
			{ x: thisBoundingRect.right, y: thisBoundingRect.top },
			{ x: thisBoundingRect.right, y: thisBoundingRect.bottom }
		];

		let convertedPoint = matrix.multiplyPoint(targetCoordinates[0]);
		const result: CommonRect = {
			left: convertedPoint.x,
			right: convertedPoint.x,
			top: convertedPoint.y,
			bottom: convertedPoint.y
		};
		for (let i = 1; i < targetCoordinates.length; ++i) {
			convertedPoint = matrix.multiplyPoint(targetCoordinates[i]);
			if (result.left > convertedPoint.x) result.left = convertedPoint.x;
			if (result.right < convertedPoint.x) result.right = convertedPoint.x;
			if (result.top > convertedPoint.y) result.top = convertedPoint.y;
			if (result.bottom < convertedPoint.y) result.bottom = convertedPoint.y;
		}
		return result;
	}
}

import type { ImageAsset, Renderer, Surface } from "@akashic/pdi-types";
import type { Camera } from "../Camera";
import type { Matrix } from "../Matrix";
import { PlainMatrix } from "../Matrix";
import { SurfaceUtil } from "../SurfaceUtil";
import type { EParameterObject } from "./E";
import { E } from "./E";

/**
 * `Sprite` のコンストラクタに渡すことができるパラメータ。
 * 各メンバの詳細は `Sprite` の同名メンバの説明を参照すること。
 *
 * 値に `width` または `height` が含まれていない場合、
 * `Sprite` のコンストラクタはそれぞれ `src.width`、 `src.height` が指定されたかのように振る舞う。
 */
export interface SpriteParameterObject extends EParameterObject {
	/**
	 * 画像として使う `Surface` または `ImageAsset` 。
	 */
	src: Surface | ImageAsset;

	/**
	 * `surface` の描画対象部分の幅。
	 * 描画はこの値を `this.width` に拡大または縮小する形で行われる。
	 * 省略された場合、値に `width` があれば `width` 、なければ `src.width` 。
	 * @default width || src.width
	 */
	srcWidth?: number;

	/**
	 * `surface` の描画対象部分の高さ。
	 * 描画はこの値を `this.height` に拡大または縮小する形で行われる。
	 * 省略された場合、値に `height` があれば `height` 、なければ `src.height` 。
	 * @default height || src.height
	 */
	srcHeight?: number;

	/**
	 * `surface` の描画対象部分の左端。
	 * @default 0
	 */
	srcX?: number;

	/**
	 * `surface` の描画対象部分の上端。
	 * @default 0
	 */
	srcY?: number;
}

/**
 * 画像を描画するエンティティ。
 */
export class Sprite extends E {
	/**
	 * 描画する `Surface` または `ImageAsset` 。
	 * `srcX` ・ `srcY` ・ `srcWidth` ・ `srcHeight` の作る矩形がこの画像の範囲外を示す場合、描画結果は保証されない。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 */
	src: Surface | ImageAsset;

	/**
	 * `surface` の描画対象部分の幅。
	 * 描画はこの値を `this.width` に拡大または縮小する形で行われる。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 */
	srcWidth: number;

	/**
	 * `surface` の描画対象部分の高さ。
	 * 描画はこの値を `this.height` に拡大または縮小する形で行われる。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 */
	srcHeight: number;

	/**
	 * `surface` の描画対象部分の左端。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 */
	srcX: number;

	/**
	 * `surface` の描画対象部分の上端。
	 * この値を変更した場合、 `this.invalidate()` を呼び出す必要がある。
	 */
	srcY: number;

	/**
	 * @private
	 */
	_surface: Surface;

	/**
	 * @private
	 */
	_stretchMatrix: Matrix | undefined;

	/**
	 * @private
	 */
	_beforeSrc: Surface | ImageAsset | undefined;

	/**
	 * @private
	 */
	_beforeSurface: Surface | undefined;

	/**
	 * 各種パラメータを指定して `Sprite` のインスタンスを生成する。
	 * @param param `Sprite` に設定するパラメータ
	 */
	constructor(param: SpriteParameterObject) {
		super(param);
		this.src = param.src;
		if ("_drawable" in param.src) {
			this._surface = param.src;
		} else {
			// @ts-ignore
			this._surface = SurfaceUtil.asSurface(param.src);
		}
		if (param.width == null) this.width = this._surface.width;
		if (param.height == null) this.height = this._surface.height;
		this.srcWidth = param.srcWidth != null ? param.srcWidth : this.width;
		this.srcHeight = param.srcHeight != null ? param.srcHeight : this.height;
		this.srcX = param.srcX || 0;
		this.srcY = param.srcY || 0;
		this._stretchMatrix = undefined;
		this._beforeSrc = this.src;
		this._beforeSurface = this._surface;
		SurfaceUtil.setupAnimatingHandler(this, this._surface);
		this._invalidateSelf();
	}

	/**
	 * @private
	 */
	_handleUpdate(): void {
		this.modified();
	}

	/**
	 * @private
	 */
	_handleAnimationStart(): void {
		if (!this.onUpdate.contains(this._handleUpdate, this)) {
			this.onUpdate.add(this._handleUpdate, this);
		}
	}

	/**
	 * @private
	 */
	_handleAnimationStop(): void {
		if (!this.destroyed()) {
			this.onUpdate.remove(this._handleUpdate, this);
		}
	}

	/**
	 * このエンティティ自身の描画を行う。
	 * このメソッドはエンジンから暗黙に呼び出され、ゲーム開発者が呼び出す必要はない。
	 */
	override renderSelf(renderer: Renderer, _camera?: Camera): boolean {
		if (this.srcWidth <= 0 || this.srcHeight <= 0) {
			return true;
		}
		if (this._stretchMatrix) {
			renderer.save();
			renderer.transform(this._stretchMatrix._matrix);
		}

		renderer.drawImage(this._surface, this.srcX, this.srcY, this.srcWidth, this.srcHeight, 0, 0);

		if (this._stretchMatrix) renderer.restore();

		return true;
	}

	/**
	 * このエンティティの描画キャッシュ無効化をエンジンに通知する。
	 * このメソッドを呼び出し後、描画キャッシュの再構築が行われ、各 `Renderer` に描画内容の変更が反映される。
	 */
	invalidate(): void {
		this._invalidateSelf();
		this.modified();
	}

	/**
	 * このエンティティを破棄する。
	 * デフォルトでは利用している `Surface` の破棄は行わない点に注意。
	 * @param destroySurface trueを指定した場合、このエンティティが抱える `Surface` も合わせて破棄する
	 */
	override destroy(destroySurface?: boolean): void {
		if (this._surface && !this._surface.destroyed() && destroySurface) {
			this._surface.destroy();
		}
		this.src = undefined!;
		this._beforeSrc = undefined;
		this._surface = undefined!;
		super.destroy();
	}

	private _invalidateSelf(): void {
		if (this.width === this.srcWidth && this.height === this.srcHeight) {
			this._stretchMatrix = undefined;
		} else {
			this._stretchMatrix = new PlainMatrix();
			this._stretchMatrix.scale(this.width / this.srcWidth, this.height / this.srcHeight);
		}
		if (this.src !== this._beforeSrc) {
			this._beforeSrc = this.src;
			if ("_drawable" in this.src) {
				this._surface = this.src;
			} else {
				// @ts-ignore
				this._surface = SurfaceUtil.asSurface(this.src);
			}
		}
		if (this._surface !== this._beforeSurface) {
			SurfaceUtil.migrateAnimatingHandler(this, this._beforeSurface!, this._surface);
			this._beforeSurface = this._surface;
		}
	}
}

import type { Asset, AssetLoadHandler, ScriptAsset, ScriptAssetRuntimeValue } from "@akashic/pdi-types";
import { Trigger } from "@akashic/trigger";

export interface BundledScriptAssetParameterObject {
	id: string;
	type: string;
	path: string;
	execute: (execEnv: ScriptAssetRuntimeValue) => any;
}

export class BundledScriptAsset implements ScriptAsset {
	type: "script";
	script: string;
	exports?: string[] | undefined;
	id: string;
	path: string;
	originalPath: string;
	onDestroyed: Trigger<Asset>;
	execute: (execEnv: ScriptAssetRuntimeValue) => any;

	constructor(param: BundledScriptAssetParameterObject) {
		this.type = "script";
		this.id = param.id;
		this.script = "";
		this.path = param.path;
		this.originalPath = param.path;
		this.onDestroyed = new Trigger();
		this.execute = param.execute.bind(this);
	}

	inUse(): boolean {
		return true;
	}

	destroy(): void {
		if (!this.onDestroyed.destroyed()) {
			this.onDestroyed.destroy();
		}
		this.execute = undefined!;
	}

	destroyed(): boolean {
		return !this.execute;
	}

	_load(loader: AssetLoadHandler): void {
		loader._onAssetLoad(this);
	}

	_assetPathFilter(path: string): string {
		return path;
	}
}

import type { Asset, AssetLoadHandler, TextAsset } from "@akashic/pdi-types";
import { Trigger } from "@akashic/trigger";

export interface BundledTextAssetParameterObject {
	id: string;
	type: string;
	path: string;
	data: string;
}

export class BundledTextAsset implements TextAsset {
	type: "text";
	data: string;
	id: string;
	path: string;
	originalPath: string;
	onDestroyed: Trigger<Asset>;

	constructor(param: BundledTextAssetParameterObject) {
		this.type = "text";
		this.id = param.id;
		this.data = param.data;
		this.path = param.path;
		this.originalPath = param.path;
		this.onDestroyed = new Trigger();
	}

	inUse(): boolean {
		return true;
	}

	destroy(): void {
		if (!this.onDestroyed.destroyed()) {
			this.onDestroyed.destroy();
			this.onDestroyed = undefined!;
		}
		this.data = undefined!;
	}

	destroyed(): boolean {
		return !this.onDestroyed;
	}

	_load(loader: AssetLoadHandler): void {
		loader._onAssetLoad(this);
	}

	_assetPathFilter(path: string): string {
		return path;
	}
}

import type { Asset, AssetLoadHandler, BinaryAsset } from "@akashic/pdi-types";
import { Trigger } from "@akashic/trigger";

export class EmptyBinaryAsset implements BinaryAsset {
	id: string;
	path: string;
	originalPath: string;
	type: "binary" = "binary";
	data: ArrayBuffer;

	onDestroyed: Trigger<Asset> = new Trigger();

	constructor(id: string, path: string) {
		this.id = id;
		this.path = path;
		this.originalPath = path;
		this.data = new ArrayBuffer(0);
	}

	inUse(): boolean {
		return false;
	}

	destroy(): void {
		if (this.destroyed()) {
			return;
		}
		this.onDestroyed.destroy();
		this.onDestroyed = undefined!;
	}

	destroyed(): boolean {
		return !this.onDestroyed;
	}

