import { AudioPlayContext, Scene } from "..";
import type { GameConfiguration } from "..";
import { Game } from "./helpers";

describe("test AudioPlayContext", () => {
	beforeEach(() => {
		jest.resetAllMocks();
	});

	const gameConfiguration: GameConfiguration = {
		width: 320,
		height: 320,
		fps: 30,
		main: "mainScene",
		audio: {
			user2: {
				loop: true,
				hint: { streaming: true }
			}
		},
		assets: {
			zoo: {
				type: "audio",
				path: "/path/to/a/zoo",
				virtualPath: "path/to/a/zoo",
				systemId: "music",
				duration: 1984
			},
			baz: {
				type: "audio",
				path: "/path/to/a/baz",
				virtualPath: "path/to/a/baz",
				systemId: "music",
				duration: 42,
				loop: false,
				hint: { streaming: false }
			},
			qux: {
				type: "audio",
				path: "/path/to/a/qux",
				virtualPath: "path/to/a/qux",
				systemId: "sound",
				duration: 667408
			},
			quux: {
				type: "audio",
				path: "/path/to/a/quux",
				virtualPath: "path/to/a/quux",
				systemId: "sound",
				duration: 5972,
				loop: true,
				hint: { streaming: true }
			}
		}
	};

	const prepareLoadedScene = async (): Promise<{ game: Game; scene: Scene }> => {
		return new Promise(resolve => {
			const game = new Game(gameConfiguration);
			const scene = new Scene({ game, assetIds: ["zoo", "baz", "qux", "quux"] });
			game.pushScene(scene);
			game._flushPostTickTasks();
			scene._onReady.add(() => {
				resolve({ game, scene });
			});
			scene._load();
		});
	};

	it("initialize", async () => {
		const { game, scene } = await prepareLoadedScene();

		const resourceFactory = game.resourceFactory;
		const music = game.audio.music;
		const zoo = scene.asset.getAudioById("zoo");

		const ctx1 = new AudioPlayContext({
			id: "play-context-1",
			resourceFactory,
			system: music,
			systemId: music.id,
			asset: zoo
		});

		expect(ctx1.asset).toEqual(zoo);
		expect(ctx1._id).toBe("play-context-1");
		expect(ctx1._system).toEqual(music);
		expect(ctx1._volume).toBe(1.0);
		expect(ctx1._player).toBeDefined();

		const sound = game.audio.sound;
		sound._setMuted(true);
		sound.volume = 0.5;
		const qux = scene.asset.getAudioById("qux");

		const ctx2 = new AudioPlayContext({
			id: "play-context-2",
			resourceFactory,
			system: sound,
			systemId: sound.id,
			asset: qux,
			volume: 0.8
		});

		expect(ctx2.asset).toEqual(qux);
		expect(ctx2._id).toBe("play-context-2");
		expect(ctx2._system).toEqual(sound);
		expect(ctx2._volume).toBe(0.8); // AudioSystem とは独立
		expect(ctx2._player).toBeDefined();
	});

	it("should stop audio context when its asset has been destroyed", async () => {
		const { game, scene } = await prepareLoadedScene();

		const resourceFactory = game.resourceFactory;
		const music = game.audio.music;
		const zoo = scene.asset.getAudioById("zoo");

		const ctx = new AudioPlayContext({
			id: "play-context",
			resourceFactory,
			system: music,
			systemId: music.id,
			asset: zoo
		});

		const mockStop = jest.spyOn(ctx._player, "stop");
		zoo.onDestroyed.fire(zoo);

		expect(mockStop).toBeCalledTimes(1);
	});

	it("should suppress the audio player when AudioPlayContext#_suppress() is called", async () => {
		const { game, scene } = await prepareLoadedScene();

		const resourceFactory = game.resourceFactory;
		const music = game.audio.music;
		const sound = game.audio.sound;
		const zoo = scene.asset.getAudioById("zoo");

		const ctx1 = new AudioPlayContext({
			id: "play-context-1",
			resourceFactory,
			system: music,
			systemId: music.id,
			asset: zoo
		});

		ctx1.changeVolume(0.3);
		ctx1._startSuppress();
		expect(ctx1._player.volume).toBe(0);

		ctx1._endSuppress();
		// systemId: music の場合は endSuppress 後に再生を続ける
		expect(ctx1._player.volume).toBe(0.3);

		const ctx2 = new AudioPlayContext({
			id: "play-context-2",
			resourceFactory,
			system: sound,
			systemId: sound.id,
			asset: zoo
		});

		const mockCtx2Stop = jest.spyOn(ctx2._player, "stop");
		ctx2._startSuppress();

		// systemId: music 以外の場合は startSuppress 時点で停止する
		expect(mockCtx2Stop).toBeCalledTimes(1);
		ctx2._endSuppress();
	});
});

import { AudioPlayContext } from "../AudioPlayContext";
import type { AudioPlayer } from "./helpers";
import { customMatchers, Game, ResourceFactory } from "./helpers";

expect.extend(customMatchers);

describe("test AudioSystem", () => {
	it("AudioSystem#volumeの入力値チェック", () => {
		const game = new Game({ width: 320, height: 320, main: "", assets: {} });
		const system = game.audio.music;
		expect(() => {
			system.volume = NaN!;
		}).toThrowError();
		expect(() => {
			system.volume = undefined!;
		}).toThrowError();
		expect(() => {
			system.volume = null!;
		}).toThrowError();
		expect(() => {
			system.volume = "" as any;
		}).toThrowError();
		expect(() => {
			system.volume = false as any;
		}).toThrowError();
		expect(() => {
			system.volume = true as any;
		}).toThrowError();
		expect(() => {
			system.volume = 0 - 0.001;
		}).toThrowError();
		expect(() => {
			system.volume = 1 + 0.001;
		}).toThrowError();
	});

	it("AudioSystem#_destroyRequestedAssets", () => {
		const game = new Game({ width: 320, height: 320, main: "", assets: {} });
		const system = game.audio.music;
		const audio = new ResourceFactory().createAudioAsset("testId", "testAssetPath", 0, system, false, {});

		system.requestDestroy(audio);
		expect(system._destroyRequestedAssets[audio.id]).toEqual(audio);
		expect(system.getDestroyRequestedAsset(audio.id)).toEqual(audio);

		system.cancelRequestDestroy(audio);
		expect(system.getDestroyRequestedAsset(audio.id)).toBeNull();
		expect(system._destroyRequestedAssets[audio.id]).toBeUndefined();
	});

	it("AudioSystem#_setPlaybackRate", () => {
		const game = new Game({ width: 320, height: 320, main: "", assets: {} });
		const system = game.audio.sound;
		const player1 = system.createPlayer();
		const player2 = system.createPlayer();

		expect(player1._muted).toBeFalsy();
		expect(player2._muted).toBeFalsy();

		system._setPlaybackRate(0.3);
		expect(player1._muted).toBeTruthy();
		expect(player2._muted).toBeTruthy();
	});

	it("AudioSystem#_changeMuted", () => {
		const game = new Game({ width: 320, height: 320, main: "", assets: {} });
		const system = game.audio.sound;
		const player1 = system.createPlayer();
		const asset = game.resourceFactory.createAudioAsset("a1", "./dummypath", 2000, system, false, {});

		expect(player1._muted).toBe(false);
		player1.play(asset);
		player1.stop();
		expect(player1._muted).toBe(false);

		player1._changeMuted(true);
		expect(player1._muted).toBe(true);
		player1.play(asset);
		player1.stop();
		expect(player1._muted).toBe(true);
	});

	it("SoundAudioSystem#_reset", () => {
		const game = new Game({ width: 320, height: 320, main: "", assets: {} });
		const system = game.audio.sound;
		const asset = game.resourceFactory.createAudioAsset("dummy", "audio/dummy", 0, system, true, {});
		const player = system.createPlayer();

		system._setPlaybackRate(0.3);
		system.requestDestroy(asset);
		expect(system._destroyRequestedAssets.dummy).toBe(asset);

		system._reset();
		expect(player._muted).toBeTruthy();
		expect(system._destroyRequestedAssets).toEqual({});
	});

	it("MusicAudioSystem#_reset", () => {
		const game = new Game({ width: 320, height: 320, main: "", assets: {} });
		const system = game.audio.music;
		const asset = game.resourceFactory.createAudioAsset("dummy", "audio/dummy", 0, system, true, {});
		const player = system.createPlayer();

		system._setPlaybackRate(0.3);
