import { Camera2D } from "..";
import type { Runtime } from "./helpers";
import { CacheableE, EntityStateFlags, Renderer, skeletonRuntime } from "./helpers";

describe("test CacheableE", () => {
	let runtime: Runtime;

	beforeEach(() => {
		runtime = skeletonRuntime();
	});

	it("初期化", () => {
		const ce = new CacheableE({ scene: runtime.scene });
		expect(ce._shouldRenderChildren).toBe(true);
		expect(ce._cache).toBeUndefined();
		expect(ce._renderer).toBeUndefined();
		expect(ce._renderedCamera).toBeUndefined();
	});

	it("invalidate", () => {
		const ce = new CacheableE({ scene: runtime.scene });
		const renderer = new Renderer();

		expect(ce.state & EntityStateFlags.Cached).toBe(0);
		ce.renderSelf(renderer);
		expect(ce.state & EntityStateFlags.Cached).not.toBe(0);
		ce.invalidate();
		expect(ce.state & EntityStateFlags.Cached).toBe(0);
		ce.renderSelf(renderer);
		expect(ce.state & EntityStateFlags.Cached).not.toBe(0);
	});

	it("renderSelf", () => {
		const ce = new CacheableE({ scene: runtime.scene });
		const renderer = new Renderer();

		// 戻り値
		expect(ce.renderSelf(renderer)).toBe(true);
		ce._shouldRenderChildren = false;
		expect(ce.renderSelf(renderer)).toBe(false);
		ce._shouldRenderChildren = true;
		expect(ce.renderSelf(renderer)).toBe(true);
	});

	it("renderSelf calls renderCache", () => {
		const ce = new CacheableE({ scene: runtime.scene });
		const renderer = new Renderer();
		const cam1 = new Camera2D({});
		const cam2 = new Camera2D({});

		let called = false;
		ce.renderCache = () => {
			called = true;
		};

		// 呼ばれる (初期状態ではキャッシュされていない)
		called = false;
		ce.renderSelf(renderer);
		expect(called).toBe(true);

		// invalidate()すると呼ばれる
		called = false;
		ce.invalidate();
		ce.renderSelf(renderer);
		expect(called).toBe(true);

		// invalidate()しなくてもcameraが変わると呼ばれる(undefined -> cam1)
		called = false;
		ce.renderSelf(renderer, cam1);
		expect(called).toBe(true);

		// invalidate()しなくてもcameraが変わると呼ばれる(cam1 -> cam2)
		called = false;
		ce.renderSelf(renderer, cam2);
		expect(called).toBe(true);
	});

	it("renderSelf creates new cache", () => {
		const ce = new CacheableE({ scene: runtime.scene });
		const renderer = new Renderer();

		ce.width = 100;
		ce.height = 200;

		// 最初の呼び出し時にキャッシュを生成する
		let before = ce._cache;
		ce.invalidate();
		ce.renderSelf(renderer);

		let after = ce._cache;
		expect(before === after).toBe(false);

		// キャッシュを再生成しない
		ce.invalidate();
		ce.renderSelf(renderer);
		before = ce._cache;
		ce.invalidate();
		ce.renderSelf(renderer);
		after = ce._cache;
		expect(before === after).toBe(true);

		// サイズが変わるとキャッシュを再生成する
		ce.invalidate();
		ce.renderSelf(renderer);
		before = ce._cache;
		ce.width = 200;
		ce.height = 300;
		ce.invalidate();
		ce.renderSelf(renderer);
		after = ce._cache;
		expect(before === after).toBe(false);
	});

	it("renderSelf size validation", () => {
		const ce = new CacheableE({ scene: runtime.scene });
		const r = new Renderer();

		ce.width = 100;
		ce.height = 200;
		ce.invalidate();
		ce.renderSelf(r);
		ce.width = 0;
		ce.height = 0;
		ce.invalidate();
		ce.renderSelf(r);
		ce.width = 200;
		ce.height = 300;
		ce.invalidate();
		ce.renderSelf(r);
		const count = r.methodCallParamsHistory("drawImage").length;
		expect(count).toBe(2);
	});
});

import type { Matrix } from "..";
import { Camera2D, PlainMatrix } from "..";
import type { Renderer } from "./helpers";
import { Game } from "./helpers";

describe("test Camera", () => {
	it("初期化", () => {
		const cam1 = new Camera2D({ width: 320, height: 240 });
		expect(cam1.local).toBe(false);
		expect(cam1.name).toBeUndefined();
		expect(cam1.x).toBe(0);
		expect(cam1.y).toBe(0);
		expect(cam1.angle).toBe(0);
		expect(cam1.width).toBe(320);
		expect(cam1.height).toBe(240);
		expect(cam1._modifiedCount).toBe(0);

		const cam2 = new Camera2D({
			name: "foo",
			x: 100,
			y: 10,
			angle: 4,
			width: 80,
			height: 70
		});
		expect(cam2.local).toBe(false);
		expect(cam2.name).toBe("foo");
		expect(cam2.x).toBe(100);
		expect(cam2.y).toBe(10);
		expect(cam2.angle).toBe(4);
		expect(cam2.width).toBe(80);
		expect(cam2.height).toBe(70);
		expect(cam2._modifiedCount).toBe(0);

		const cam3 = new Camera2D({
			local: true,
			name: "bar",
			x: 100,
			y: 10
		});
		expect(cam3.local).toBe(true);
		expect(cam3.name).toBe("bar");
		expect(cam3.x).toBe(100);
		expect(cam3.y).toBe(10);
		expect(cam3.angle).toBe(0);
		expect(cam3.width).toBe(0);
		expect(cam3.height).toBe(0);
		expect(cam3._modifiedCount).toBe(0);
	});

	it("modified", () => {
		const cam = new Camera2D({});

		expect(cam._modifiedCount).toBe(0);
		cam.modified();
		expect(cam._modifiedCount).toBe(1);
		const matrix = cam._matrix;
		cam.getMatrix();
		cam.modified();
		expect(cam._modifiedCount).toBe(2);
		expect(cam._matrix!._modified).toBe(true);
		expect(cam._matrix).not.toEqual(matrix);
	});

	it("x, y, angle", () => {
		const cam = new Camera2D({});
		const expected = new PlainMatrix();
		let mat: Matrix;

		mat = cam.getMatrix();
		expect(mat._matrix).toEqual([1, 0, 0, 1, 0, 0]);

		cam.x = 10;
		cam.y = 100;
		cam.modified();
		mat = cam.getMatrix();
		expected.reset(-10, -100); // カメラは x, y の逆方向のオフセットがかかる
		expect(mat._matrix).toEqual(expected._matrix);

		const angle = 10;
		cam.angle = angle;
		cam.modified();
		mat = cam.getMatrix();
		expected.updateByInverse(320, 240, 1, 1, 10, 10, 100, 0, 0); // angle も逆方向に作用する
		expect(mat._matrix).toEqual(expected._matrix);
	});

	it("anchor", () => {
		const cam = new Camera2D({ width: 320, height: 240, angle: 10, x: 10, y: 100, anchorX: 0.5, anchorY: 0.5 });
		const expected = new PlainMatrix();
		const mat = cam.getMatrix();
		expected.updateByInverse(320, 240, 1, 1, 10, 10, 100, 0.5, 0.5);
		expect(mat._matrix).toEqual(expected._matrix);
	});

	it("_applyTransformToRenderer", () => {
		const game = new Game({ width: 320, height: 240, main: "", assets: {} });
		const cam = new Camera2D({});
		const surface = game.resourceFactory.createSurface(320, 240);
		const renderer = surface.renderer() as Renderer;

		cam.opacity = 0.5;
		cam.modified();
		renderer.clearMethodCallHistory();
		cam._applyTransformToRenderer(renderer);
		expect(renderer.methodCallHistory).toEqual(["translate", "opacity"]);
		expect(renderer.methodCallParamsHistory("translate")).toEqual([{ x: -0, y: -0 }]);
		expect(renderer.methodCallParamsHistory("opacity")).toEqual([{ opacity: 0.5 }]);

		cam.opacity = 1;
		cam.x = 10;
		cam.y = 100;
		cam.modified();
		renderer.clearMethodCallHistory();
		cam._applyTransformToRenderer(renderer);
		expect(renderer.methodCallHistory).toEqual(["translate"]);
		expect(renderer.methodCallParamsHistory("translate")).toEqual([{ x: -10, y: -100 }]);

		cam.angle = 10;
		cam.modified();
		renderer.clearMethodCallHistory();
		cam._applyTransformToRenderer(renderer);
		expect(renderer.methodCallHistory).toEqual(["transform"]);
		const mat = new PlainMatrix();
		mat.updateByInverse(320, 240, 1, 1, 10, 10, 100, 0, 0); // angle も逆方向に作用する
		expect(cam.getMatrix()._matrix).toEqual(mat._matrix);
		expect(renderer.methodCallParamsHistory("transform")).toEqual([{ matrix: mat._matrix }]);
	});

	it("serialize", () => {
		const cam = new Camera2D({
			x: 32,
			y: 15,
			angle: 3,
			name: "mycamera1"
		});
		let ser = cam.serialize();

		const cam2 = Camera2D.deserialize(ser);
		expect(cam2.x).toBe(32);
		expect(cam2.y).toBe(15);
		expect(cam2.angle).toBe(3);
		expect(cam2.scaleX).toBe(1);
		expect(cam2.scaleY).toBe(1);
		expect(cam2.opacity).toBe(1);
		expect(cam2.anchorX).toBe(0);
		expect(cam2.anchorY).toBe(0);
		expect(cam2.name).toBe("mycamera1");
		expect(cam2.local).toBe(false);

		cam2.x = 10;
		cam2.y = 100;
		cam2.opacity = 0.5;
		cam2.anchor(1.0, 0.5);
		ser = cam2.serialize();

		const cam3 = Camera2D.deserialize(ser);
		expect(cam3.x).toBe(10);
		expect(cam3.y).toBe(100);
		expect(cam3.angle).toBe(3);
		expect(cam3.scaleX).toBe(1);
		expect(cam3.scaleY).toBe(1);
		expect(cam3.anchorX).toBe(1.0);
		expect(cam3.anchorY).toBe(0.5);
		expect(cam3.opacity).toBe(0.5);
		expect(cam3.name).toBe("mycamera1");
		expect(cam3.local).toBe(false);
	});
});

import { E, Collision } from "..";
import { skeletonRuntime } from "./helpers";

describe("Collision.intersectLineSegments()", () => {
	it("is true for crossing edges", () => {
		expect(Collision.intersectLineSegments({ x: 2, y: 1 }, { x: 3, y: 4 }, { x: 1, y: 3 }, { x: 3, y: 3 })).toBe(true);
	});
	it("is true for identical edges", () => {
		expect(Collision.intersectLineSegments({ x: 2, y: 1 }, { x: 3, y: 4 }, { x: 3, y: 4 }, { x: 2, y: 1 })).toBe(true);
	});
	it("is true for contacting edges", () => {
		expect(Collision.intersectLineSegments({ x: 3, y: 4 }, { x: 2, y: 1 }, { x: 1, y: 3 }, { x: 3, y: 4 })).toBe(true);
	});
	it("is false for horizontally non-crossing edges", () => {
		expect(Collision.intersectLineSegments({ x: 3, y: 4 }, { x: 2, y: 1 }, { x: 1, y: 3 }, { x: 2, y: 2 })).toBe(false);
	});
	it("is false for vertically non-crossing edges", () => {
		expect(Collision.intersectLineSegments({ x: 3, y: 4 }, { x: 2, y: 1 }, { x: 1, y: -1 }, { x: 4, y: 1 })).toBe(false);
	});
});

describe("Collision.intersectEntities()", () => {
	const runtime = skeletonRuntime();
	const scene = runtime.scene;

	it("disconnected", () => {
		const e1 = new E({ scene, parent: scene, x: 10, y: 10, width: 20, height: 30 });
		const e2 = new E({ scene, x: 28, y: 38, width: 20, height: 30 });
		expect(Collision.intersectEntities(e1, e2)).toBe(false);
	});

	it("children of the scene, no scale, no rotation", () => {
		const e1 = new E({ scene, parent: scene, x: 10, y: 10, width: 20, height: 30 });
		const e2 = new E({ scene, parent: scene, x: 28, y: 38, width: 20, height: 30 });
		expect(Collision.intersectEntities(e1, e2)).toBe(true);
		e2.x += 10;
		e2.modified();
		expect(Collision.intersectEntities(e1, e2)).toBe(false);
	});

	it("brothers, scaled, no rotation", () => {
		const parent = new E({ scene, parent: scene, x: 100, y: 100 });
		const e1 = new E({ scene, parent: parent, x: 10, y: 10, width: 20, height: 30, scaleX: 1.5, scaleY: 1.5 });
		const e2 = new E({ scene, parent: parent, x: 35, y: 45, width: 20, height: 30 });
		expect(Collision.intersectEntities(e1, e2)).toBe(true);
		e1.scaleX = e1.scaleY = 0.9;
		e1.modified();
		expect(Collision.intersectEntities(e1, e2)).toBe(false);
	});

	it("brothers, no scale, rotated", () => {
		const parent = new E({ scene, parent: scene, x: 100, y: 100 });
		const e1 = new E({ scene, parent: parent, x: 10, y: 10, width: 20, height: 30, angle: 3 });
		const e2 = new E({ scene, parent: parent, x: 28, y: 38, width: 20, height: 30 });
		expect(Collision.intersectEntities(e1, e2)).toBe(true);
		e1.angle = 180;
		e1.modified();
		expect(Collision.intersectEntities(e1, e2)).toBe(false);
	});

	it("brothers, scaled, rotated", () => {
		const parent = new E({ scene, parent: scene, x: 100, y: 100 });
		const e1 = new E({ scene, parent: parent, x: 10, y: 10, width: 20, height: 30, scaleX: 1.5, scaleY: 1.5, angle: 90 });
		const e2 = new E({ scene, parent: parent, x: 35, y: 45, width: 20, height: 30 });
		expect(Collision.intersectEntities(e1, e2)).toBe(false);
		e1.angle = 5;
		e1.modified();
		expect(Collision.intersectEntities(e1, e2)).toBe(true);
	});

	it("cousin, scaled, rotation", () => {
		const root = new E({ scene, parent: scene, x: 100, y: 100 });

		// 原点 (200, 100), 90 度回転
		const p1 = new E({ scene, parent: root, x: 100, y: 0, width: 10, height: 10, angle: 90 });
		// 原点 (100, 230), X 軸 2 倍拡大
		const p2 = new E({ scene, parent: root, x: 0, y: 130, width: 10, height: 10, scaleX: 2 });

		// 原点 (200, 200), 左上端 (50, 100), サイズ 50x50
		const e1 = new E({ scene, parent: p1, x: 100, y: 0, width: 50, height: 50 });
		// 原点＝左上端 (120, 230), サイズ 40x50
		const e2 = new E({ scene, parent: p2, x: 10, y: 0, width: 20, height: 50 });

		expect(Collision.intersectEntities(e1, e2)).toBe(true);

		p2.scaleX = 1;
		p2.modified();
		expect(Collision.intersectEntities(e1, e2)).toBe(false);

		p2.scaleX = 2;
		p2.modified();
		p1.angle = 45;
		p1.modified();
		expect(Collision.intersectEntities(e1, e2)).toBe(false);
	});

	it("cousin, scaled, rotation, with hit rects", () => {
		const root = new E({ scene, parent: scene, x: 100, y: 100 });

		// 原点 (200, 100), 90 度回転
		const p1 = new E({ scene, parent: root, x: 100, y: 0, width: 10, height: 10, angle: 90 });
		// 原点 (100, 230), X 軸 2 倍拡大
		const p2 = new E({ scene, parent: root, x: 0, y: 130, width: 10, height: 10, scaleX: 2 });

		// 原点 (200, 200), 左上端 (50, 100), サイズ 50x50
		const e1 = new E({ scene, parent: p1, x: 100, y: 0, width: 50, height: 50 });
		// 原点＝左上端 (120, 230), サイズ 40x50
		const e2 = new E({ scene, parent: p2, x: 10, y: 0, width: 20, height: 50 });

		const e2h = e2.height;
		expect(Collision.intersectEntities(e1, e2, null, { x: 0, y: e2h / 2, width: e2.width, height: e2h })).toBe(false);
		expect(Collision.intersectEntities(e1, e2, { x: 0, y: 0, width: e1.width / 2, height: e1.height }, null)).toBe(false);
	});
});

