	describe("localToGlobal, globalToLocal", () => {
		let p: E;
		let p2: E;
		let p3: E;
		let e: E;
		let anotherRuntime: Runtime;
		beforeEach(() => {
			// 各エンティティのマトリクスは以下の値になる
			// p: [ 0.5, 0, -0, 0.5, 100, 100 ]
			// p2: [ 0.7071067811865476, 0.7071067811865475, -0.7071067811865475, 0.7071067811865476, 0, 0 ]
			// p3:  [ 2, 0, -0, 3, 20, 20 ]
			// e: [ 1, 0, 0, 1, 10, 0 ]
			// p * p2 * p3 * e: [0.707107, 0.707107, -1.06066, 1.06066, 107.071, 121.213]
			// ( p * p2 * p3 * e)-1: [0.707107, -0.471405, 0.707107, 0.471405, -161.421, -6.6666]
			p = new E({ scene: runtime.scene, x: 100, y: 100, scaleX: 0.5, scaleY: 0.5, anchorX: 1, anchorY: 1 });
			p2 = new E({ scene: runtime.scene, angle: 45, anchorX: 0.5, anchorY: 0.5, parent: p });
			p3 = new E({ scene: runtime.scene, x: 20, y: 20, scaleX: 2, scaleY: 3, parent: p2 });
			e = new E({ scene: runtime.scene, parent: p3, x: 10, y: 0 });
			anotherRuntime = skeletonRuntime();
		});
		it("can convert local point to global point", () => {
			// 一番上の親エンティティのparentがundefinedの場合
			const targetPoint = { x: 5, y: 30 };
			const actual = e.localToGlobal(targetPoint);
			// (p * p2 * p3 * e) * targetPoint の計算結果
			const expected = { x: 78.787, y: 156.568 };
			// 小数点第2位まで合っていればパスとする
			expect(actual.x).toBeApproximation(expected.x, 3);
			expect(actual.y).toBeApproximation(expected.y, 3);

			// 一番上の親エンティティのparentがsceneに変わってもlocalToGlobalの結果は変わらない
			p.parent = anotherRuntime.scene;
			anotherRuntime.scene.append(p);
			const actual2 = e.localToGlobal(targetPoint);
			expect(actual2.x).toBeApproximation(expected.x, 3);
			expect(actual2.y).toBeApproximation(expected.y, 3);
		});
		it("can convert global point to local point", () => {
			// 一番上の親エンティティのparentがundefinedの場合
			const targetPoint = { x: 500, y: 500 };
			const actual = e.globalToLocal(targetPoint);
			// (p * p2 * p3 * e)-1 * targetPoint の計算結果
			const expected = { x: 545.686, y: -6.667 };
			// 小数点第2位まで合っていればパスとする
			expect(actual.x).toBeApproximation(expected.x, 3);
			expect(actual.y).toBeApproximation(expected.y, 3);

			// 一番上の親エンティティのparentがsceneに変わってもlocalToGlobalの結果は変わらない
			p.parent = anotherRuntime.scene;
			anotherRuntime.scene.append(p);
			const actual2 = e.globalToLocal(targetPoint);
			expect(actual2.x).toBeApproximation(expected.x, 3);
			expect(actual2.y).toBeApproximation(expected.y, 3);
		});
		it("is reversible", () => {
			const targetPoint = { x: 0, y: 0 };
			const actual = e.localToGlobal(e.globalToLocal(targetPoint));
			expect(actual.x).toBeApproximation(targetPoint.x, 10);
			expect(actual.y).toBeApproximation(targetPoint.y, 10);
			const actual2 = e.globalToLocal(e.localToGlobal(targetPoint));
			expect(actual2.x).toBeApproximation(targetPoint.x, 10);
			expect(actual2.y).toBeApproximation(targetPoint.y, 10);
		});
		it("can convert predictable values", () => {
			const targetPoint = { x: 0, y: 0 };
			// これらのマトリクスはかけると [1, 0, 0, 1, 0, 0] に近似した値となる
			p = new E({ scene: runtime.scene, x: 100, y: 100, scaleX: 0.5, scaleY: 0.5 });
			p2 = new E({ scene: runtime.scene, angle: 45, parent: p });
			p3 = new E({ scene: runtime.scene, angle: -45, scaleX: 2, scaleY: 2, parent: p2 });
			e = new E({ scene: runtime.scene, parent: p3, x: -100, y: -100 });

			// localToGlobalとglobalToLocalのどちらを実行しても元の位置に戻る
			const actual = e.localToGlobal(targetPoint);
			expect(actual.x).toBeApproximation(targetPoint.x, 3);
			expect(actual.y).toBeApproximation(targetPoint.y, 3);
			const actual2 = e.globalToLocal(targetPoint);
			expect(actual2.x).toBeApproximation(targetPoint.x, 3);
			expect(actual2.y).toBeApproximation(targetPoint.y, 3);
		});
	});
});

import { PlatformButtonType } from "@akashic/pdi-types";
import * as pl from "@akashic/playlog";
import { PointDownEvent, PointMoveEvent, PointUpEvent } from "../entities/E";
import { FilledRect } from "../entities/FilledRect";
import { JoinEvent, MessageEvent, OperationEvent, TimestampEvent, LeaveEvent, PlayerInfoEvent } from "../Event";
import { EventConverter } from "../EventConverter";
import { EventPriority } from "../EventPriority";
import type { Player } from "../Player";
import { Game, skeletonRuntime } from "./helpers";

describe("EventConverter", () => {
	it("can be instantiated", () => {
		const game = new Game({
			width: 320,
			height: 320,
			fps: 30,
			main: "",
			assets: {}
		});
		const self = new EventConverter({ game, playerId: "dummyPlayerId" });
		expect(self._game).toBe(game);
		expect(self._playerId).toBe("dummyPlayerId");
		expect(self._playerTable).toEqual({});
	});

	it("encode/decode events", () => {
		const runtime = skeletonRuntime();
		const game = runtime.game;
		const scene = runtime.scene;
		const player: Player = { id: "dummyPlayerId", name: "dummyName" };
		const self = new EventConverter({ game, playerId: player.id });

		const pjoin: pl.JoinEvent = [pl.EventCode.Join, EventPriority.System, player.id!, player.name!];
		const join = new JoinEvent(player, EventPriority.System);
		const join2 = self.toGameEvent(pjoin);
		expect(join).toEqual(join2);
		expect(() => {
			self.toPlaylogEvent(join2);
		}).toThrow();

		const rect = new FilledRect({
			scene,
			cssColor: "red",
			x: 100,
			y: 100,
			width: 100,
			height: 100,
			touchable: true
		});
		scene.append(rect);

		// エンティティが存在する位置
		const source = game.findPointSource({ x: 110, y: 120 })!;
		expect(source.target!.id).toBeGreaterThan(0);
		expect(source.point).toEqual({ x: 10, y: 20 });

		const pd = new PointDownEvent(1, source.target, source.point!, player, false, EventPriority.Joined);
		const pd2 = self.toGameEvent(self.toPlaylogEvent(pd));
		expect(pd).toEqual(pd2);

		const pm = new PointMoveEvent(
			1,
			source.target,
			source.point!,
			{ x: 2, y: 3 },
			{ x: 2, y: 3 },
			player,
			false,
			PlatformButtonType.Unchanged,
			EventPriority.Lowest
		);
		const pm2 = self.toGameEvent(self.toPlaylogEvent(pm));
		expect(pm).toEqual(pm2);

		const pu = new PointUpEvent(
			1,
			source.target,
			source.point!,
			{ x: 4, y: 1 },
			{ x: 6, y: 4 },
			player,
			false,
			PlatformButtonType.Secondary,
			EventPriority.Joined
		);
		const pu2 = self.toGameEvent(self.toPlaylogEvent(pu));
		expect(pu).toEqual(pu2);

		// エンティティが存在する位置
		const point = { x: 10, y: 10 };
		const nonJoinedPlayer: Player = { id: "nonjoined-dummy-id" };
		const source2 = game.findPointSource(point)!;
		expect(source2.target).toBe(undefined);
		expect(source2.point).toEqual(undefined);
		expect(source2.local).toEqual(false);
		const lpd = new PointDownEvent(1, source2.target, point, nonJoinedPlayer, false, EventPriority.System);
		const lpd2 = self.toGameEvent(self.toPlaylogEvent(lpd, true));
		expect(lpd).toEqual(lpd2);
		const lpm = new PointMoveEvent(
			1,
			source2.target,
			point,
			{ x: 2, y: 3 },
			{ x: 2, y: 3 },
			nonJoinedPlayer,
			false,
			EventPriority.Unjoined
		);
		const lpm2 = self.toGameEvent(self.toPlaylogEvent(lpm, true));
		expect(lpm).toEqual(lpm2);
		const lpu = new PointUpEvent(1, source2.target, point, { x: 4, y: 1 }, { x: 6, y: 4 }, nonJoinedPlayer, false);
		const lpu2 = self.toGameEvent(self.toPlaylogEvent(lpu, true));
		expect(lpu).toEqual(lpu2);

		const msg = new MessageEvent({ value: "data" }, player, true, EventPriority.Joined);
		const msg2 = self.toGameEvent(self.toPlaylogEvent(msg));
		expect(msg).toEqual(msg2);

		const op = new OperationEvent(42, { value: "op" }, player, false, EventPriority.Joined);
		const op2 = self.toGameEvent(self.toPlaylogEvent(op));
		expect(op).toEqual(op2);

		// Timestamp: Code, Priority, PlayerId, Timestamp
		const timestamp = new TimestampEvent(4201, player, EventPriority.System);
		const timestamp2 = self.toGameEvent(self.toPlaylogEvent(timestamp));
		expect(timestamp).toEqual(timestamp2);

		// Leave: Code, Priority, PlayerId
		const pleave: pl.LeaveEvent = [pl.EventCode.Leave, EventPriority.System, "dummyPlayerId"];
		const leave = new LeaveEvent(player, EventPriority.System);
		const leave2 = self.toGameEvent(pleave);
		expect(leave).toEqual(leave2);
		expect(() => {
			self.toPlaylogEvent(leave2);
		}).toThrow();

		// PlayerInfo: Code, Priority, PlayerId, PlayerName, UserData
		const pPlayerInfo: pl.PlayerInfoEvent = [
			pl.EventCode.PlayerInfo,
			EventPriority.System,
			"dummyPlayerId",
			"dummyName",
			{ userDataProp: "dummy" }
		];
		const playerInfo = new PlayerInfoEvent(
			{ id: "dummyPlayerId", name: "dummyName", userData: { userDataProp: "dummy" } },
			EventPriority.System
		);
		const playerInfo2 = self.toGameEvent(pPlayerInfo);
		expect(playerInfo).toEqual(playerInfo2);

		// PlayerInfoEvent 送信後にプレイヤー情報が取得できていることを確認
		const pdown: pl.PointDownEvent = [pl.EventCode.PointDown, EventPriority.System, "dummyPlayerId", 0, 110, 120];
		const pointDown = self.toGameEvent(pdown) as PointDownEvent;
		expect(pointDown.player!.id).toBe("dummyPlayerId");
		expect(pointDown.player!.name).toBe("dummyName");
		expect(pointDown.player!.userData).toEqual({ userDataProp: "dummy" });

		// JoinEvent 送信後にユーザデータが上書きされていないことを確認
		const pjoin2: pl.JoinEvent = [pl.EventCode.Join, EventPriority.System, player.id!, player.name!, undefined];
		self.toGameEvent(pjoin2);
		const pdown2: pl.PointDownEvent = [pl.EventCode.PointDown, EventPriority.System, "dummyPlayerId", 0, 110, 120];
		const pointDown2 = self.toGameEvent(pdown2) as PointDownEvent;
		expect(pointDown2.player!.id).toBe("dummyPlayerId");
		expect(pointDown2.player!.name).toBe("dummyName");
		expect(pointDown2.player!.userData).toEqual({ userDataProp: "dummy" });
	});
});

