import { skeletonRuntime } from "./helpers";

describe("test E", () => {
	let runtime: Runtime, e: E;

	beforeEach(() => {
		runtime = skeletonRuntime();
		e = new E({ scene: runtime.scene });
		runtime.scene.append(e);
		e.width = 30;
		e.height = 20;
		e.touchable = true;
		e.modified();
	});

	it("移動なし", () => {
		for (let x = 0; x < e.width; x++) {
			for (let y = 0; y < e.height; y++) {
				const t = e.findPointSourceByPoint({ x: x, y: y })!;
				expect(t.target).toBe(e);
			}
		}
		let t = e.findPointSourceByPoint({ x: e.width, y: e.height - 1 });
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: e.width, y: e.height });
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: -1, y: 0 });
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: 0, y: -1 });
		expect(t).toBeUndefined();
	});

	it("移動あり", () => {
		const xp = 20;
		const yp = 10;
		e.moveTo(xp, yp);
		for (let x = xp; x < e.width + xp; x++) {
			for (let y = yp; y < e.height + yp; y++) {
				const t = e.findPointSourceByPoint({ x: x, y: y })!;
				expect(t.target).toBe(e);
			}
		}
		let t = e.findPointSourceByPoint({ x: e.width + xp, y: e.height + yp - 1 })!;
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: e.width + xp - 1, y: e.height + yp })!;
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: xp - 1, y: yp })!;
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: xp, y: yp - 1 })!;
		expect(t).toBeUndefined();
	});

	it("拡大あり: アンカーポイントが左上", () => {
		const scale = 2;
		const fromX = 0;
		const fromY = 0;
		const toX = e.width * scale;
		const toY = e.height * scale;
		e.scale(scale);
		for (let x = fromX; x < toX; x++) {
			for (let y = fromY; y < toY; y++) {
				const t = e.findPointSourceByPoint({ x, y })!;
				expect(t.target).toBe(e);
			}
		}
		let t = e.findPointSourceByPoint({
			x: fromX,
			y: fromY - 1
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({
			x: fromX - 1,
			y: fromY
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX + 1, y: toY });
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX, y: toY + 1 });
		expect(t).toBeUndefined();
	});

	it("拡大あり: アンカーポイントが中央", () => {
		const scale = 2;
		const w = e.width * scale;
		const h = e.height * scale;
		const fromX = e.width / 2 - (e.width * scale) / 2;
		const fromY = e.height / 2 - (e.height * scale) / 2;
		const toX = fromX + w;
		const toY = fromY + h;
		e.moveTo(e.width / 2, e.height / 2);
		e.anchor(0.5, 0.5);
		e.scale(scale);
		for (let x = fromX; x < toX; x++) {
			for (let y = fromY; y < toY; y++) {
				const t = e.findPointSourceByPoint({ x, y })!;
				expect(t.target).toBe(e);
			}
		}
		let t = e.findPointSourceByPoint({
			x: fromX,
			y: fromY - 1
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({
			x: fromX - 1,
			y: fromY
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX + 1, y: toY });
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX, y: toY + 1 });
		expect(t).toBeUndefined();
	});

	it("回転あり: アンカーポイントが左上", () => {
		const fromX = -e.height;
		const fromY = 0;
		const toX = 0;
		const toY = e.width;
		const angle = 90;
		e.angle = angle;
		for (let x = fromX + 0.1; x < toX; x++) {
			for (let y = fromY + 0.1; y < toY; y++) {
				const t = e.findPointSourceByPoint({ x, y })!;
				expect(t.target).toBe(e);
			}
		}
		let t = e.findPointSourceByPoint({
			x: fromX + 0.1,
			y: fromY - 1
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({
			x: fromX - 1,
			y: fromY + 0.1
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX + 1, y: toY });
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX, y: toY + 1 });
		expect(t).toBeUndefined();
	});

	it("回転あり: アンカーポイントが中央", () => {
		const fromX = 0;
		const fromY = 0;
		const toX = e.width;
		const toY = e.height;
		const angle = 180;
		e.anchor(0.5, 0.5);
		e.moveTo(e.width / 2, e.height / 2);
		e.angle = angle;
		for (let x = fromX + 0.1; x < toX; x++) {
			for (let y = fromY + 0.1; y < toY; y++) {
				const t = e.findPointSourceByPoint({ x, y })!;
				expect(t.target).toBe(e);
			}
		}
		let t = e.findPointSourceByPoint({
			x: fromX + 0.1,
			y: fromY - 1
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({
			x: fromX - 1,
			y: fromY + 0.1
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX + 1, y: toY });
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX, y: toY + 1 });
		expect(t).toBeUndefined();
	});

	it("拡大+回転あり", () => {
		const angle = 180;
		const scale = 2;
		const fromX = -e.width * scale;
		const fromY = -e.height * scale;
		const toX = 0;
		const toY = 0;
		e.scale(scale);
		e.angle = angle;
		for (let x = fromX + 0.1; x < toX; x++) {
			for (let y = fromY + 0.1; y < toY; y++) {
				const t = e.findPointSourceByPoint({ x, y })!;
				expect(t.target).toBe(e);
			}
		}
		let t = e.findPointSourceByPoint({
			x: fromX + 0.1,
			y: fromY - 1
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({
			x: fromX - 1,
			y: fromY + 0.1
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX + 1, y: toY });
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX, y: toY + 1 });
		expect(t).toBeUndefined();
	});

	it("入れ子", () => {
		e.scale(2);
		const e2 = new E({ scene: runtime.scene });
		e2.width = 10;
		e2.height = 10;
		e2.scale(1.5);
		e.touchable = false;
		e.append(e2);
		e2.touchable = true;
		e2.modified();
		expect(e2.touchable).toBe(true);
		expect(e.touchable).toBe(false);
		expect(e._hasTouchableChildren).toBe(true);

		let t = e.findPointSourceByPoint({ x: 20, y: 10 })!;
		expect(t.target).toBe(e2);
		t = e.findPointSourceByPoint({ x: 30, y: 11 })!;
		expect(t).toBeUndefined();
	});

	it("入れ子で両方有効", () => {
		e.scale(2);
		const e2 = new E({ scene: runtime.scene });
		e2.width = 10;
		e2.height = 10;
		e2.scale(1.5);
		e.touchable = true;
		e.append(e2);
		e2.modified();
		e2.touchable = true;
		expect(e2.touchable).toBe(true);
		expect(e._hasTouchableChildren).toBe(true);

		let t = e.findPointSourceByPoint({ x: 20, y: 10 })!;
		expect(t.target).toBe(e2);
		t = e.findPointSourceByPoint({ x: 30, y: 11 })!;
		expect(t.target).toBe(e);
		t = e.findPointSourceByPoint({ x: 30, y: 40 })!;
		expect(t).toBeUndefined();
	});

	it("入れ子のやつをappendしてその後remove", () => {
		e.scale(2);
		const e2 = new E({ scene: runtime.scene });
		e2.width = 10;
		e2.height = 10;
		e2.scale(1.5);
		e.touchable = false;
		e2.touchable = true;
		e.append(e2);
		e2.modified();
		expect(e2.touchable).toBe(true);
		expect(e.touchable).toBe(false);
		expect(e._hasTouchableChildren).toBe(true);

		e2.remove();
		expect(e._hasTouchableChildren).toBe(false);
	});

	it("deprecated: 座標基点=左上, 拡大+回転の基点=中央", () => {
		const angle = 180;
		const scale = 2;
		const w = e.width * scale;
		const h = e.height * scale;
		const fromX = e.width / 2 - w / 2;
		const fromY = e.height / 2 - h / 2;
		const toX = fromX + w;
		const toY = fromY + h;
		e.scale(scale);
		e.angle = angle;
		e.anchorX = null;
		for (let x = fromX + 0.1; x < toX; x++) {
			for (let y = fromY + 0.1; y < toY; y++) {
				const t = e.findPointSourceByPoint({ x, y })!;
				expect(t.target).toBe(e);
			}
		}
		let t = e.findPointSourceByPoint({
			x: fromX + 0.1,
			y: fromY - 1
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({
			x: fromX - 1,
			y: fromY + 0.1
		});
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX + 1, y: toY });
		expect(t).toBeUndefined();
		t = e.findPointSourceByPoint({ x: toX, y: toY + 1 });
		expect(t).toBeUndefined();
	});
});

import type { GameConfiguration } from "..";
import { Game } from "./helpers";

describe("test InitialScene", () => {
	const configuration: GameConfiguration = {
		width: 320,
		height: 320,
		main: "./main.js",
		assetBundle: "./asset.bundle.js",
		assets: {
			main: {
				type: "script",
				path: "./main.js",
				virtualPath: "main.js",
				global: true
			},
			"asset.bundle": {
				type: "script",
				path: "./asset.bundle.js",
				virtualPath: "asset.bundle.js",
				global: true
			}
		}
	};
	const assetBundle = `{
		assets: {
			"/script/preload.js": {
				type: "script",
				path: "script/preload.js",
				preload: true,
				execute: (runtimeValue) => {
					const { module } = runtimeValue;
					const exports = module.exports;

					module.exports = () => {
						g.game.vars.preloaded = true;
					}

					return module.exports;
				}
			},
			"/script/module.js": {
				type: "script",
				path: "script/module.js",
				execute: (runtimeValue) => {
					const { module } = runtimeValue;
					const exports = module.exports;

					exports.multiply = (a, b) => {
						return a * b;
					}

					return module.exports;
				}
			},
		},
	}`;

	it("should load from asset.bundle.js instead of the defined asset", done => {
		const game = new Game(configuration);
		game.resourceFactory.scriptContents["./main.js"] = "module.exports = () => g.game.__entry_point__();";
		game.resourceFactory.scriptContents["./asset.bundle.js"] = `module.exports = ${assetBundle}`;
		(game as any).__entry_point__ = () => {
			expect(game.vars.preloaded).toBe(true); // エントリポイントに先行して /script/preload.js が実行されていることを確認

			const assetBundle = game._moduleManager._internalRequire(configuration.assetBundle!);
			expect(assetBundle.assets["/script/module.js"]).toBeDefined();
			expect(assetBundle.assets["/script/module.js"].type).toBe("script");
			expect(assetBundle.assets["/script/module.js"].path).toBe("script/module.js");
			expect(assetBundle.assets["/script/module.js"].execute).toBeInstanceOf(Function);

			const module = game._moduleManager._internalRequire("./script/module.js");
			expect(module.multiply).toBeInstanceOf(Function);
			expect(module.multiply(2, 10)).toBe(20);
			done();
		};
		game._loadAndStart();
	});
});

import type { GlyphArea } from "..";
import { BitmapFont, Label } from "..";
import type { Surface } from "./helpers";
import { Renderer, skeletonRuntime } from "./helpers";

describe("test Label", () => {
	it("初期化", () => {
		const runtime = skeletonRuntime();
		const width = 32;
		const height = 64;
		const imageAsset = runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", width, height);
		const map = { "37564": { x: 0, y: 1 } };
		const missingGlyph: GlyphArea = { x: 2, y: 3 };
		const bmpfont = new BitmapFont({
			src: imageAsset,
			map: map,
			defaultGlyphWidth: width,
			defaultGlyphHeight: height,
			missingGlyph: missingGlyph
		});

		const label = new Label({
			scene: runtime.scene,
			text: "a",
			font: bmpfont,
			fontSize: 10,
			textAlign: "center",
			maxWidth: 100,
			widthAutoAdjust: false,
			width: 50,
			height: 20,
			textColor: "white"
		});
		expect(label.scene).toBe(runtime.scene);
		expect(label.text).toEqual("a");
		expect(label.font).toBe(bmpfont);
		expect(label.fontSize).toBe(10);
		expect(label.textAlign).toBe("center");
		expect(label.maxWidth).toBe(100);
		expect(label.widthAutoAdjust).toBe(false);
		expect(label.width).toBe(50);
		expect(label.height).toBe(10); // height 指定は無視されて fontSize で上書きされる
		expect(label.textColor).toBe("white");
	});
	it("初期化 - missMissingGlyph", () => {
		const runtime = skeletonRuntime();
		const width = 32;
		const height = 64;
		const imageAsset = runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", width, height);
		const map = { "37564": { x: 0, y: 1 } };
		// @ts-ignore
		const missingGlyph: GlyphArea = null;

		const bmpfont = new BitmapFont({
			src: imageAsset,
			map: map,
			defaultGlyphWidth: width,
			defaultGlyphHeight: height,
			missingGlyph: missingGlyph
		});
		expect(bmpfont.surface).not.toBeNull();
		expect(bmpfont.defaultGlyphWidth).toEqual(width);
		expect(bmpfont.defaultGlyphHeight).toEqual(height);
		expect(bmpfont.map).toEqual(map);
		expect(bmpfont.missingGlyph).toBeNull();
	});
	it("初期化 - fontSize = 0", () => {
		const runtime = skeletonRuntime();
		const width = 32;
		const height = 64;
		const imageAsset = runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", width, height);
		const map = { "37564": { x: 0, y: 1 } };
		const missingGlyph: GlyphArea = { x: 2, y: 3 };

		const bmpfont = new BitmapFont({
			src: imageAsset,
			map: map,
			defaultGlyphWidth: width,
			defaultGlyphHeight: height,
			missingGlyph: missingGlyph
		});
		const label = new Label({
			scene: runtime.scene,
			text: "a",
			font: bmpfont,
			fontSize: 0,
			textAlign: 0,
			maxWidth: 100
		});
		expect(label.textAlign).toBe(0);
		expect(label.widthAutoAdjust).toBe(true);
		expect(label.width).toBe(0);
		expect(label.height).toBe(0);
	});

	it("初期化 - default fontSize is same as font.size", () => {
		const runtime = skeletonRuntime();
		const width = 32;
		const height = 64;
		const imageAsset = runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", width, height);
		const map = { "37564": { x: 0, y: 1 } };
		const missingGlyph: GlyphArea = { x: 2, y: 3 };

		const bmpfont = new BitmapFont({
			src: imageAsset,
			map: map,
			defaultGlyphWidth: width,
			defaultGlyphHeight: height,
			missingGlyph: missingGlyph
		});
		const label = new Label({
			scene: runtime.scene,
			text: "a",
			font: bmpfont
		});
		expect(label.fontSize).toBe(bmpfont.size);
	});

	it("glyphForCharacter", () => {
		const runtime = skeletonRuntime();
		const width = 32;
		const height = 64;
		const imageAsset = runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", width, height);
		const map = { "37564": { x: 0, y: 1 } };
		// @ts-ignore
		const missingGlyph: GlyphArea = null;

		const bmpfont = new BitmapFont({
			src: imageAsset,
			map: map,
			defaultGlyphWidth: width,
			defaultGlyphHeight: height,
			missingGlyph: missingGlyph
		});
		expect(bmpfont.glyphForCharacter(37564)!.code).toBe(37564);
		expect(bmpfont.glyphForCharacter(-1)).toBeNull();
	});

	it("glyphForCharacter - handle unmapped glyph", () => {
		const runtime = skeletonRuntime();
		const width = 32;
		const height = 64;
		const imageAsset = runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", width, height);
		const map = { "37564": { x: 0, y: 1 } };

		const bmpfont = new BitmapFont({
			src: imageAsset,
			map: map,
			defaultGlyphWidth: width,
			defaultGlyphHeight: height
		});
		const label = new Label({
			scene: runtime.scene,
			text: "a",
			font: bmpfont,
			fontSize: 10,
			textAlign: "center",
			maxWidth: 100,
			widthAutoAdjust: false,
			width: 50,
			height: 20,
			textColor: "white"
		});
		bmpfont.glyphForCharacter = () => {
			return null;
		}; // g.Font からグリフ情報を得られない状態を模倣する
		label.text = "咫";
		expect(() => {
			label.invalidate();
		}).not.toThrow();
	});
	it("aligning", () => {
		const runtime = skeletonRuntime();
		const width = 32;
		const height = 64;
		const imageAsset = runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", width, height);
		const map = { 97: { x: 0, y: 1 } }; // "a".charCodeAt(0) === 97
		const missingGlyph: GlyphArea = null!;

		const bmpfont = new BitmapFont({
			src: imageAsset,
			map: map,
			defaultGlyphWidth: width,
			defaultGlyphHeight: height,
			missingGlyph: missingGlyph
		});
		const label = new Label({
			scene: runtime.scene,
			text: "a",
			font: bmpfont,
			fontSize: 10,
			textAlign: "center",
			maxWidth: 100,
			widthAutoAdjust: false,
			width: 50,
			height: 20
		});
		label.aligning(100, "center");
		expect(label.width).toBe(100);
		expect(label.widthAutoAdjust).toBe(false);
		expect(label.textAlign).toBe("center");
	});
	it("キャッシュのテスト", () => {
		const runtime = skeletonRuntime();
		const r = new Renderer();
		const width = 512;
		const height = 350;
		const map = { "37564": { x: 0, y: 1 } };
		const missingGlyph: GlyphArea = { x: 2, y: 3 };
		const bmpfont = new BitmapFont({
			src: runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", width, height),
			map: map,
			defaultGlyphWidth: 35,
			defaultGlyphHeight: 50,
			missingGlyph: missingGlyph
		});
		const label = new Label({
			scene: runtime.scene,
			text: "a",
			font: bmpfont,
			fontSize: 10
		});
		label.render(r);
		label.fontSize = 0;
		label.height = 0;
		label.width = 0;
		label.invalidate();
		label.render(r);
		const count = (label._renderer as Renderer).methodCallHistory.filter(elem => elem === "drawImage").length;
		const bmpfont2 = new BitmapFont({
			src: runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", width, height),
			map: map,
			defaultGlyphWidth: 0,
			defaultGlyphHeight: 0,
			missingGlyph: missingGlyph
		});
		const label2 = new Label({
			scene: runtime.scene,
			text: "b",
			font: bmpfont2,
			fontSize: 10
		});
		label2.render(r);
		label2.fontSize = 20;
		label2.invalidate();
		label2.render(r);
		const count2 = (label2._renderer as Renderer).methodCallHistory.filter(elem => elem === "drawImage").length;
		const label3 = new Label({
			scene: runtime.scene,
			text: "c",
			font: bmpfont,
			fontSize: 10
		});
		label3.render(r);
		label3.text = "";
		label3.invalidate();
		label3.render(r);
		const count3 = (label3._renderer as Renderer).methodCallHistory.filter(elem => elem === "drawImage").length;
		expect(count).toBe(1);
		expect(count2).toBe(0);
		expect(count3).toBe(1);
	});
	it("renderCache - textColor", () => {
		const runtime = skeletonRuntime();
		const r = new Renderer();
		const width = 512;
		const height = 350;
		const map = { "37564": { x: 0, y: 1 } };
		const missingGlyph: GlyphArea = { x: 2, y: 3 };
		const bmpfont = new BitmapFont({
			src: runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", width, height),
			map: map,
			defaultGlyphWidth: width,
			defaultGlyphHeight: height,
			missingGlyph: missingGlyph
		});
		const label = new Label({
			scene: runtime.scene,
			text: "a",
			font: bmpfont,
			fontSize: 10,
			textColor: "blue"
		});
		label.render(r);

		const cr = (label._cache as Surface).createdRenderer as Renderer;

		expect(cr.methodCallParamsHistory("setCompositeOperation").length).toBe(1);
		expect(cr.methodCallParamsHistory("setCompositeOperation")[0]).toEqual({
			operation: "source-atop"
		});

		expect(cr.methodCallParamsHistory("fillRect").length).toBe(1);
		expect(cr.methodCallParamsHistory("fillRect")[0]).toEqual({
			x: 0,
