import { CompositeOperation, Object2D, PlainMatrix } from "..";
import { customMatchers } from "./helpers";

expect.extend(customMatchers);

describe("test Object2D", () => {
	let e: Object2D;

	beforeEach(() => {
		e = new Object2D();
	});

	it("初期化", () => {
		expect(e.x).toEqual(0);
		expect(e.y).toEqual(0);
		expect(e.width).toEqual(0);
		expect(e.height).toEqual(0);
		expect(e.opacity).toEqual(1);
		expect(e.scaleX).toEqual(1);
		expect(e.scaleY).toEqual(1);
		expect(e.angle).toEqual(0);
		expect(e.compositeOperation).toBeUndefined();
		expect(e.anchorX).toBe(0);
		expect(e.anchorY).toBe(0);
		expect(e._matrix).toBeUndefined();
	});

	it("初期化 - ParameterObject", () => {
		let e = new Object2D({});
		expect(e.x).toEqual(0);
		expect(e.y).toEqual(0);
		expect(e.width).toEqual(0);
		expect(e.height).toEqual(0);
		expect(e.opacity).toEqual(1);
		expect(e.scaleX).toEqual(1);
		expect(e.scaleY).toEqual(1);
		expect(e.angle).toEqual(0);
		expect(e.compositeOperation).toBeUndefined();
		expect(e.anchorX).toBe(0);
		expect(e.anchorY).toBe(0);
		expect(e._matrix).toBeUndefined();

		e = new Object2D({
			x: 1,
			y: 2,
			width: 3,
			height: 4,
			opacity: 0.2,
			scaleX: 0.4,
			scaleY: 1.2,
			angle: 10,
			compositeOperation: "source-atop",
			anchorX: 0,
			anchorY: 1
		});
		expect(e.x).toEqual(1);
		expect(e.y).toEqual(2);
		expect(e.width).toEqual(3);
		expect(e.height).toEqual(4);
		expect(e.opacity).toEqual(0.2);
		expect(e.scaleX).toEqual(0.4);
		expect(e.scaleY).toEqual(1.2);
		expect(e.angle).toEqual(10);
		expect(e.compositeOperation).toEqual("source-atop");
		expect(e.anchorX).toBe(0);
		expect(e.anchorY).toBe(1);
		expect(e._matrix).toBeUndefined();

		e = new Object2D({
			x: 1,
			y: 2,
			width: 3,
			height: 4,
			opacity: 0.2,
			scaleX: 0.4,
			scaleY: 1.2,
			angle: 10,
			compositeOperation: CompositeOperation.SourceAtop,
			anchorX: 0,
			anchorY: 1
		});
		expect(e.x).toEqual(1);
		expect(e.y).toEqual(2);
		expect(e.width).toEqual(3);
		expect(e.height).toEqual(4);
		expect(e.opacity).toEqual(0.2);
		expect(e.scaleX).toEqual(0.4);
		expect(e.scaleY).toEqual(1.2);
		expect(e.angle).toEqual(10);
		expect(e.compositeOperation).toEqual(CompositeOperation.SourceAtop);
		expect(e.anchorX).toBe(0);
		expect(e.anchorY).toBe(1);
		expect(e._matrix).toBeUndefined();

		e = new Object2D({
			x: 1,
			y: 2,
			width: 3,
			height: 4,
			opacity: 0.2,
			scaleX: 0.4,
			scaleY: 1.2,
			angle: 10,
			compositeOperation: "source-atop",
			anchorX: null,
			anchorY: null
		});
		expect(e.anchorX).toBeNull();
		expect(e.anchorY).toBeNull();
	});

	it("moveTo", () => {
		e.moveTo(1, 1);
		expect(e.x).toEqual(1);
		expect(e.y).toEqual(1);
		e.moveTo(-1, -1);
		expect(e.x).toEqual(-1);
		expect(e.y).toEqual(-1);
		e.moveTo(0, -1);
		expect(e.x).toEqual(0);
		expect(e.y).toEqual(-1);

		const pos = { x: 1, y: 1 };
		e.moveTo(pos);
		expect(e.x).toEqual(1);
		expect(e.y).toEqual(1);
	});

	it("moveTo - AssertionError", () => {
		const pos = { x: 1, y: 1 };
		expect(() => {
			e.moveTo(-1, pos as any);
		}).toThrowError("AssertionError");
	});

	it("moveToEntity", () => {
		const e2 = new Object2D();
		e.moveTo(e2);
		expect(e.x).toEqual(e2.x);
		expect(e.y).toEqual(e2.y);
		e2.moveTo(500, 500);
		e.moveTo(e2);
		expect(e.x).toEqual(e2.x);
		expect(e.y).toEqual(e2.y);
		e2.moveTo(100, 41000);
		e.moveTo(e2);
		expect(e.x).toEqual(e2.x);
		expect(e.y).toEqual(e2.y);
	});

	it("moveBy", () => {
		e.moveBy(1, 0);
		expect(e.x).toEqual(1);
		expect(e.y).toEqual(0);
		e.moveBy(0, 1);
		expect(e.x).toEqual(1);
		expect(e.y).toEqual(1);
		e.moveBy(0, -1);
		expect(e.x).toEqual(1);
		expect(e.y).toEqual(0);
		e.moveBy(-2, -1);
		expect(e.x).toEqual(-1);
		expect(e.y).toEqual(-1);
	});

	it("resizeTo", () => {
		e.resizeTo(100, 100);
		expect(e.width).toEqual(100);
		expect(e.height).toEqual(100);
		e.resizeTo(-100, 100);
		expect(e.width).toEqual(-100);
		expect(e.height).toEqual(100);
		e.resizeTo(-200, -200);
		expect(e.width).toEqual(-200);
		expect(e.height).toEqual(-200);

		const size = { width: 100, height: 100 };
		e.resizeTo(size);
		expect(e.width).toEqual(100);
		expect(e.height).toEqual(100);
	});

	it("resizeTo - AssertionError", () => {
		const size = { width: 100, height: 100 };
		expect(() => {
			e.resizeTo(100, size as any);
		}).toThrowError("AssertionError");
	});

	it("resizeToEntity", () => {
		const e2 = new Object2D();
		e.resizeTo(e2);
		expect(e.width).toEqual(e2.width);
		expect(e.height).toEqual(e2.height);
		e2.resizeTo(500, 500);
		e.resizeTo(e2);
		expect(e.width).toEqual(e2.width);
		expect(e.height).toEqual(e2.height);
		e2.resizeTo(100, 41000);
		e.resizeTo(e2);
		expect(e.width).toEqual(e2.width);
		expect(e.height).toEqual(e2.height);
	});

	it("resizeBy", () => {
		e.resizeBy(1, 0);
		expect(e.width).toEqual(1);
		expect(e.height).toEqual(0);
		e.resizeBy(0, 1);
		expect(e.width).toEqual(1);
		expect(e.height).toEqual(1);
		e.resizeBy(0, -1);
		expect(e.width).toEqual(1);
		expect(e.height).toEqual(0);
		e.resizeBy(-2, -1);
		expect(e.width).toEqual(-1);
		expect(e.height).toEqual(-1);
	});

	it("scale", () => {
		e.scale(2);
		expect(e.scaleX).toBe(2);
		expect(e.scaleY).toBe(2);
		e.scale(0.5);
		expect(e.scaleX).toBe(0.5);
		expect(e.scaleY).toBe(0.5);
		e.scale(1);
		expect(e.scaleX).toBe(1);
		expect(e.scaleY).toBe(1);
	});

	it("anchor", () => {
		e.anchor(1, 0);
		expect(e.anchorX).toBe(1);
		expect(e.anchorY).toBe(0);
		e.anchor(0.5, 0.5);
		expect(e.anchorX).toBe(0.5);
		expect(e.anchorY).toBe(0.5);
	});

	it("getMatrix", () => {
		let scarecrow = new PlainMatrix();
		expect(e.getMatrix()).toEqual(scarecrow);

		e.scale(2);
		e._matrix!._modified = true;
		scarecrow = new PlainMatrix(0, 0, 2, 2, 0, 1, 1);
		expect(e.getMatrix()).toEqual(scarecrow);
		expect(e._matrix!._modified).toBe(false);

		e.scale(1);
		e._matrix!._modified = true;
		scarecrow = new PlainMatrix();
		expect(e.getMatrix()).toEqual(scarecrow);
		expect(e._matrix!._modified).toBe(false);

		e.resizeTo(20, 20);
		e.moveTo(10, 10);
		e.anchor(1, 1);
		e._matrix!._modified = true;
		const expected = new PlainMatrix();
		expected.update(20, 20, 1, 1, 0, 10, 10, 1, 1);
		expect(e.getMatrix()._matrix).toEqual(expected._matrix);
		expect(e._matrix!._modified).toBe(false);
	});
});

import { Trigger } from "@akashic/trigger";
import type { GameConfiguration, InternalOperationPluginOperation, Module, OperationPluginViewInfo } from "..";
import { Game } from "./helpers";

// テスト用ダミー操作プラグイン
class TestOperationPlugin {
	operationTrigger: Trigger<any> = new Trigger();
	_game: Game;
	_viewInfo: OperationPluginViewInfo;
	_option: any;
	_started: boolean = false;

	static isSupported(): boolean {
		return true;
	}

	constructor(game: Game, viewInfo: OperationPluginViewInfo, option: any) {
		this._game = game;
		this._viewInfo = viewInfo;
		this._option = option;
	}

	start(): void {
		this._started = true;
	}

	stop(): void {
		this._started = false;
	}

	debugFire(v: any): void {
		this.operationTrigger.fire(v);
	}
}

class TestOperationPluginUnsupported extends TestOperationPlugin {
	static override isSupported(): boolean {
		return false;
	}
}

describe("test OperationPluginManager", () => {
	const dummyViewInfo: OperationPluginViewInfo = { dummy: true } as any;
	let game: Game;

	beforeEach(() => {
		const conf: GameConfiguration = {
			width: 320,
			height: 270,
			assets: {
				mainScene: {
					type: "script",
					path: "/dummy/dummy.js",
					virtualPath: "dummy/dummy.js",
					global: true
				}
			},
			operationPlugins: [
				{ code: 42, script: "/script/op-plugin.js" },
				{ code: 10, script: undefined },
				{ code: 15, script: "/script/op-plugin-unsupported.js" },
				{ code: 2, script: "/script/op-plugin.js", manualStart: true }
			],
			main: "./dummy/dummy.js"
		};
		game = new Game(conf, "/", "foo", dummyViewInfo);
		const manager = game._moduleManager;
		const requireOriginal = manager._require;
		manager._require = (path: string, currentModule?: Module) => {
			switch (path) {
				case "/script/op-plugin.js":
					return TestOperationPlugin;
				case "/script/op-plugin-unsupported.js":
					return TestOperationPluginUnsupported;
				default:
					return requireOriginal.call(manager, path, currentModule);
			}
		};
	});

	it("初期化", done => {
		expect(game.operationPluginManager).not.toBeFalsy();
		expect(game.operationPluginManager.onOperate instanceof Trigger).toBe(true);
		expect(game.operationPluginManager.plugins).toEqual({});
		done();
	});

	it("Register gameConfiguration.operationPlugins with _onStart", done => {
		game._onStart.add(() => {
			const self = game.operationPluginManager;
			expect(self.plugins[42]).not.toBeFalsy();
			expect((self.plugins[42] as any)._started).toBe(true);
			expect((self.plugins[42] as any)._game).toBe(game);
			expect((self.plugins[42] as any)._viewInfo).toBe(dummyViewInfo);
			expect(self.plugins[2]).not.toBeFalsy();
			expect((self.plugins[2] as any)._started).toBe(false);
			expect(self.plugins[10]).toBeFalsy();
			expect(self.plugins[15]).toBeFalsy();
			done();
		});
		game._loadAndStart();
	});

	it("operated", done => {
		game._onStart.add(() => {
			const self = game.operationPluginManager;

			const ops: InternalOperationPluginOperation[] = [];
			self.onOperate.add(op => {
				ops.push(op);
			});

			const plugin = self.plugins[42] as TestOperationPlugin;
			plugin.debugFire(["foo", 1]);
			plugin.debugFire([4]);
			expect(ops).toEqual([
				{ _code: 42, data: ["foo", 1] },
				{ _code: 42, data: [4] }
			]);
			plugin.debugFire({ local: true, data: [] });
			expect(ops[2]).toEqual({ _code: 42, local: true, data: [] });
			done();
		});
		game._loadAndStart();
	});

	it("register", done => {
		game._onStart.add(() => {
			const self = game.operationPluginManager;

			expect(self.plugins[30]).toBeUndefined();
			// @ts-ignore
			self.register(TestOperationPlugin, 30, { dummy: true });

			expect(self.plugins[30]).toBeDefined();

			const plugin1 = self.plugins[30] as TestOperationPlugin;
			expect(plugin1._option).toEqual({ dummy: true });
			expect(plugin1._started).toBe(false);
			self.start(30);
			expect(plugin1._started).toBe(true);

			expect(self.plugins[60]).toBeUndefined();
			// @ts-ignore
			self.register(TestOperationPluginUnsupported, 60, { dummy: false });
			expect(self.plugins[60]).toBeUndefined();

			expect(() => {
				// @ts-ignore
				self.register(TestOperationPlugin, 30);
			}).toThrowError("Plugin#code conflicted for code: 30");
			expect(() => {
				// unsupported の場合初期化されない (=例外が発生しない) ことを確認
				// @ts-ignore
				self.register(TestOperationPluginUnsupported, 42);
			}).not.toThrowError("Plugin#code conflicted for code: 42");

			done();
		});
		game._loadAndStart();
	});

	it("destroy", done => {
		game._onStart.add(() => {
			const self = game.operationPluginManager;

			self.destroy();
			expect(self.onOperate).toBeFalsy();
			expect(self.plugins).toBeFalsy();
			done();
		});
		game._loadAndStart();
	});

	it("reset", done => {
		game._onStart.add(() => {
			const self = game.operationPluginManager;
			self.onOperate.add(() => {
				return;
			});
			// @ts-ignore
			const plugin = self.register(TestOperationPlugin, 11, { dummy: true }) as TestOperationPlugin;
			expect(self.plugins[11]).toBeDefined();
			plugin!.start();
			expect(plugin._started).toBe(true);

			self.reset();
			expect(self.onOperate.length).toBe(0);
			expect(self.plugins).toEqual({});
			expect(plugin._started).toBe(false);
			done();
		});
		game._loadAndStart();
	});
});

import type { CommonRect } from "..";
import { E, Pane, Sprite, SurfaceUtil } from "..";
import type { Runtime } from "./helpers";
import { customMatchers, EntityStateFlags, Renderer, skeletonRuntime, Surface } from "./helpers";

expect.extend(customMatchers);

describe("test Pane", () => {
	let runtime: Runtime;

	beforeEach(() => {
		runtime = skeletonRuntime();
	});

	it("初期化 - ParameterObject", () => {
		const pane = new Pane({
			scene: runtime.scene,
			width: 10,
			height: 20,
			padding: { top: 3, left: 1, right: 4, bottom: 2 }
		});
		expect(pane.width).toBe(10);
		expect(pane.height).toBe(20);
		expect(pane._oldWidth).toBe(10);
		expect(pane._oldHeight).toBe(20);
		expect(pane).toHaveUndefinedValue("backgroundImage", "backgroundEffector");
		expect((pane._padding as CommonRect).top).toBe(3);
		expect((pane._padding as CommonRect).bottom).toBe(2);
		expect((pane._padding as CommonRect).left).toBe(1);
		expect((pane._padding as CommonRect).right).toBe(4);
		expect(pane._childrenSurface instanceof Surface).toBe(true);
		expect(pane._childrenRenderer instanceof Renderer).toBe(true);
		expect(pane._paddingChanged).toBe(false);
		expect(pane._bgSurface).toBeUndefined();
	});

	it("padding", () => {
		const game = runtime.game;
		const scene = runtime.scene;
		const surface = game.resourceFactory.createSurface(320, 320);
		game.renderers.push(surface.renderer());

		const pane = new Pane({
			scene: scene,
			width: 10,
			height: 20,
			padding: 3
		});
		scene.append(pane);
		expect(pane.padding).toBe(3);
		pane.padding = 5;
		pane.modified();
		expect(pane.padding).toBe(5);
	});

	it("convert ImageAsset to Surface", () => {
		const imageAsset = runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", 480, 480);
		const pane = new Pane({
			scene: runtime.scene,
			width: 10,
			height: 20,
			padding: { top: 3, left: 1, right: 4, bottom: 2 },
			backgroundImage: imageAsset
		});
		expect(pane._backgroundImageSurface).toEqual(SurfaceUtil.asSurface(imageAsset));
	});

	it("change backgroundImage", () => {
		const scene = runtime.scene;
		const imageAsset = runtime.game.resourceFactory.createImageAsset("dummy", "testAssetPath", 200, 200);
		const r = new Renderer();

		const pane = new Pane({
			scene: scene,
			width: 10,
			height: 20,
			padding: 3
		});
		scene.append(pane);

		expect(pane.backgroundImage).toBeUndefined();
		expect(pane._beforeBackgroundImage).toBeUndefined();
		expect(pane._backgroundImageSurface).toBeUndefined();

		pane.backgroundImage = imageAsset;
		pane.renderCache(r); // invalidate()
		expect(pane.backgroundImage).toBe(imageAsset);
		expect(pane._beforeBackgroundImage).toBe(imageAsset);
		expect(pane._backgroundImageSurface).toBe(imageAsset.asSurface());

		pane.backgroundImage = undefined;
		pane.renderCache(r); // invalidate()
		expect(pane.backgroundImage).toBeUndefined();
		expect(pane._beforeBackgroundImage).toBeUndefined();
		expect(pane._backgroundImageSurface).toBeUndefined();
	});

	it("modified", () => {
		const game = runtime.game;
		const scene = runtime.scene;
		const surface = game.resourceFactory.createSurface(320, 320);
		game.renderers.push(surface.renderer());

		const pane = new Pane({
			scene: scene,
			width: 10,
			height: 20,
			padding: 3
		});
		const child = new E({ scene: scene });
		const grandChild = new E({ scene: scene });
		scene.append(pane);
		pane.append(child);
		child.append(grandChild);
		expect(pane.state & EntityStateFlags.Cached).toBe(0);

		// リセット
		game.render();
		expect(pane.state & EntityStateFlags.Cached).toBe(EntityStateFlags.Cached);
		// Pane#modified() を直接呼ぶと Cached は落ちない
		pane.modified();
		expect(pane.state & EntityStateFlags.Cached).toBe(EntityStateFlags.Cached);

		// リセット
		game.render();
		expect(pane.state & EntityStateFlags.Cached).toBe(EntityStateFlags.Cached);
		// 子の E#modified() から間接的に呼ぶと Cached は落ちる
		child.modified();
		expect(pane.state & EntityStateFlags.Cached).toBe(0);

		// リセット
		game.render();
		expect(pane.state & EntityStateFlags.Cached).toBe(EntityStateFlags.Cached);
		// 孫から呼んでも立つ
		grandChild.modified();
		expect(pane.state & EntityStateFlags.Cached).toBe(0);
	});

	it("shouldFindChildrenByPoint", () => {
		const pane = new Pane({
			scene: runtime.scene,
			width: 10,
			height: 20,
			padding: { top: 3, left: 1, right: 4, bottom: 2 }
		});
		let result = pane.shouldFindChildrenByPoint({ x: 1, y: 3 });
		expect(result).toBe(false);
		result = pane.shouldFindChildrenByPoint({ x: 2, y: 3 });
		expect(result).toBe(false);
		result = pane.shouldFindChildrenByPoint({ x: 2, y: 4 });
		expect(result).toBe(true);
		result = pane.shouldFindChildrenByPoint({ x: 2, y: 17 });
		expect(result).toBe(true);
		result = pane.shouldFindChildrenByPoint({ x: 2, y: 18 });
		expect(result).toBe(false);
		result = pane.shouldFindChildrenByPoint({ x: 5, y: 4 });
		expect(result).toBe(true);
		result = pane.shouldFindChildrenByPoint({ x: 6, y: 4 });
		expect(result).toBe(false);
	});

	it("render", () => {
		// no backgroundImage
		let pane = new Pane({
			scene: runtime.scene,
			width: 10,
			height: 20,
			padding: { top: 3, left: 1, right: 4, bottom: 2 }
		});
		const r = new Renderer();
		pane.invalidate();
		pane.render(r);
		let renderer = pane._renderer as Renderer;
		expect(renderer.methodCallParamsHistory("drawImage").length).toBe(1);
		renderer.clearMethodCallHistory();

		const imageAsset = runtime.game.resourceFactory.createImageAsset("dummy", "testAssetPath", 200, 200);

		// given backgroundImage
		pane = new Pane({
			scene: runtime.scene,
			width: 10,
			height: 20,
			padding: { top: 3, left: 1, right: 4, bottom: 2 },
			backgroundImage: imageAsset
		});
		pane.invalidate();
		pane.render(r);
		renderer = pane._renderer as Renderer;
		expect(renderer.methodCallParamsHistory("drawImage").length).toBe(2); // + draw background imageAsset
		renderer.clearMethodCallHistory();

		pane.width = 0;
		pane.height = 0;
		pane.invalidate();
		pane.render(r);
		expect(renderer.methodCallParamsHistory("drawImage").length).toBe(0);
		renderer.clearMethodCallHistory();
	});

	it("render - validation", () => {
		const pane = new Pane({
			scene: runtime.scene,
			width: 10,
			height: 20,
			padding: { top: 10, left: 5, right: 5, bottom: 10 }
		});
		const r = new Renderer();
		pane.invalidate();
		pane.render(r);
		const renderer = pane._renderer as Renderer;
		expect(renderer.methodCallParamsHistory("drawImage").length).toBe(0);
		renderer.clearMethodCallHistory();
	});

	it("calculateBoundingRect", () => {
		const pane = new Pane({
			scene: runtime.scene,
			width: 50,
			height: 50
		});
		const imageAsset = runtime.game.resourceFactory.createImageAsset("testId", "testAssetPath", 32, 32);
		const child = new Sprite({
			scene: runtime.scene,
			width: 32,
			height: 32,
			src: imageAsset
		});
		child.x = 100;
		pane.append(child);
		expect(pane.calculateBoundingRect()).toEqual({
			left: 0,
			right: 50,
			top: 0,
			bottom: 50
		});
	});
});

