	it("prefetch - with no assets", done => {
		const game = new Game({
			width: 320,
			height: 320,
			main: "",
			assets: assetsConfiguration
		});
		const scene = new Scene({ game: game });
		game.resourceFactory.createsDelayedAsset = true;

