		expect(scene2._timer._timers.length).toBe(1);
		scene2.setInterval(() => {
			// do nothing
		}, 50);
		expect(scene1._timer._timers.length).toBe(1);
		expect(scene2._timer._timers.length).toBe(1);

		game.popScene();
		game._flushPostTickTasks();
		expect(scene1._timer._timers.length).toBe(1);
		expect(scene2._timer._timers).toBeUndefined();

		const scene3 = new Scene({ game: game });
		game.replaceScene(scene3);
		game._flushPostTickTasks();
		expect(scene1._timer._timers).toBeUndefined();
	});

	it("setInterval", () => {
		const runtime = skeletonRuntime({ width: 320, height: 320, fps: 32, main: "", assets: {} });
		const game = runtime.game;
		const scene = game.scene()!;
		const owner = {};
		let callCount = 0;
		scene.setInterval(
			function (this: any): void {
				expect(this).toBe(owner);
				callCount++;
			},
			100,
			owner
		);

		game.tick(true);
		game.tick(true);
		game.tick(true); // 3/32*1000 = 93.75ms
		expect(callCount).toBe(0);
		game.tick(true); // 4/32*1000 = 125ms
		expect(callCount).toBe(1);
		game.tick(true);
		game.tick(true);
		expect(callCount).toBe(1);
		game.tick(true); // 7/32*1000 = 218.75ms
		expect(callCount).toBe(2);
		game.tick(true);
		game.tick(true);
		expect(callCount).toBe(2);
		game.tick(true); // 10/32*1000 = 312.5ms
		expect(callCount).toBe(3);
	});

	it("isCurrentScene/gotoScene/end", done => {
		const game = new Game({ width: 320, height: 320, main: "", assets: {} });
		game._onLoad.add(() => {
			// game.scenes テストのため _loaded を待つ必要がある
			const scene1 = new Scene({ game: game });
			const scene2 = new Scene({ game: game });
			const scene3 = new Scene({ game: game });

			game.pushScene(scene1);
			game._flushPostTickTasks();
			expect(scene1.isCurrentScene()).toBe(true);
			expect(scene2.isCurrentScene()).toBe(false);
			expect(scene3.isCurrentScene()).toBe(false);

			scene1.gotoScene(scene2, true); // push scene2
			game._flushPostTickTasks();
			expect(scene1.isCurrentScene()).toBe(false);
			expect(scene2.isCurrentScene()).toBe(true);
			expect(scene3.isCurrentScene()).toBe(false);

			scene2.end();
			game._flushPostTickTasks();
			expect(scene1.isCurrentScene()).toBe(true);
			expect(scene3.isCurrentScene()).toBe(false);

			scene1.gotoScene(scene3, false); // replace scene1 to scene3
			game._flushPostTickTasks();
			expect(scene3.isCurrentScene()).toBe(true);
			done();
		});
		game._startLoadingGlobalAssets();
	});

	it("gotoScene - AssertionError", done => {
		const game = new Game({ width: 320, height: 320, main: "", assets: {} });
		game._onLoad.add(() => {
			// game.scenes テストのため _loaded を待つ必要がある
			const scene1 = new Scene({ game: game });
			const scene2 = new Scene({ game: game });
			expect(() => {
				scene1.gotoScene(scene2);
			}).toThrowError("AssertionError");
			done();
		});
		game._startLoadingGlobalAssets();
	});

	it("end - AssertionError", done => {
		const game = new Game({ width: 320, height: 320, main: "", assets: {} });
		game._onLoad.add(() => {
			// game.scenes テストのため _loaded を待つ必要がある
			const scene1 = new Scene({ game: game });
			expect(() => {
				scene1.end();
			}).toThrowError("AssertionError");
			done();
		});
		game._startLoadingGlobalAssets();
	});
});

import { E, Sprite, SpriteFactory } from "..";
import { skeletonRuntime } from "./helpers";

describe("test SpriteFactory", () => {
	it("createSpriteFromE", () => {
		const runtime = skeletonRuntime();
		const scene = runtime.scene;
		const e = new E({ scene: scene });
		e.width = 100;
		e.height = 50;
		e.opacity = 0.5;
		scene.append(e);

		const sp = SpriteFactory.createSpriteFromE(scene, e);
		expect(sp instanceof Sprite).toBe(true);
		expect(sp.width).toBe(100);
		expect(sp.height).toBe(50);
	});

	it("createSpriteFromE with children", () => {
		const runtime = skeletonRuntime();
		const scene = runtime.scene;
		const e = new E({ scene: scene });

		const oldModified = e.modified;
		let modifiedCounter = 0;
		e.modified = () => {
			++modifiedCounter;
			oldModified.call(e);
		};

		e.width = 100;
		e.height = 50;
		e.opacity = 0.5;
		e.anchorX = 0;
		e.anchorY = 0;
		scene.append(e);

		const e2 = new E({ scene: scene });
		e2.width = 200;
		e2.height = 100;
		e2.opacity = 0.1;
		e.anchorX = 0;
		e.anchorY = 0;
		e2.scale(2);
		scene.append(e2);

		e.append(e2);

		const modCount = modifiedCounter;
		const sp = SpriteFactory.createSpriteFromE(scene, e);
		expect(sp instanceof Sprite).toBe(true);
		expect(sp.width).toBe(400);
		expect(sp.height).toBe(200);
		expect(modifiedCounter).toBe(modCount); // createSpriteFromE() は modified() しない
	});

	it("createSpriteFromE with hide", () => {
		const runtime = skeletonRuntime();
		const scene = runtime.scene;
		const e = new E({ scene: scene });
		e.width = 100;
		e.height = 50;
		scene.append(e);

		const e2 = new E({ scene: scene });
		e2.width = 200;
		e2.height = 100;
		e2.hide();
		scene.append(e2);

		e.append(e2);

		const sp = SpriteFactory.createSpriteFromE(scene, e);
		expect(sp instanceof Sprite).toBe(true);
		expect(sp.width).toBe(100);
		expect(sp.height).toBe(50);

		e2.show();
		const sp2 = SpriteFactory.createSpriteFromE(scene, e);
		expect(sp2 instanceof Sprite).toBe(true);
		expect(sp2.width).toBe(200);
		expect(sp2.height).toBe(100);
	});

	it("createSpriteFromScene", () => {
		const runtime = skeletonRuntime();
		const scene = runtime.scene;
		const sp = SpriteFactory.createSpriteFromScene(scene, scene);
		expect(sp instanceof Sprite).toBe(true);
		expect(sp.width).toBe(runtime.game.width);
		expect(sp.height).toBe(runtime.game.height);

		const sceneHasChild = runtime.scene;
		sceneHasChild.append(sp);
		const spHasChild = SpriteFactory.createSpriteFromScene(sceneHasChild, scene);
		expect(spHasChild instanceof Sprite).toBe(true);
		expect(spHasChild.width).toBe(runtime.game.width);
		expect(spHasChild.height).toBe(runtime.game.height);
	});
});

import { Sprite } from "..";
import { Renderer, skeletonRuntime, Surface } from "./helpers";

describe("test Sprite", () => {
	let updated = false;

	class MonitorSprite extends Sprite {
		override _handleUpdate(): void {
			super._handleUpdate();
			updated = true;
		}
	}

	beforeEach(() => {
		updated = false;
	});

	it("初期化", () => {
		const runtime = skeletonRuntime();
		const surface = new Surface(480, 480);
		const sprite = new MonitorSprite({
			scene: runtime.scene,
			src: surface,
			width: 32,
			height: 48
		});
		expect(sprite.width).toBe(32);
		expect(sprite.height).toBe(48);
		expect(sprite.srcWidth).toBe(32);
		expect(sprite.srcHeight).toBe(48);
		expect(sprite.srcX).toBe(0);
		expect(sprite.srcY).toBe(0);
		expect(sprite.src).toBe(surface);
		expect(sprite._beforeSrc).toBe(sprite.src);
		expect(sprite._surface).toBe(surface);
		expect(sprite._beforeSurface).toBe(sprite._surface);

		sprite.invalidate();
		expect(sprite.width).toBe(32);
		expect(sprite.height).toBe(48);
		sprite.srcWidth = 10;
		sprite.srcHeight = 10;
		sprite.invalidate();
		expect(sprite.srcWidth).toBe(10);
		expect(sprite.srcHeight).toBe(10);

		const surface2 = new Surface(16, 32);
		const sprite2 = new MonitorSprite({
			scene: runtime.scene,
			src: surface2
		});
		expect(sprite2.width).toBe(16);
		expect(sprite2.height).toBe(32);
		expect(sprite2.srcWidth).toBe(16);
		expect(sprite2.srcHeight).toBe(32);
		expect(sprite2.srcX).toBe(0);
		expect(sprite2.srcY).toBe(0);
		expect(sprite2.src).toBe(surface2);
		expect(sprite2._beforeSrc).toBe(sprite2.src);
		expect(sprite2._surface).toBe(surface2);
		expect(sprite2._beforeSurface).toBe(sprite2._surface);
