			code,
			x,
			y,
			width,
			height,
			surface,
			offsetX: 0,
			offsetY: 0,
			advanceWidth: width,
			isSurfaceValid: !!surface,
			_atlas: null
		};
	};

	it("初期化", () => {
		const runtime = skeletonRuntime();
		surfaceAtlasSet = new SurfaceAtlasSet({ resourceFactory: runtime.game.resourceFactory });
		expect(surfaceAtlasSet._surfaceAtlases).toEqual([]);
		expect(surfaceAtlasSet.getMaxAtlasNum()).toEqual(SurfaceAtlasSet.INITIAL_MAX_SURFACEATLAS_NUM);
		expect(surfaceAtlasSet.getAtlasUsedSize()).toEqual({ width: 512, height: 512 });
	});

	it("初期化 パラメータあり", () => {
		const runtime = skeletonRuntime();
		const surfaceAtlasSetParams: SurfaceAtlasSetParameterObject = {
			resourceFactory: runtime.game.resourceFactory,
			hint: {
				initialAtlasWidth: 2, // このテストでは 1x1 のグリフしか入れないが、内部的に幅・高さを1pxずつ拡張して管理するので最低 2x2 は必要
				initialAtlasHeight: 2,
				maxAtlasWidth: 2,
				maxAtlasHeight: 3,
				maxAtlasNum: 111
			}
		};
		surfaceAtlasSet = new SurfaceAtlasSet(surfaceAtlasSetParams);
		expect(surfaceAtlasSet._surfaceAtlases).toEqual([]);
		expect(surfaceAtlasSet.getMaxAtlasNum()).toEqual(111);
		expect(surfaceAtlasSet.getAtlasUsedSize()).toEqual({ width: 2, height: 2 });
	});

	describe("_spliceLeastFrequentlyUsedAtlas", () => {
		it("_accessScoreが低いSurfaceAtlasが保持配列から削除される", () => {
			for (let i = 0; i < 10; i++) {
				surfaceAtlasSet._reallocateAtlas();
			}

			surfaceAtlasSet._surfaceAtlases.forEach((atlas, index) => {
				atlas._accessScore = index;
			});

			const removedAtlas = surfaceAtlasSet._spliceLeastFrequentlyUsedAtlas();
			const ret = surfaceAtlasSet._surfaceAtlases.find(atlas => atlas._accessScore === 0);
			expect(ret).toBeUndefined();
			expect(removedAtlas).not.toBeNull();
			expect(removedAtlas!._accessScore).toBe(0);
			expect(surfaceAtlasSet.getAtlasNum()).toBe(9);
		});
	});

	describe("addGlyph", () => {
		it("追加対象のSurfaceに空き領域がない場合、falseが返る", () => {
			const glyph = createGlyph(300, 0, 0, 10, 10);
			const ret = surfaceAtlasSet.addGlyph(glyph);
			expect(ret).toBe(false);
		});
		it("正常にグリフが追加された場合、trueが返る", () => {
			const glyph = createGlyph(300, 0, 0, 1, 1, new Surface(1, 1));
			const ret = surfaceAtlasSet.addGlyph(glyph);
			expect(ret).toBe(true);
		});
	});

	describe("reallocateAtlas", () => {
		it("SurfaceAtlasの保持数が最大値未満の場合、SurfaceAtlasが追加される", () => {
			surfaceAtlasSet.changeMaxAtlasNum(surfaceAtlasSet.getAtlasNum() + 1);
			const currentLength = surfaceAtlasSet.getAtlasNum();

			surfaceAtlasSet._reallocateAtlas();
			expect(surfaceAtlasSet.getAtlasNum()).toEqual(currentLength + 1);
		});
		it("SurfaceAtlasの保持数が最大値の場合、削除処理が呼ばれる。", () => {
			const method = jest.spyOn(surfaceAtlasSet, "_spliceLeastFrequentlyUsedAtlas");
			surfaceAtlasSet._reallocateAtlas();
			expect(method).toHaveBeenCalled();
		});
	});

	describe("changeMaxAtlasNum", () => {
		it("現在のSurfaceAtlasの保持数より値が大きい場合、maxAtlasNumの値が設定される", () => {
			surfaceAtlasSet.changeMaxAtlasNum(15);
			expect(surfaceAtlasSet.getMaxAtlasNum()).toEqual(15);
		});
		it("現在のSurfaceAtlasの保持数より値が小さい場合、maxAtlasNumの値が設定される", () => {
			surfaceAtlasSet.changeMaxAtlasNum(5);
			expect(surfaceAtlasSet.getAtlasNum()).toEqual(5);
		});
	});

	describe("touchGlyph", () => {
		it("touch された glyph のある atlas は「最も利用されていない」ではなくなる", () => {
			const runtime = skeletonRuntime();
			const surfaceAtlasSet = new SurfaceAtlasSet({
				resourceFactory: runtime.game.resourceFactory,
				hint: {
					initialAtlasWidth: 10,
					initialAtlasHeight: 10,
					maxAtlasNum: 5
				}
			});

			// 1 グリフ 1 枚のアトラスを占有する
			// (SurfaceAtlas が内部的に幅・高さを 1px ずつ拡張して管理するので、
			// 10x10 のグリフは入らないことに注意。ここでは 8x8 で一枚ずつ占有させている)
			const glyph0 = createGlyph(300, 0, 0, 8, 8, new Surface(8, 8));
			expect(surfaceAtlasSet.addGlyph(glyph0)).toBe(true);
			const glyph1 = createGlyph(301, 0, 0, 8, 8, new Surface(8, 8));
			expect(surfaceAtlasSet.addGlyph(glyph1)).toBe(true);
			const glyph2 = createGlyph(301, 0, 0, 8, 8, new Surface(8, 8));
			expect(surfaceAtlasSet.addGlyph(glyph2)).toBe(true);

			expect(glyph0._atlas).toBe(surfaceAtlasSet._surfaceAtlases[0]);
			expect(glyph1._atlas).toBe(surfaceAtlasSet._surfaceAtlases[1]);
			expect(glyph2._atlas).toBe(surfaceAtlasSet._surfaceAtlases[2]);

			surfaceAtlasSet.touchGlyph(glyph0);
			surfaceAtlasSet.touchGlyph(glyph2);
			expect(surfaceAtlasSet._findLeastFrequentlyUsedAtlasIndex()).toBe(1);
			surfaceAtlasSet.touchGlyph(glyph1);
			expect(surfaceAtlasSet._findLeastFrequentlyUsedAtlasIndex()).toBe(0);
			surfaceAtlasSet.touchGlyph(glyph0);
			expect(surfaceAtlasSet._findLeastFrequentlyUsedAtlasIndex()).toBe(2);
		});
	});
});

import type { ImageAsset as PdiImageAsset } from "@akashic/pdi-types";
import { SurfaceUtil } from "..";
import { Renderer, customMatchers, Game, skeletonRuntime, Surface } from "./helpers";

expect.extend(customMatchers);

describe("test SurfaceUtil", () => {
	it("asSurface", done => {
		const runtime = skeletonRuntime();
		const scene = runtime.scene;
		const surface = new Surface(1, 1);
		expect(SurfaceUtil.asSurface(surface)).toBe(surface);
		expect(SurfaceUtil.asSurface(undefined)).toBeUndefined();
		expect(() => {
			SurfaceUtil.asSurface(scene as any);
		}).toThrowError("TypeMismatchError");

		const game = new Game({
			width: 320,
			height: 270,
			main: "",
			assets: {
				foo: {
					type: "image",
					path: "/dummypath.png",
					virtualPath: "dummypath.png",
					global: true,
					width: 1,
					height: 1
				}
			}
		});
		game._onLoad.add(() => {
			expect(SurfaceUtil.asSurface(game.assets.foo as PdiImageAsset)).toEqual((game.assets.foo as PdiImageAsset).asSurface());
			done();
		});
		game._startLoadingGlobalAssets();
	});

	it("SurfaceUtil#drawNinePatch()", () => {
		const game = new Game({
			width: 320,
			height: 270,
			main: "",
			assets: {}
		});
		const destSurface = game.resourceFactory.createSurface(100, 100);
		const srcSurface = game.resourceFactory.createSurface(100, 100);
		const borderWidth = {
			top: 1,
			bottom: 2,
			left: 3,
			right: 4
		};
		SurfaceUtil.drawNinePatch(destSurface, srcSurface, borderWidth);
		const drawImage = (destSurface.renderer() as Renderer).methodCallParamsHistory("drawImage");
		expect(drawImage.length).toBe(9);

		// corners
		expect(drawImage[0].width).toBe(3);
		expect(drawImage[0].height).toBe(1);
		expect(drawImage[1].width).toBe(4);
		expect(drawImage[1].height).toBe(1);
		expect(drawImage[2].width).toBe(3);
		expect(drawImage[2].height).toBe(2);
		expect(drawImage[3].width).toBe(4);
		expect(drawImage[3].height).toBe(2);

		// borders
		expect(drawImage[4].width).toBe(93);
		expect(drawImage[4].height).toBe(1);
		expect(drawImage[5].width).toBe(3);
		expect(drawImage[5].height).toBe(97);
		expect(drawImage[6].width).toBe(4);
		expect(drawImage[6].height).toBe(97);
		expect(drawImage[7].width).toBe(93);
		expect(drawImage[7].height).toBe(2);

		// center
		expect(drawImage[8].width).toBe(93);
		expect(drawImage[8].height).toBe(97);
	});

	it("SurfaceUtil#rendererNinePatch()", () => {
		const game = new Game({
			width: 320,
			height: 270,
			main: "",
			assets: {}
		});
		const renderer = new Renderer();
		const srcSurface = game.resourceFactory.createSurface(200, 200);
		const width = 100;
		const height = 100;
		const borderWidth = {
			top: 1,
			bottom: 2,
			left: 3,
			right: 4
		};
		SurfaceUtil.renderNinePatch(renderer, width, height, srcSurface, borderWidth);
		const drawImage = renderer.methodCallParamsHistory("drawImage");
		expect(drawImage.length).toBe(9);

		// corners
		expect(drawImage[0].width).toBe(3);
		expect(drawImage[0].height).toBe(1);
		expect(drawImage[1].width).toBe(4);
		expect(drawImage[1].height).toBe(1);
		expect(drawImage[2].width).toBe(3);
		expect(drawImage[2].height).toBe(2);
		expect(drawImage[3].width).toBe(4);
		expect(drawImage[3].height).toBe(2);

		// borders
		expect(drawImage[4].width).toBe(193);
		expect(drawImage[4].height).toBe(1);
		expect(drawImage[5].width).toBe(3);
		expect(drawImage[5].height).toBe(197);
		expect(drawImage[6].width).toBe(4);
		expect(drawImage[6].height).toBe(197);
		expect(drawImage[7].width).toBe(193);
		expect(drawImage[7].height).toBe(2);

		// center
		expect(drawImage[8].width).toBe(193);
		expect(drawImage[8].height).toBe(197);
	});
});

import { Trigger } from "@akashic/trigger";
import { Timer, TimerManager } from "..";
import { customMatchers } from "./helpers";

expect.extend(customMatchers);

describe("test TimerManager", () => {
	let trigger: Trigger<void>;

	beforeEach(() => {
		trigger = new Trigger();
	});

	function loopFire(count: number): void {
		let i = 0;
		while (i < count) {
			trigger.fire.call(trigger);
			i++;
		}
	}

	it("constructor", () => {
		const m = new TimerManager(trigger, 30);

		expect(m._timers.length).toEqual(0);
		expect(m._trigger).toBe(trigger);
		expect(m._identifiers.length).toEqual(0);
		expect(m._fps).toBe(30);
		expect(m._registered).toBe(false);
		expect(m._trigger.contains(m._tick, m)).toBe(false);
	});

	it("createTimer", () => {
		const m = new TimerManager(trigger, 30);

		const timer = m.createTimer(100);
		expect(m._timers.length).toBe(1);
		expect(m._timers[0]).toBe(timer);
		expect(m._registered).toBe(true);
		expect(m._trigger.contains(m._tick, m)).toBe(true);
		expect(m._identifiers.length).toEqual(0);
	});

	it("createTimer - shared timer(same interval)", () => {
		const m = new TimerManager(trigger, 30);

		const timer1 = m.createTimer(100);
		const timer2 = m.createTimer(100);
		expect(m._timers.length).toBe(1);
		expect(timer1).toBe(timer2);
	});

	it("createTimer - new timer(different interval)", () => {
		const m = new TimerManager(trigger, 30);

		const timer1 = m.createTimer(100);
		const timer2 = m.createTimer(101);
		expect(m._timers.length).toBe(2);
		expect(timer1).not.toBe(timer2);
	});

	it("createTimer - new timer(same interval)", () => {
		const m = new TimerManager(trigger, 30);

		const timer1 = m.createTimer(100);
		trigger.fire();
		const timer2 = m.createTimer(100);
		expect(m._timers.length).toBe(2);
		expect(timer1).not.toBe(timer2);
	});

	it("createTimer - error", () => {
		const m = new TimerManager(trigger, 30);
		expect(() => {
			m.createTimer(-1);
		}).toThrowError("AssertionError");
	});

	it("deleteTimer", () => {
		const m = new TimerManager(trigger, 30);

		const timer = m.createTimer(100);
		expect(m._timers.length).toBe(1);
		expect(m._identifiers.length).toEqual(0);
		expect(m._timers[0]).toBe(timer);
		expect(m._registered).toBe(true);
		m.deleteTimer(timer);
		expect(m._timers.length).toBe(0);
		expect(m._registered).toBe(false);
		expect(timer.destroyed()).toBe(true);
		expect(trigger.contains(m._tick, m)).toBe(false);
	});

	it("deleteTimer - handler remains", () => {
		const m = new TimerManager(trigger, 30);

		const timer1 = m.createTimer(100);
		const timer2 = m.createTimer(101);
		m.deleteTimer(timer1);
		expect(timer1.destroyed()).toBe(true);
		expect(m._registered).toBe(true);
		expect(m._trigger.contains(m._tick, m)).toBe(true);
		m.deleteTimer(timer2);
		expect(timer2.destroyed()).toBe(true);
		expect(m._registered).toBe(false);
		expect(m._trigger.contains(m._tick, m)).toBe(false);
	});

	it("deleteTimer - (invalid context)", () => {
		const m = new TimerManager(trigger, 30);
		const t = new Timer(100, undefined!);
		expect(() => {
			m.deleteTimer(t);
		}).not.toThrow();
	});

	it("deleteTimer - (invalid status)", () => {
		const m = new TimerManager(trigger, 30);

		const t = m.createTimer(100);
		m._registered = false;
		expect(() => {
			m.deleteTimer(t);
		}).not.toThrow();
	});

	it("setTimeout", () => {
		const m = new TimerManager(trigger, 30);

		const parent = new Object();
		let passedOwner = null;
		let count = 0;
		m.setTimeout(
			function (this: any): void {
				count++;
				passedOwner = this;
			},
			1000,
			parent
		);
		expect(m._identifiers.length).toEqual(1);
		loopFire(29); // 966.666ms
		expect(count).toBe(0);
		trigger.fire(); // 1000ms
		expect(count).toBe(1);
		loopFire(30); // 2000ms
		expect(count).toBe(1);
		expect(passedOwner).toBe(parent);
		expect(m._identifiers.length).toEqual(0);
	});

	it("setInterval - check calculation error", () => {
		const m = new TimerManager(trigger, 30);

		const parent = new Object();
		let count = 0;
		m.setInterval(
			() => {
				count++;
			},
			2000,
			parent
		);
		loopFire(60);
		expect(count).toBe(1);
	});

	it("setTimeout - invalid status", () => {
		const m = new TimerManager(trigger, 30);

		const parent = new Object();
		m.setTimeout(
			() => {
				/* do nothing */
			},
			1000,
			parent
		);
		expect(m._identifiers.length).toEqual(1);
		m._identifiers.length = 0;
		expect(() => {
			loopFire(30);
		}).not.toThrow();
	});

	it("setTimeout - serial two timers(same interval)", () => {
		const m = new TimerManager(trigger, 30);

		let count1 = 0;
		let count2 = 0;
		m.setTimeout(() => {
			count1++;
		}, 1000);
		expect(m._identifiers.length).toEqual(1);
		loopFire(30); // 1000ms
		expect(m._identifiers.length).toEqual(0);
		expect(count1).toBe(1);

		m.setTimeout(() => {
			count2++;
		}, 1000);
		expect(m._identifiers.length).toEqual(1);
		loopFire(29); // 1966.666ms
		expect(count2).toBe(0);
		trigger.fire(); // 2000ms
		expect(count2).toBe(1);
		expect(m._identifiers.length).toEqual(0);
		loopFire(30); // 3000ms
		expect(count2).toBe(1);
		expect(count1).toBe(1);
	});

	it("setTimeout - parallel two timers(same interval)", () => {
		const m = new TimerManager(trigger, 30);

		let count1 = 0;
		let count2 = 0;
		m.setTimeout(() => {
			count1++;
		}, 1000);
		m.setTimeout(() => {
			count2++;
		}, 1000);
		expect(m._identifiers.length).toEqual(2);
		loopFire(29); // 966.666ms
		expect(count1).toBe(0);
		expect(count2).toBe(0);
		trigger.fire(); // 1000ms
		expect(count1).toBe(1);
		expect(count2).toBe(1);
		expect(m._identifiers.length).toEqual(0);
		loopFire(30); // 2000ms
		expect(count1).toBe(1);
		expect(count2).toBe(1);
	});

	it("setTimeout - serial two timers(different interval)", () => {
		const m = new TimerManager(trigger, 10);

		let count1 = 0;
		let count2 = 0;
		m.setTimeout(() => {
			count1++;
		}, 500);
		loopFire(5); // 500ms
		expect(count1).toBe(1);

		m.setTimeout(() => {
			count2++;
		}, 1000);
		loopFire(10); // 1500ms
		expect(count2).toBe(1);
		loopFire(15); // 3000ms
		expect(count2).toBe(1);
		expect(count1).toBe(1);
		expect(m._identifiers.length).toEqual(0);
	});

	it("setTimeout - parallel two timers(different interval)", () => {
		const m = new TimerManager(trigger, 10);

		let count1 = 0;
		let count2 = 0;
		m.setTimeout(() => {
			count1++;
		}, 500);
		m.setTimeout(() => {
			count2++;
		}, 1000);
		loopFire(5); // 500ms
		expect(count1).toBe(1);
		expect(count2).toBe(0);
		loopFire(5); // 1000ms
		expect(count1).toBe(1);
		expect(count2).toBe(1);
		expect(m._identifiers.length).toEqual(0);
	});

	it("setTimeout - zero interval", () => {
		const m = new TimerManager(trigger, 10);

		let count = 0;
		m.setTimeout(() => {
			count++;
		}, 0);

		loopFire(1); // 100ms
		expect(count).toBe(1);
		loopFire(10); // 1100ms
		expect(count).toBe(1);
	});

	it("clearTimeout", () => {
		const m = new TimerManager(trigger, 10);

		let count = 0;
		const timeout = m.setTimeout(() => {
			count++;
		}, 500);
		expect(m._identifiers.length).toEqual(1);
		loopFire(3); // 300ms
		m.clearTimeout(timeout);
		expect(m._identifiers.length).toEqual(0);
		loopFire(2); // 500ms
		expect(count).toBe(0);
		loopFire(5); // 1000ms
		expect(count).toBe(0);
	});

	it("clearTimeout - (not found)", () => {
		const m = new TimerManager(trigger, 10);

		const timeout = m.setTimeout(() => {
			/* do nothing */
		}, 500);
		loopFire(3);
		m.clearTimeout(timeout);
		expect(() => {
			m.clearTimeout(timeout);
		}).not.toThrow();
	});

	it("clearTimeout - (invalid identifier)", () => {
		const m = new TimerManager(trigger, 10);

		const timeout = m.setTimeout(() => {
			/* do nothing */
		}, 500);
		loopFire(3);
		timeout.destroy();
		expect(() => {
			m.clearTimeout(timeout);
		}).not.toThrow();
	});

	it("clearTimeout - parallel two timers", () => {
		const m = new TimerManager(trigger, 10);

		let count1 = 0;
		let count2 = 0;
		const timeout1 = m.setTimeout(() => {
			count1++;
		}, 500);
		m.setTimeout(() => {
			count2++;
		}, 500);
		loopFire(3); // 300ms
		m.clearTimeout(timeout1);
		loopFire(2); // 500ms
		expect(count1).toBe(0);
		expect(count2).toBe(1);
	});

	it("clearTimeout - zero interval", () => {
		const m = new TimerManager(trigger, 10);

		let count = 0;
		const timeout = m.setTimeout(() => {
			count++;
		}, 0);
		m.clearTimeout(timeout);
		loopFire(10); // 1000ms
		expect(count).toBe(0);
	});

	it("setInterval", () => {
		const m = new TimerManager(trigger, 10);

		const parent = new Object();
		let passedOwner = null;
		let count = 0;
		m.setInterval(
			function (this: any): void {
				count++;
				passedOwner = this;
			},
			500,
			parent
		);
		loopFire(4); // 400ms
		expect(count).toBe(0);
		trigger.fire(); // 500ms
		expect(count).toBe(1);
		loopFire(5); // 1000ms
		expect(count).toBe(2);
		loopFire(5); // 1500ms
		expect(count).toBe(3);
		loopFire(5); // 2000ms
		expect(count).toBe(4);
		expect(passedOwner).toBe(parent);
		expect(m._identifiers.length).toEqual(1);
	});

	it("setInterval - two timers(same interval)", () => {
		const m = new TimerManager(trigger, 10);

		let count1 = 0;
		let count2 = 0;
		m.setInterval(() => {
			count1++;
		}, 500);
		m.setInterval(() => {
			count2++;
		}, 500);
		loopFire(4); // 400ms
		expect(count1).toBe(0);
		expect(count2).toBe(0);
		trigger.fire(); // 500ms
		expect(count1).toBe(1);
		expect(count2).toBe(1);
		loopFire(5); // 1000ms
		expect(count1).toBe(2);
		expect(count2).toBe(2);
		loopFire(5); // 1500ms
		expect(count1).toBe(3);
		expect(count2).toBe(3);
		loopFire(5); // 2000ms
		expect(count1).toBe(4);
		expect(count2).toBe(4);
		expect(m._identifiers.length).toEqual(2);
	});

	it("setInterval - two timers(different interval)", () => {
		const m = new TimerManager(trigger, 10);

		let count1 = 0;
		let count2 = 0;
		m.setInterval(() => {
			count1++;
		}, 500);
		m.setInterval(() => {
			count2++;
		}, 1000);
		loopFire(5); // 500ms
		expect(count1).toBe(1);
		expect(count2).toBe(0);
		loopFire(5); // 1000ms
		expect(count1).toBe(2);
		expect(count2).toBe(1);
		loopFire(5); // 1500ms
		expect(count1).toBe(3);
		expect(count2).toBe(1);
		loopFire(5); // 2000ms
		expect(count1).toBe(4);
		expect(count2).toBe(2);
		expect(m._identifiers.length).toEqual(2);
	});

	it("setInterval - zero interval", () => {
		const m = new TimerManager(trigger, 10);

		let count = 0;
		m.setInterval(() => {
			count++;
		}, 0);
		loopFire(10); // 1000ms
		expect(count).toBe(1000);
	});

	it("clearInterval", () => {
		const m = new TimerManager(trigger, 10);

		let count = 0;
		const interval = m.setInterval(() => {
			count++;
		}, 500);
		loopFire(20); // 2000ms
		expect(count).toBe(4);
		m.clearInterval(interval);
		expect(m._identifiers.length).toEqual(0);
		loopFire(20); // 4000ms
		expect(count).toBe(4);
	});

	it("clearInterval - (not found)", () => {
